def _external_corpus_manifest_path(config: ProjectConfig) -> Path | None:
    manifest = config.external_corpus_manifest
    if not manifest:
        return None
    return _project_config_path(config.root, manifest).resolve()


def _load_external_corpus_manifest(
    config: ProjectConfig,
) -> tuple[Mapping[str, Any] | None, str | None]:
    manifest_path = _external_corpus_manifest_path(config)
    if manifest_path is None:
        return None, None
    if not _is_relative_to(manifest_path, config.root):
        return None, "outside-project"
    if not manifest_path.exists():
        return None, "missing"
    try:
        manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return None, "invalid"
    if not isinstance(manifest, Mapping):
        return None, "invalid"
    if manifest.get("schemaVersion") != EXTERNAL_CORPUS_SCHEMA_VERSION:
        return None, "invalid"
    if not isinstance(manifest.get("entries"), list):
        return None, "invalid"
    return manifest, None


def _external_corpus_manifest_entry_reasons(entry: Any) -> list[str]:
    if not isinstance(entry, Mapping):
        return ["entry must be an object"]

    reasons = []
    path = entry.get("path")
    if not _is_non_empty_string(path):
        reasons.append("path must be a non-empty repository-relative string")
    else:
        normalized_path = path.replace("\\", "/")
        if not _is_repository_relative_report_path(normalized_path):
            reasons.append("path must be repository-relative")

    if "id" in entry and not _is_non_empty_string(entry.get("id")):
        reasons.append("id must be a non-empty string")

    source_backend = entry.get("sourceBackend")
    if source_backend is not None and not _is_non_empty_string(source_backend):
        reasons.append("sourceBackend must be a non-empty string")

    targets = entry.get("targets")
    if targets is not None:
        valid_targets = _is_non_empty_string(targets) or (
            isinstance(targets, Sequence)
            and not isinstance(targets, (bytes, bytearray))
            and len(targets) > 0
            and all(_is_non_empty_string(target) for target in targets)
        )
        if not valid_targets:
            reasons.append(
                "targets must be a non-empty string or list of non-empty strings"
            )

    for field_name in ("repository", "commit", "sourceUrl"):
        if field_name in entry and not _is_non_empty_string(entry.get(field_name)):
            reasons.append(f"{field_name} must be a string")
    commit = entry.get("commit")
    if _is_non_empty_string(commit) and not _is_lowercase_hex_digest(
        commit,
        GIT_COMMIT_HEX_LENGTH,
    ):
        reasons.append("commit must be a lowercase 40-character hex digest")
    repository = entry.get("repository")
    source_url = entry.get("sourceUrl")
    if (
        _is_non_empty_string(repository)
        and _is_non_empty_string(source_url)
        and not _source_url_matches_repository(source_url, repository)
    ):
        reasons.append("sourceUrl must start with repository")

    return reasons


def _external_corpus_manifest_entry_identity(
    entry: Mapping[str, Any],
) -> tuple[str | None, str | None]:
    entry_id = entry.get("id")
    normalized_id = entry_id if _is_non_empty_string(entry_id) else None
    path = entry.get("path")
    normalized_path = path.replace("\\", "/") if _is_non_empty_string(path) else None
    return normalized_id, normalized_path


def _external_corpus_manifest_entry_duplicate_reasons(
    entry: Mapping[str, Any],
    *,
    seen_ids: Mapping[str, int],
    seen_paths: Mapping[str, int],
) -> list[str]:
    entry_id, path = _external_corpus_manifest_entry_identity(entry)
    reasons = []
    if entry_id is not None and entry_id in seen_ids:
        reasons.append(f"id duplicates entry {seen_ids[entry_id] + 1}")
    if path is not None and path in seen_paths:
        reasons.append(f"path duplicates entry {seen_paths[path] + 1}")
    return reasons


def _valid_external_corpus_manifest_entries(
    manifest: Mapping[str, Any],
) -> list[tuple[int, Mapping[str, Any]]]:
    entries = []
    seen_ids: dict[str, int] = {}
    seen_paths: dict[str, int] = {}
    for index, entry in enumerate(manifest.get("entries", [])):
        if _external_corpus_manifest_entry_reasons(entry):
            continue
        duplicate_reasons = _external_corpus_manifest_entry_duplicate_reasons(
            entry,
            seen_ids=seen_ids,
            seen_paths=seen_paths,
        )
        if duplicate_reasons:
            continue
        entry_id, path = _external_corpus_manifest_entry_identity(entry)
        if entry_id is not None:
            seen_ids[entry_id] = index
        if path is not None:
            seen_paths[path] = index
        entries.append((index, entry))
    return entries


def _external_corpus_manifest_reference(config: ProjectConfig) -> str:
    return str(config.external_corpus_manifest or "")


def _manifest_entry_targets(
    entry: Mapping[str, Any], fallback_targets: Sequence[str]
) -> list[str]:
    targets = entry.get("targets")
    if isinstance(targets, str):
        return _normalized_targets([targets])
    if isinstance(targets, Sequence) and not isinstance(targets, (bytes, bytearray)):
        valid_targets = [target for target in targets if isinstance(target, str)]
        if valid_targets:
            return _normalized_targets(valid_targets)
    return list(fallback_targets)


def _resolve_external_corpus_source_backend(value: str) -> str | None:
    register_default_sources()
    discover_backend_plugins()
    return SOURCE_REGISTRY.resolve_name(value)


def _external_corpus_source_backend(value: Any) -> str:
    if not _is_non_empty_string(value):
        return "unknown"
    canonical_name = _resolve_external_corpus_source_backend(value)
    return canonical_name or value.strip()


def _external_corpus_entries_by_source_backend(
    entries: Sequence[Mapping[str, Any]],
) -> dict[str, int]:
    counts: dict[str, int] = {}
    for entry in entries:
        source_backend = str(entry.get("sourceBackend", "unknown"))
        counts[source_backend] = counts.get(source_backend, 0) + 1
    return dict(sorted(counts.items()))


def _external_corpus_entries_by_target(
    entries: Sequence[Mapping[str, Any]],
) -> dict[str, int]:
    counts: dict[str, int] = {}
    for entry in entries:
        for target in entry.get("targets", []):
            target_name = str(target)
            counts[target_name] = counts.get(target_name, 0) + 1
    return dict(sorted(counts.items()))


def _external_corpus_artifacts(
    entries: Sequence[Mapping[str, Any]], artifacts: Sequence[Mapping[str, Any]]
) -> list[Mapping[str, Any]]:
    entry_targets: dict[str, set[str]] = {}
    for entry in entries:
        path = entry.get("path")
        if not _is_non_empty_string(path):
            continue
        targets = {
            target for target in entry.get("targets", []) if isinstance(target, str)
        }
        entry_targets.setdefault(path, set()).update(targets)

    corpus_artifacts = []
    for artifact in artifacts:
        source = artifact.get("source")
        target = artifact.get("target")
        if not _is_non_empty_string(source) or source not in entry_targets:
            continue
        targets = entry_targets[source]
        if targets and target not in targets:
            continue
        corpus_artifacts.append(artifact)
    return corpus_artifacts


def _external_corpus_entry_artifacts(
    entry: Mapping[str, Any], artifacts: Sequence[Mapping[str, Any]]
) -> list[Mapping[str, Any]]:
    path = entry.get("path")
    if not _is_non_empty_string(path):
        return []
    targets = {target for target in entry.get("targets", []) if isinstance(target, str)}
    return [
        artifact
        for artifact in artifacts
        if artifact.get("source") == path
        and (not targets or artifact.get("target") in targets)
    ]


def _external_corpus_report(
    config: ProjectConfig,
    units: Sequence[ProjectTranslationUnit],
    artifacts: Sequence[Mapping[str, Any]],
    targets: Sequence[str],
) -> dict[str, Any] | None:
    if not config.external_corpus_manifest:
        return None

    manifest, status = _load_external_corpus_manifest(config)
    if manifest is None:
        return {
            "schemaVersion": EXTERNAL_CORPUS_SCHEMA_VERSION,
            "manifest": _external_corpus_manifest_reference(config),
            "status": status or "invalid",
            "entries": [],
            "summary": _external_corpus_empty_summary(),
        }

    units_by_path = {unit.relative_path: unit for unit in units}
    artifacts_by_source: dict[str, list[Mapping[str, Any]]] = {}
    for artifact in artifacts:
        source = str(artifact.get("source", ""))
        if source:
            artifacts_by_source.setdefault(source, []).append(artifact)

    valid_manifest_entries = _valid_external_corpus_manifest_entries(manifest)
    manifest_entry_count = len(manifest.get("entries", []))

    entries = []
    for index, raw_entry in valid_manifest_entries:
        path = str(raw_entry.get("path", "")).replace("\\", "/")
        entry_targets = _manifest_entry_targets(raw_entry, targets)
        unit = units_by_path.get(path)
        manifest_source_backend = raw_entry.get("sourceBackend")
        if unit is not None:
            source_backend = unit.source_backend
        elif _is_non_empty_string(manifest_source_backend):
            source_backend = _external_corpus_source_backend(manifest_source_backend)
        else:
            source_backend = "unknown"
        entry_artifacts = [
            artifact
            for artifact in artifacts_by_source.get(path, [])
            if not entry_targets or artifact.get("target") in entry_targets
        ]
        entry_path = config.root / path
        present = (
            bool(path)
            and _is_repository_relative_report_path(path)
            and entry_path.exists()
        )
        discovered = unit is not None
        entry_payload = {
            "id": str(raw_entry.get("id") or path or f"entry-{index + 1}"),
            "path": path,
            "sourceBackend": source_backend,
            "targets": entry_targets,
            "present": present,
            "discovered": discovered,
            "artifactCount": len(entry_artifacts),
            "translatedCount": sum(
                1
                for artifact in entry_artifacts
                if artifact.get("status") == "translated"
            ),
            "failedCount": sum(
                1 for artifact in entry_artifacts if artifact.get("status") == "failed"
            ),
        }
        for field_name in ("repository", "commit", "sourceUrl"):
            value = raw_entry.get(field_name)
            if isinstance(value, str) and value:
                entry_payload[field_name] = value
        entries.append(entry_payload)

    summary = {
        "manifestEntryCount": manifest_entry_count,
        "validEntryCount": len(entries),
        "invalidEntryCount": manifest_entry_count - len(entries),
        "entryCount": len(entries),
        "presentCount": sum(1 for entry in entries if entry["present"]),
        "missingCount": sum(1 for entry in entries if not entry["present"]),
        "discoveredUnitCount": sum(1 for entry in entries if entry["discovered"]),
        "undiscoveredPresentCount": sum(
            1 for entry in entries if entry["present"] and not entry["discovered"]
        ),
        "entriesBySourceBackend": _external_corpus_entries_by_source_backend(entries),
        "entriesByTarget": _external_corpus_entries_by_target(entries),
        "artifactsByTarget": _artifact_counts_by_target(
            _external_corpus_artifacts(entries, artifacts)
        ),
    }
    payload = {
        "schemaVersion": EXTERNAL_CORPUS_SCHEMA_VERSION,
        "manifest": _external_corpus_manifest_reference(config),
        "status": "ok",
        "entries": entries,
        "summary": summary,
    }
    for field_name in ("name", "description"):
        value = manifest.get(field_name)
        if isinstance(value, str) and value:
            payload[field_name] = value
    return payload


def _resolved_include_dir(config: ProjectConfig, include_dir: str) -> Path:
    return _project_config_path(config.root, include_dir).resolve()


def _resolved_include_dirs(config: ProjectConfig) -> list[str]:
    include_dirs = []
    for include_dir in config.include_dirs:
        include_dirs.append(str(_resolved_include_dir(config, include_dir)))
    return include_dirs


def _include_dir_status_for_path(config: ProjectConfig, path: Path) -> str:
    if not _is_relative_to(path, config.root):
        return "outside-project"
    if not path.exists():
        return "missing"
    if not path.is_dir():
        return "not-directory"
    return "active"


def _include_dir_status_records(config: ProjectConfig) -> list[dict[str, Any]]:
    records = []
    for include_dir in config.include_dirs:
        absolute_dir = _resolved_include_dir(config, include_dir)
        status = _include_dir_status_for_path(config, absolute_dir)
        records.append(
            {
                "path": include_dir,
                "resolvedPath": str(absolute_dir),
                "status": status,
                "frontendVisible": status == "active",
            }
        )
    return records


def _include_dir_status_counts(
    records: Sequence[Mapping[str, Any]],
) -> dict[str, int]:
    counts = {status: 0 for status in sorted(INCLUDE_DIR_STATUSES)}
    for record in records:
        status = record.get("status")
        if isinstance(status, str) and status in counts:
            counts[status] += 1
    return {status: count for status, count in counts.items() if count}


def _frontend_include_dirs(config: ProjectConfig) -> list[str]:
    include_dirs = []
    for include_dir in config.include_dirs:
        absolute_dir = _resolved_include_dir(config, include_dir)
        if _include_dir_status_for_path(config, absolute_dir) == "active":
            include_dirs.append(str(absolute_dir))
    return include_dirs


def _source_options_for_backend(
    config: ProjectConfig, source_backend: str
) -> dict[str, Any]:
    register_default_sources()
    key = SOURCE_REGISTRY.resolve_name(source_backend) or source_backend.strip().lower()
    source_options = config.source_options.get(key, {})
    return {
        name: value
        for name, value in source_options.items()
        if name not in {SOURCE_OPTION_PATTERNS_KEY, TARGET_SOURCE_OPTIONS_KEY}
    }


def _source_options_for_unit(
    config: ProjectConfig,
    source_backend: str,
    relative_path: str,
    target: str | None = None,
) -> dict[str, Any]:
    register_default_sources()
    key = SOURCE_REGISTRY.resolve_name(source_backend) or source_backend.strip().lower()
    configured_options = config.source_options.get(key, {})
    source_options: dict[str, Any] = {}
    template_limit_source = None
    work_limit_source = None

    def apply_options(option_values: Mapping[str, Any], option_path: str) -> None:
        nonlocal template_limit_source, work_limit_source
        for name, value in option_values.items():
            if name in {SOURCE_OPTION_PATTERNS_KEY, TARGET_SOURCE_OPTIONS_KEY}:
                continue
            source_options[name] = value
        if METAL_TEMPLATE_SPECIALIZATION_LIMIT_OPTION in option_values:
            template_limit_source = (
                f"{option_path}.{METAL_TEMPLATE_SPECIALIZATION_LIMIT_OPTION}"
            )
        if METAL_TEMPLATE_MATERIALIZATION_WORK_LIMIT_OPTION in option_values:
            work_limit_source = (
                f"{option_path}.{METAL_TEMPLATE_MATERIALIZATION_WORK_LIMIT_OPTION}"
            )

    def apply_source_patterns(
        option_values: Mapping[str, Any], option_path: str
    ) -> None:
        nonlocal template_limit_source, work_limit_source
        source_patterns = option_values.get(SOURCE_OPTION_PATTERNS_KEY)
        if not isinstance(source_patterns, Mapping):
            return
        normalized_path = _normalize_project_relative_path(relative_path)
        for pattern, pattern_options in source_patterns.items():
            if not isinstance(pattern, str) or not isinstance(pattern_options, Mapping):
                continue
            normalized_pattern = _normalize_project_relative_path(pattern)
            if not fnmatch.fnmatch(normalized_path, normalized_pattern):
                continue
            source_options.update(pattern_options)
            if METAL_TEMPLATE_SPECIALIZATION_LIMIT_OPTION in pattern_options:
                pattern_path = _mapping_key_path(
                    f"{option_path}.{SOURCE_OPTION_PATTERNS_KEY}",
                    normalized_pattern,
                )
                template_limit_source = (
                    f"{pattern_path}." f"{METAL_TEMPLATE_SPECIALIZATION_LIMIT_OPTION}"
                )
            if METAL_TEMPLATE_MATERIALIZATION_WORK_LIMIT_OPTION in pattern_options:
                pattern_path = _mapping_key_path(
                    f"{option_path}.{SOURCE_OPTION_PATTERNS_KEY}",
                    normalized_pattern,
                )
                work_limit_source = (
                    f"{pattern_path}."
                    f"{METAL_TEMPLATE_MATERIALIZATION_WORK_LIMIT_OPTION}"
                )

    backend_option_path = f"project.source_options.{key}"
    apply_options(configured_options, backend_option_path)
    apply_source_patterns(configured_options, backend_option_path)

    target_options = configured_options.get(TARGET_SOURCE_OPTIONS_KEY)
    if target is not None and isinstance(target_options, Mapping):
        target_key = normalize_backend_name(target) or target.strip().lower()
        configured_target_options = target_options.get(target_key)
        if isinstance(configured_target_options, Mapping):
            target_option_path = _mapping_key_path(
                f"{backend_option_path}.{TARGET_SOURCE_OPTIONS_KEY}",
                target_key,
            )
            apply_options(configured_target_options, target_option_path)
            apply_source_patterns(configured_target_options, target_option_path)

    source_options.pop(SOURCE_OPTION_PATTERNS_KEY, None)
    source_options.pop(TARGET_SOURCE_OPTIONS_KEY, None)
    if (
        source_backend == "metal"
        and METAL_TEMPLATE_SPECIALIZATION_LIMIT_OPTION in source_options
        and template_limit_source is not None
    ):
        source_options[METAL_TEMPLATE_SPECIALIZATION_LIMIT_SOURCE_OPTION] = (
            template_limit_source
        )
    if (
        source_backend == "metal"
        and METAL_TEMPLATE_MATERIALIZATION_WORK_LIMIT_OPTION in source_options
        and work_limit_source is not None
    ):
        source_options[METAL_TEMPLATE_MATERIALIZATION_WORK_LIMIT_SOURCE_OPTION] = (
            work_limit_source
        )
    return source_options


def _frontend_source_options(source_options: Mapping[str, Any]) -> dict[str, Any]:
    return {
        name: value
        for name, value in source_options.items()
        if name
        not in {
            TEMPLATE_VARIANTS_SOURCE_OPTION,
            TARGET_SOURCE_OPTIONS_KEY,
            METAL_TEMPLATE_SPECIALIZATION_LIMIT_SOURCE_OPTION,
            METAL_TEMPLATE_MATERIALIZATION_WORK_LIMIT_SOURCE_OPTION,
        }
    }


def _strip_include_line_comment(value: str) -> str:
    return value.split("//", 1)[0].strip()


def _mask_preprocessor_block_comments(lines: Sequence[str]) -> list[str]:
    masked: list[str] = []
    in_block_comment = False
    for line in lines:
        chars = list(line)
        index = 0
        while index < len(chars):
            if in_block_comment:
                end = line.find("*/", index)
                if end == -1:
                    for offset in range(index, len(chars)):
                        chars[offset] = " "
                    index = len(chars)
                    continue
                for offset in range(index, end + 2):
                    chars[offset] = " "
                in_block_comment = False
                index = end + 2
                continue

            start = line.find("/*", index)
            line_comment = line.find("//", index)
            if line_comment != -1 and (start == -1 or line_comment < start):
                break
            if start == -1:
                break
            end = line.find("*/", start + 2)
            if end == -1:
                for offset in range(start, len(chars)):
                    chars[offset] = " "
                in_block_comment = True
                index = len(chars)
                continue
            for offset in range(start, end + 2):
                chars[offset] = " "
            index = end + 2
        masked.append("".join(chars))
    return masked


def _include_literal(value: str) -> tuple[str, str] | None:
    match = INCLUDE_LITERAL_RE.match(value)
    if not match:
        return None
    delimiter = match.group("open")
    close = match.group("close")
    if delimiter == '"' and close != '"':
        return None
    if delimiter == "<" and close != ">":
        return None
    kind = "local" if delimiter == '"' else "system"
    include_path = match.group("path").strip()
    if not include_path:
        return None
    return kind, include_path


def _include_literal_from_define(
    config: ProjectConfig, expression: str
) -> tuple[str, str, str] | None:
    define_name = expression.strip()
    if not define_name or define_name not in config.defines:
        return None

    literal = _include_literal(config.defines[define_name].strip())
    if literal is None:
        return None
    kind, include_path = literal
    return define_name, kind, include_path


@dataclass
class _IncludeConditionalFrame:
    parent_active: bool
    branch_active: bool
    branch_taken: bool


def _strip_preprocessor_line_comment(value: str) -> str:
    return value.split("//", 1)[0].strip()


def _include_condition_tokens(expression: str) -> list[str] | None:
    tokens = INCLUDE_CONDITION_TOKEN_RE.findall(
        _strip_preprocessor_line_comment(expression)
    )
    if not tokens:
        return None
    allowed_operators = {
        "defined",
        "&&",
        "||",
        "!",
        "(",
        ")",
        "==",
        "!=",
        "<",
        "<=",
        ">",
        ">=",
    }
    for token in tokens:
        if token in allowed_operators:
            continue
        if re.match(r"^[+-]?[0-9]+$", token):
            continue
        if re.match(r"^[A-Za-z_][A-Za-z0-9_]*$", token):
            continue
        return None
    return tokens


def _define_condition_scalar(value: str) -> int | bool | None:
    stripped = value.strip()
    if not stripped:
        return False
    if re.match(r"^[+-]?[0-9]+$", stripped):
        return int(stripped, 10)
    if stripped.lower() == "true":
        return True
    if stripped.lower() == "false":
        return False
    return None


def _define_condition_value(value: str) -> bool | None:
    scalar = _define_condition_scalar(value)
    return None if scalar is None else bool(scalar)


def _include_if_expression_value(config: ProjectConfig, expression: str) -> bool | None:
    tokens = _include_condition_tokens(expression)
    if tokens is None:
        return None
    index = 0
    comparison_operators = {"==", "!=", "<", "<=", ">", ">="}

    def condition_bool(value: int | bool | None) -> bool | None:
        return None if value is None else bool(value)

    def condition_int(value: int | bool | None) -> int | None:
        if value is None:
            return None
        return int(value)

    def parse_or() -> bool | None:
        nonlocal index
        value = parse_and()
        while index < len(tokens) and tokens[index] == "||":
            index += 1
            right = parse_and()
            if value is None or right is None:
                value = None
            else:
                value = value or right
        return value

    def parse_and() -> bool | None:
        nonlocal index
        value = parse_comparison()
        while index < len(tokens) and tokens[index] == "&&":
            index += 1
            right = parse_comparison()
            if value is None or right is None:
                value = None
            else:
                value = value and right
        return value

    def parse_comparison() -> bool | None:
        nonlocal index
        left = parse_not()
        if index >= len(tokens) or tokens[index] not in comparison_operators:
            return condition_bool(left)
        operator = tokens[index]
        index += 1
        right = parse_not()
        left_value = condition_int(left)
        right_value = condition_int(right)
        if left_value is None or right_value is None:
            return None
        if operator == "==":
            return left_value == right_value
        if operator == "!=":
            return left_value != right_value
        if operator == "<":
            return left_value < right_value
        if operator == "<=":
            return left_value <= right_value
        if operator == ">":
            return left_value > right_value
        if operator == ">=":
            return left_value >= right_value
        return None

    def parse_not() -> int | bool | None:
        nonlocal index
        if index < len(tokens) and tokens[index] == "!":
            index += 1
            value = parse_not()
            truth_value = condition_bool(value)
            return None if truth_value is None else not truth_value
        return parse_atom()

    def parse_atom() -> int | bool | None:
        nonlocal index
        if index >= len(tokens):
            return None
        token = tokens[index]
        if token == "(":
            index += 1
            value = parse_or()
            if index >= len(tokens) or tokens[index] != ")":
                return None
            index += 1
            return value
        if token == "defined":
            index += 1
            if index < len(tokens) and tokens[index] == "(":
                index += 1
                if index >= len(tokens):
                    return None
                name = tokens[index]
                index += 1
                if index >= len(tokens) or tokens[index] != ")":
                    return None
                index += 1
            elif index < len(tokens):
                name = tokens[index]
                index += 1
            else:
                return None
            if not re.match(r"^[A-Za-z_][A-Za-z0-9_]*$", name):
                return None
            return name in config.defines
        index += 1
        if re.match(r"^[+-]?[0-9]+$", token):
            return int(token, 10)
        if re.match(r"^[A-Za-z_][A-Za-z0-9_]*$", token):
            if token not in config.defines:
                return False
            return _define_condition_scalar(config.defines[token])
        return None

    value = parse_or()
    if index != len(tokens):
        return None
    return value


def _include_condition_value(
    config: ProjectConfig, directive: str, expression: str
) -> bool | None:
    expression = _strip_preprocessor_line_comment(expression)
    if directive == "ifdef":
        if not re.match(r"^[A-Za-z_][A-Za-z0-9_]*$", expression):
            return None
        return expression in config.defines
    if directive == "ifndef":
        if not re.match(r"^[A-Za-z_][A-Za-z0-9_]*$", expression):
            return None
        return expression not in config.defines
    return _include_if_expression_value(config, expression)


def _configured_define_origin_label(config: ProjectConfig, name: str) -> str:
    origins = []
    if name in config.defines:
        origins.append("project define")
    variants = sorted(
        variant for variant, defines in config.variants.items() if name in defines
    )
    if variants:
        label = "variant define" if len(variants) == 1 else "variant defines"
        origins.append(f"{label}: {', '.join(variants)}")
    return "; ".join(origins) or "configured define"


def _define_shadowing_diagnostic(
    *,
    config: ProjectConfig,
    relative_path: str,
    line_number: int,
    column: int,
    directive: str,
    name: str,
) -> ProjectDiagnostic:
    verb = "redefines" if directive == "define" else "undefines"
    origin = _configured_define_origin_label(config, name)
    return ProjectDiagnostic(
        severity="warning",
        code="project.scan.define-shadowed",
        message=(
            f"Preprocessor directive in {relative_path}:{line_number} {verb} "
            f"configured define '{name}' ({origin}); project define "
            "preprocessing may not match source-local macro state."
        ),
        location=SourceLocation(
            file=relative_path,
            line=line_number,
            column=column,
            end_line=line_number,
            end_column=column,
        ),
        missing_capabilities=["macro.defines"],
    )


def _scan_define_shadowing_lines(
    config: ProjectConfig,
    lines: Sequence[str],
    relative_path: str,
    *,
    seen: set[tuple[str, int, str, str]],
    diagnostic_config: ProjectConfig | None = None,
) -> list[ProjectDiagnostic]:
    if not config.defines:
        return []

    diagnostic_config = diagnostic_config or config
    diagnostics: list[ProjectDiagnostic] = []
    conditional_stack: list[_IncludeConditionalFrame] = []
    for line_number, line in enumerate(lines, start=1):
        conditional = INCLUDE_CONDITIONAL_DIRECTIVE_RE.match(line)
        if conditional:
            _apply_include_conditional_directive(
                config,
                conditional_stack,
                conditional.group("directive"),
                conditional.group("body"),
            )
            continue
        if not _include_conditionals_active(conditional_stack):
            continue
        define_directive = DEFINE_DIRECTIVE_RE.match(line)
        if not define_directive:
            continue
        directive = define_directive.group("directive")
        name = define_directive.group("name")
        if name not in config.defines:
            continue
        key = (relative_path, line_number, directive, name)
        if key in seen:
            continue
        seen.add(key)
        diagnostics.append(
            _define_shadowing_diagnostic(
                config=diagnostic_config,
                relative_path=relative_path,
                line_number=line_number,
                column=max(1, line.find("#") + 1),
                directive=directive,
                name=name,
            )
        )
    return diagnostics


def _preprocessor_diagnostic(
    *,
    relative_path: str,
    line_number: int,
    column: int,
    directive: str,
    message: str,
    variant: str | None = None,
) -> ProjectDiagnostic:
    severity = "error" if directive == "error" else "warning"
    code = f"project.scan.preprocessor-{directive}"
    rendered_message = message or "(no message)"
    return ProjectDiagnostic(
        severity=severity,
        code=code,
        message=(
            f"Active preprocessor #{directive} directive in "
            f"{relative_path}:{line_number}: {rendered_message}"
        ),
        location=SourceLocation(
            file=relative_path,
            line=line_number,
            column=column,
            end_line=line_number,
            end_column=column,
        ),
        variant=variant,
    )


def _scan_preprocessor_diagnostic_lines(
    config: ProjectConfig,
    lines: Sequence[str],
    relative_path: str,
    *,
    seen: set[tuple[str, int, str, str]],
    variant: str | None = None,
) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    conditional_stack: list[_IncludeConditionalFrame] = []
    for line_number, line in enumerate(lines, start=1):
        conditional = INCLUDE_CONDITIONAL_DIRECTIVE_RE.match(line)
        if conditional:
            _apply_include_conditional_directive(
                config,
                conditional_stack,
                conditional.group("directive"),
                conditional.group("body"),
            )
            continue
        if not _include_conditionals_active(conditional_stack):
            continue
        directive_match = PREPROCESSOR_DIAGNOSTIC_DIRECTIVE_RE.match(line)
        if not directive_match:
            continue
        directive = directive_match.group("directive")
        message = _strip_preprocessor_line_comment(directive_match.group("body"))
        key = (relative_path, line_number, directive, message)
        if key in seen:
            continue
        seen.add(key)
        diagnostics.append(
            _preprocessor_diagnostic(
                relative_path=relative_path,
                line_number=line_number,
                column=max(1, line.find("#") + 1),
                directive=directive,
                message=message,
                variant=variant,
            )
        )
    return diagnostics


def _unsupported_macro_form_diagnostic(
    *,
    relative_path: str,
    line_number: int,
    column: int,
    source_backend: str,
    reason: str,
    form: str,
    variant: str | None = None,
) -> ProjectDiagnostic:
    context = f" for variant {variant}" if variant else ""
    return ProjectDiagnostic(
        severity="warning",
        code="project.scan.unsupported-macro-form",
        message=(
            f"Native macro form in {relative_path}:{line_number}{context} "
            f"is not covered by project macro semantic planning for the "
            f"{source_backend} frontend: {reason} ({form})."
        ),
        location=SourceLocation(
            file=relative_path,
            line=line_number,
            column=column,
            end_line=line_number,
            end_column=column,
        ),
        source_backend=source_backend,
        variant=variant,
        missing_capabilities=["macro.native"],
    )


def _unsupported_native_directive_diagnostic(
    *,
    relative_path: str,
    line_number: int,
    column: int,
    source_backend: str,
    kind: str,
    payload: str,
    variant: str | None = None,
) -> ProjectDiagnostic:
    context = f" for variant {variant}" if variant else ""
    rendered_payload = payload or "(empty payload)"
    return ProjectDiagnostic(
        severity="warning",
        code="project.scan.unsupported-native-directive",
        message=(
            f"Native directive {kind} in {relative_path}:{line_number}{context} "
            f"is recognized by the {source_backend} frontend but configured as "
            f"unsupported: {rendered_payload}."
        ),
        location=SourceLocation(
            file=relative_path,
            line=line_number,
            column=column,
            end_line=line_number,
            end_column=column,
        ),
        source_backend=source_backend,
        variant=variant,
        missing_capabilities=[f"native.directive.{kind}"],
    )


def _macro_form_label(directive: str, body: str) -> str:
    if directive == "define":
        body = _strip_preprocessor_line_comment(body)
        function_like = FUNCTION_LIKE_DEFINE_RE.match(body)
        if function_like:
            return f"function-like define {function_like.group('name')}"
        parts = body.strip().split(maxsplit=1)
        if parts:
            return f"object-like define {parts[0]}"
        return "malformed define"
    if directive == "undef":
        parts = body.strip().split(maxsplit=1)
        return f"undef {parts[0]}" if parts else "malformed undef"
    return f"#{directive}"


def _metal_mode_directive_policy(config: ProjectConfig) -> str:
    options = config.source_options.get("metal", {})
    value = options.get(METAL_MODE_DIRECTIVE_SOURCE_OPTION, "preserve")
    if isinstance(value, str):
        policy = METAL_MODE_DIRECTIVE_POLICY_ALIASES.get(
            value.strip().lower().replace("-", "_")
        )
        if policy is not None:
            return policy
    return "preserve"


def _native_directive_handling_status(
    config: ProjectConfig,
    *,
    source_backend: str,
    kind: str,
    default_status: str,
) -> str:
    if source_backend == "metal" and kind == "mode":
        policy = _metal_mode_directive_policy(config)
        if policy == "preserve":
            return "preserved"
        if policy == "expand":
            return "expanded"
        return "unsupported"
    return default_status


def _metal_mode_variant_name(payload: str) -> str:
    normalized = " ".join(payload.split())
    slug = re.sub(r"[^A-Za-z0-9]+", "-", normalized.lower()).strip("-")
    if not slug:
        slug = "empty"
    digest = hashlib.sha256(normalized.encode("utf-8")).hexdigest()[:8]
    return f"metal-mode-{slug[:40]}-{digest}"


def _native_directive_variant(
    *,
    source_backend: str,
    plan: Mapping[str, str],
    variant: str | None,
) -> str | None:
    if (
        source_backend == "metal"
        and plan.get("kind") == "mode"
        and plan.get("handlingStatus") == "expanded"
    ):
        return _metal_mode_variant_name(plan.get("payload", ""))
    return variant


def _source_frontend_native_directive_plan(
    *,
    config: ProjectConfig,
    source_backend: str,
    directive: str,
    body: str,
) -> dict[str, str] | None:
    source_spec = SOURCE_REGISTRY.get(source_backend)
    if source_spec is None:
        return None
    payload = _strip_preprocessor_line_comment(body).strip()
    raw_plan = source_spec.classify_native_directive(directive, payload)
    if raw_plan is None:
        return None
    kind = str(raw_plan.get("kind", "")).strip().lower()
    handling_status = str(raw_plan.get("handlingStatus", "")).strip().lower()
    handling_status = _native_directive_handling_status(
        config,
        source_backend=source_backend,
        kind=kind,
        default_status=handling_status,
    )
    if not kind or handling_status not in NATIVE_DIRECTIVE_HANDLING_STATUSES:
        return None
    return {
        "kind": kind,
        "payload": str(raw_plan.get("payload", payload)).strip(),
        "handlingStatus": handling_status,
    }


def _unsupported_macro_form_reason(
    *,
    directive: str,
    body: str,
    source_backend: str,
) -> str | None:
    if directive not in PROJECT_KNOWN_PREPROCESSOR_DIRECTIVES:
        return "unknown preprocessor directive is preserved for backend-native handling"

    supports_defines = _source_frontend_supports_lexer_keyword(
        source_backend, "defines"
    )
    if directive in {"define", "undef"} and not supports_defines:
        return "source frontend does not accept project define forwarding"

    if directive != "define":
        return None

    stripped = _strip_preprocessor_line_comment(body)
    if not DEFINE_DIRECTIVE_RE.match(f"#define {stripped}"):
        return "malformed define directive"

    function_like = FUNCTION_LIKE_DEFINE_RE.match(stripped)
    if function_like:
        replacement = function_like.group("replacement")
    else:
        define_parts = stripped.split(None, 1)
        replacement = define_parts[1] if len(define_parts) > 1 else ""
    if "__VA_OPT__" in replacement:
        return "__VA_OPT__ variadic expansion is not modeled by project macro planning"
    if "#@" in replacement:
        return "charizing macro operator is not modeled by project macro planning"
    if source_backend in SOURCE_FRONTENDS_WITH_NATIVE_MACRO_EXPANSION:
        return None
    if function_like:
        return (
            "function-like define requires native macro expansion not provided "
            "by the source frontend"
        )
    if "##" in replacement:
        return (
            "token-pasting define requires native macro expansion not provided "
            "by the source frontend"
        )
    return None


def _scan_native_macro_semantic_lines(
    config: ProjectConfig,
    lines: Sequence[str],
    relative_path: str,
    *,
    source_backend: str,
    seen: set[tuple[str, int, str, str, str | None]],
    variant: str | None = None,
) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    conditional_stack: list[_IncludeConditionalFrame] = []
    for line_number, line in enumerate(lines, start=1):
        directive_match = PREPROCESSOR_DIRECTIVE_RE.match(line)
        if not directive_match:
            continue

        directive = directive_match.group("directive")
        body = directive_match.group("body")
        if directive in {"if", "ifdef", "ifndef", "elif", "else", "endif"}:
            _apply_include_conditional_directive(
                config,
                conditional_stack,
                directive,
                body,
            )
            continue

        if not _include_conditionals_active(conditional_stack):
            continue

        if (
            _source_frontend_native_directive_plan(
                config=config,
                source_backend=source_backend,
                directive=directive,
                body=body,
            )
            is not None
        ):
            continue

        reason = _unsupported_macro_form_reason(
            directive=directive,
            body=body,
            source_backend=source_backend,
        )
        if reason is None:
            continue
        form = _macro_form_label(directive, body)
        key = (relative_path, line_number, directive, form, variant)
        if key in seen:
            continue
        seen.add(key)
        diagnostics.append(
            _unsupported_macro_form_diagnostic(
                relative_path=relative_path,
                line_number=line_number,
                column=max(1, line.find("#") + 1),
                source_backend=source_backend,
                reason=reason,
                form=form,
                variant=variant,
            )
        )
    return diagnostics


def _scan_native_directive_lines(
    config: ProjectConfig,
    lines: Sequence[str],
    relative_path: str,
    *,
    source_backend: str,
    seen: set[tuple[str, int, str, str, str, str | None]],
    variant: str | None = None,
) -> tuple[list[ProjectNativeDirective], list[ProjectDiagnostic]]:
    native_directives: list[ProjectNativeDirective] = []
    diagnostics: list[ProjectDiagnostic] = []
    conditional_stack: list[_IncludeConditionalFrame] = []
    for line_number, line in enumerate(lines, start=1):
        directive_match = PREPROCESSOR_DIRECTIVE_RE.match(line)
        if not directive_match:
            continue

        directive = directive_match.group("directive")
        body = directive_match.group("body")
        if directive in {"if", "ifdef", "ifndef", "elif", "else", "endif"}:
            _apply_include_conditional_directive(
                config,
                conditional_stack,
                directive,
                body,
            )
            continue

        if not _include_conditionals_active(conditional_stack):
            continue

        plan = _source_frontend_native_directive_plan(
            config=config,
            source_backend=source_backend,
            directive=directive,
            body=body,
        )
        if plan is None:
            continue
        directive_variant = _native_directive_variant(
            source_backend=source_backend,
            plan=plan,
            variant=variant,
        )
        key = (
            relative_path,
            line_number,
            plan["kind"],
            plan["payload"],
            plan["handlingStatus"],
            directive_variant,
        )
        if key in seen:
            continue
        seen.add(key)
        column = max(1, line.find("#") + 1)
        native_directives.append(
            ProjectNativeDirective(
                source=relative_path,
                source_backend=source_backend,
                line=line_number,
                column=column,
                kind=plan["kind"],
                payload=plan["payload"],
                handling_status=plan["handlingStatus"],
                variant=directive_variant,
            )
        )
        if plan["handlingStatus"] == "unsupported":
            diagnostics.append(
                _unsupported_native_directive_diagnostic(
                    relative_path=relative_path,
                    line_number=line_number,
                    column=column,
                    source_backend=source_backend,
                    kind=plan["kind"],
                    payload=plan["payload"],
                    variant=directive_variant,
                )
            )
    return native_directives, diagnostics


def _scan_native_directive_planning(
    config: ProjectConfig,
    source_path: Path,
    relative_path: str,
    *,
    source_backend: str,
) -> tuple[list[ProjectNativeDirective], list[ProjectDiagnostic]]:
    source_spec = SOURCE_REGISTRY.get(source_backend)
    if source_spec is None or source_spec.native_directive_classifier is None:
        return [], []
    try:
        lines = source_path.read_text(encoding="utf-8", errors="replace").splitlines()
    except OSError:
        return [], []

    native_directives: list[ProjectNativeDirective] = []
    diagnostics: list[ProjectDiagnostic] = []
    seen: set[tuple[str, int, str, str, str, str | None]] = set()
    scan_lines = _mask_preprocessor_block_comments(lines)
    for variant, defines in _variant_jobs(config):
        scan_config = (
            replace(config, defines=defines) if variant is not None else config
        )
        scanned_directives, scanned_diagnostics = _scan_native_directive_lines(
            scan_config,
            scan_lines,
            relative_path,
            source_backend=source_backend,
            seen=seen,
            variant=variant,
        )
        native_directives.extend(scanned_directives)
        diagnostics.extend(scanned_diagnostics)
    return native_directives, diagnostics


def _scan_unsupported_wgsl_macro_semantics(
    config: ProjectConfig,
    source_path: Path,
    relative_path: str,
) -> list[ProjectDiagnostic]:
    if (
        _skipped_source_extension(relative_path)
        not in WGSL_UNSUPPORTED_SOURCE_EXTENSIONS
    ):
        return []

    try:
        lines = source_path.read_text(encoding="utf-8", errors="replace").splitlines()
    except OSError as exc:
        return [
            ProjectDiagnostic(
                severity="warning",
                code="project.scan.include-read-failed",
                message=(
                    f"Could not scan preprocessor directives in {relative_path}: "
                    f"{exc}"
                ),
                location=SourceLocation(file=relative_path),
                missing_capabilities=["macro.native"],
            )
        ]

    diagnostics: list[ProjectDiagnostic] = []
    seen: set[tuple[str, int, str, str, str | None]] = set()
    scan_lines = _mask_preprocessor_block_comments(lines)
    for variant, defines in _variant_jobs(config):
        scan_config = (
            replace(config, defines=defines) if variant is not None else config
        )
        diagnostics.extend(
            _scan_native_macro_semantic_lines(
                scan_config,
                scan_lines,
                relative_path,
                source_backend="wgsl",
                seen=seen,
                variant=variant,
            )
        )
    return diagnostics


def _include_conditionals_active(stack: Sequence[_IncludeConditionalFrame]) -> bool:
    return all(frame.branch_active for frame in stack)


def _apply_include_conditional_directive(
    config: ProjectConfig,
    stack: list[_IncludeConditionalFrame],
    directive: str,
    expression: str,
) -> None:
    if directive in {"if", "ifdef", "ifndef"}:
        parent_active = _include_conditionals_active(stack)
        condition = _include_condition_value(config, directive, expression)
        branch_active = (
            parent_active if condition is None else parent_active and condition
        )
        stack.append(
            _IncludeConditionalFrame(
                parent_active=parent_active,
                branch_active=branch_active,
                branch_taken=parent_active and condition is True,
            )
        )
        return

    if directive == "elif":
        if not stack:
            return
        frame = stack[-1]
        if frame.branch_taken:
            frame.branch_active = False
            return
        condition = _include_condition_value(config, "if", expression)
        frame.branch_active = (
            frame.parent_active
            if condition is None
            else frame.parent_active and condition
        )
        frame.branch_taken = frame.parent_active and condition is True
        return

    if directive == "else":
        if not stack:
            return
        frame = stack[-1]
        frame.branch_active = frame.parent_active and not frame.branch_taken
        frame.branch_taken = frame.branch_taken or frame.branch_active
        return

    if directive == "endif" and stack:
        stack.pop()


def _include_search_roots(
    config: ProjectConfig, source_path: Path, kind: str
) -> list[tuple[str, Path]]:
    roots: list[tuple[str, Path]] = []
    if kind == "local":
        roots.append(("source", source_path.parent.resolve()))
    roots.extend(
        ("include-dir", Path(include_dir).resolve())
        for include_dir in _frontend_include_dirs(config)
    )
    return roots


def _include_target_is_absolute(include_path: str) -> bool:
    return (
        Path(include_path).is_absolute()
        or PureWindowsPath(include_path).is_absolute()
        or bool(PureWindowsPath(include_path).drive)
    )


def _resolve_include_dependency(
    config: ProjectConfig,
    source_path: Path,
    kind: str,
    include_path: str,
) -> tuple[str, str | None, str | None]:
    if _include_target_is_absolute(include_path):
        return "outside-project", None, None

    outside_project = False
    for source, root in _include_search_roots(config, source_path, kind):
        candidate = (root / include_path).resolve()
        if not _is_relative_to(candidate, config.root):
            outside_project = True
            continue
        if candidate.is_file():
            return "resolved", _relpath(candidate, config.root), source

    if outside_project:
        return "outside-project", None, None
    if kind == "system":
        return "system", None, None
    return "missing", None, None


def _include_resolution_diagnostic(
    *,
    relative_path: str,
    line_number: int,
    status: str,
    include_path: str,
    location: SourceLocation,
    define_name: str | None = None,
    variant: str | None = None,
) -> ProjectDiagnostic | None:
    context_suffix = _include_resolution_context_suffix(
        define_name=define_name,
        variant=variant,
    )
    if status == "missing":
        return ProjectDiagnostic(
            severity="warning",
            code="project.scan.missing-include",
            message=(
                f"Include directive in {relative_path}:{line_number} "
                f"could not be resolved{context_suffix}: {include_path}"
            ),
            location=location,
            variant=variant,
            missing_capabilities=["include.resolution"],
        )
    if status == "outside-project":
        return ProjectDiagnostic(
            severity="warning",
            code="project.scan.include-outside-project",
            message=(
                f"Include directive in {relative_path}:{line_number} "
                "resolves outside the repository or uses an absolute "
                f"path{context_suffix}: {include_path}"
            ),
            location=location,
            variant=variant,
            missing_capabilities=["include.resolution"],
        )
    return None


def _include_resolution_context_suffix(
    *, define_name: str | None = None, variant: str | None = None
) -> str:
    if _is_non_empty_string(define_name):
        define_source = (
            f"variant {variant} define"
            if _is_non_empty_string(variant)
            else "project define"
        )
        return f" (from {define_source} {define_name})"
    if _is_non_empty_string(variant):
        return f" (for variant {variant})"
    return ""


def _include_cycle_diagnostic(
    *,
    relative_path: str,
    line_number: int,
    include_path: str,
    location: SourceLocation,
    variant: str | None = None,
) -> ProjectDiagnostic:
    context_suffix = _include_resolution_context_suffix(variant=variant)
    return ProjectDiagnostic(
        severity="warning",
        code="project.scan.include-cycle",
        message=(
            f"Include directive in {relative_path}:{line_number} creates a "
            f"cycle and was not scanned recursively{context_suffix}: {include_path}"
        ),
        location=location,
        variant=variant,
        missing_capabilities=["include.resolution"],
    )


def _scan_resolved_include_dependencies(
    config: ProjectConfig,
    unit_relative_path: str,
    resolved_path: str,
    *,
    line_number: int,
    include_path: str,
    location: SourceLocation,
    include_stack: tuple[str, ...],
    scanned_sources: set[str],
    define_shadowing_seen: set[tuple[str, int, str, str]],
    preprocessor_seen: set[tuple[str, int, str, str]],
    macro_semantics_seen: set[tuple[str, int, str, str, str | None]],
    diagnostic_config: ProjectConfig,
    source_backend: str,
    variant: str | None = None,
) -> tuple[list[dict[str, Any]], list[ProjectDiagnostic]]:
    if resolved_path in include_stack:
        return [], [
            _include_cycle_diagnostic(
                relative_path=location.file,
                line_number=line_number,
                include_path=include_path,
                location=location,
                variant=variant,
            )
        ]
    if resolved_path in scanned_sources:
        return [], []
    return _scan_include_dependencies_for_source(
        config,
        unit_relative_path,
        (config.root / resolved_path).resolve(),
        resolved_path,
        include_stack=(*include_stack, resolved_path),
        scanned_sources=scanned_sources,
        define_shadowing_seen=define_shadowing_seen,
        preprocessor_seen=preprocessor_seen,
        macro_semantics_seen=macro_semantics_seen,
        diagnostic_config=diagnostic_config,
        source_backend=source_backend,
        variant=variant,
    )


def _scan_include_dependencies_for_source(
    config: ProjectConfig,
    unit_relative_path: str,
    source_path: Path,
    source_relative_path: str,
    *,
    include_stack: tuple[str, ...],
    scanned_sources: set[str],
    define_shadowing_seen: set[tuple[str, int, str, str]],
    preprocessor_seen: set[tuple[str, int, str, str]],
    macro_semantics_seen: set[tuple[str, int, str, str, str | None]],
    diagnostic_config: ProjectConfig,
    source_backend: str,
    variant: str | None = None,
) -> tuple[list[dict[str, Any]], list[ProjectDiagnostic]]:
    dependencies: list[dict[str, Any]] = []
    diagnostics: list[ProjectDiagnostic] = []
    scanned_sources.add(source_relative_path)

    try:
        lines = source_path.read_text(encoding="utf-8", errors="replace").splitlines()
    except OSError as exc:
        diagnostics.append(
            ProjectDiagnostic(
                severity="warning",
                code="project.scan.include-read-failed",
                message=(
                    f"Could not scan include directives in {source_relative_path}: "
                    f"{exc}"
                ),
                location=SourceLocation(file=source_relative_path),
                missing_capabilities=["include.resolution"],
            )
        )
        return dependencies, diagnostics

    scan_lines = _mask_preprocessor_block_comments(lines)
    diagnostics.extend(
        _scan_define_shadowing_lines(
            config,
            scan_lines,
            source_relative_path,
            seen=define_shadowing_seen,
            diagnostic_config=diagnostic_config,
        )
    )
    diagnostics.extend(
        _scan_preprocessor_diagnostic_lines(
            config,
            scan_lines,
            source_relative_path,
            seen=preprocessor_seen,
            variant=variant,
        )
    )
    diagnostics.extend(
        _scan_native_macro_semantic_lines(
            config,
            scan_lines,
            source_relative_path,
            source_backend=source_backend,
            seen=macro_semantics_seen,
            variant=variant,
        )
    )

    conditional_stack: list[_IncludeConditionalFrame] = []
    for line_number, line in enumerate(scan_lines, start=1):
        conditional = INCLUDE_CONDITIONAL_DIRECTIVE_RE.match(line)
        if conditional:
            _apply_include_conditional_directive(
                config,
                conditional_stack,
                conditional.group("directive"),
                conditional.group("body"),
            )
            continue
        if not _include_conditionals_active(conditional_stack):
            continue
        directive = INCLUDE_DIRECTIVE_RE.match(line)
        if not directive:
            continue
        raw_body = directive.group("body").strip()
        column = max(1, line.find("#") + 1)
        location = SourceLocation(
            file=source_relative_path,
            line=line_number,
            column=column,
            end_line=line_number,
            end_column=column,
        )
        literal = _include_literal(raw_body)
        if literal is None:
            body = _strip_include_line_comment(raw_body) or raw_body
            define_literal = _include_literal_from_define(config, body)
            if define_literal is not None:
                define_name, kind, include_path = define_literal
                status, resolved_path, resolved_from = _resolve_include_dependency(
                    config, source_path, kind, include_path
                )
                dependency = {
                    "include": include_path,
                    "kind": kind,
                    "status": status,
                    "line": line_number,
                    "column": column,
                    "resolvedFromDefine": define_name,
                }
                if variant is not None:
                    dependency["variant"] = variant
                if source_relative_path != unit_relative_path:
                    dependency["source"] = source_relative_path
                if resolved_path:
                    resolved_file = config.root / resolved_path
                    dependency["resolvedPath"] = resolved_path
                    dependency["resolvedHash"] = _source_hash(resolved_file)
                    dependency["resolvedSizeBytes"] = resolved_file.stat().st_size
                if resolved_from:
                    dependency["resolvedFrom"] = resolved_from
                dependencies.append(dependency)
                diagnostic = _include_resolution_diagnostic(
                    relative_path=source_relative_path,
                    line_number=line_number,
                    status=status,
                    include_path=include_path,
                    location=location,
                    define_name=define_name,
                    variant=variant,
                )
                if diagnostic is not None:
                    diagnostics.append(diagnostic)
                if resolved_path:
                    nested_dependencies, nested_diagnostics = (
                        _scan_resolved_include_dependencies(
                            config,
                            unit_relative_path,
                            resolved_path,
                            line_number=line_number,
                            include_path=include_path,
                            location=location,
                            include_stack=include_stack,
                            scanned_sources=scanned_sources,
                            define_shadowing_seen=define_shadowing_seen,
                            preprocessor_seen=preprocessor_seen,
                            macro_semantics_seen=macro_semantics_seen,
                            diagnostic_config=diagnostic_config,
                            source_backend=source_backend,
                            variant=variant,
                        )
                    )
                    dependencies.extend(nested_dependencies)
                    diagnostics.extend(nested_diagnostics)
                continue

            dependency = {
                "include": body,
                "kind": "dynamic",
                "status": "dynamic",
                "line": line_number,
                "column": column,
            }
            if variant is not None:
                dependency["variant"] = variant
            if source_relative_path != unit_relative_path:
                dependency["source"] = source_relative_path
            dependencies.append(dependency)
            diagnostics.append(
                ProjectDiagnostic(
                    severity="warning",
                    code="project.scan.dynamic-include",
                    message=(
                        "Include directive uses a dynamic target that cannot be "
                        "resolved during project scan"
                        f"{_include_resolution_context_suffix(variant=variant)}: "
                        f"{body}"
                    ),
                    location=location,
                    variant=variant,
                    missing_capabilities=["include.resolution"],
                )
            )
            continue

        kind, include_path = literal
        status, resolved_path, resolved_from = _resolve_include_dependency(
            config, source_path, kind, include_path
        )
        dependency = {
            "include": include_path,
            "kind": kind,
            "status": status,
            "line": line_number,
            "column": column,
        }
        if variant is not None:
            dependency["variant"] = variant
        if source_relative_path != unit_relative_path:
            dependency["source"] = source_relative_path
        if resolved_path:
            resolved_file = config.root / resolved_path
            dependency["resolvedPath"] = resolved_path
            dependency["resolvedHash"] = _source_hash(resolved_file)
            dependency["resolvedSizeBytes"] = resolved_file.stat().st_size
        if resolved_from:
            dependency["resolvedFrom"] = resolved_from
        dependencies.append(dependency)
        diagnostic = _include_resolution_diagnostic(
            relative_path=source_relative_path,
            line_number=line_number,
            status=status,
            include_path=include_path,
            location=location,
            variant=variant,
        )
        if diagnostic is not None:
            diagnostics.append(diagnostic)
        if resolved_path:
            nested_dependencies, nested_diagnostics = (
                _scan_resolved_include_dependencies(
                    config,
                    unit_relative_path,
                    resolved_path,
                    line_number=line_number,
                    include_path=include_path,
                    location=location,
                    include_stack=include_stack,
                    scanned_sources=scanned_sources,
                    define_shadowing_seen=define_shadowing_seen,
                    preprocessor_seen=preprocessor_seen,
                    macro_semantics_seen=macro_semantics_seen,
                    diagnostic_config=diagnostic_config,
                    source_backend=source_backend,
                    variant=variant,
                )
            )
            dependencies.extend(nested_dependencies)
            diagnostics.extend(nested_diagnostics)

    return dependencies, diagnostics


def _scan_include_dependencies(
    config: ProjectConfig,
    unit_path: Path,
    relative_path: str,
    source_backend: str,
) -> tuple[list[dict[str, Any]], list[ProjectDiagnostic]]:
    dependencies: list[dict[str, Any]] = []
    diagnostics: list[ProjectDiagnostic] = []
    define_shadowing_seen: set[tuple[str, int, str, str]] = set()
    preprocessor_seen: set[tuple[str, int, str, str]] = set()
    macro_semantics_seen: set[tuple[str, int, str, str, str | None]] = set()
    for variant, defines in _variant_jobs(config):
        scan_config = (
            replace(config, defines=defines) if variant is not None else config
        )
        variant_dependencies, variant_diagnostics = (
            _scan_include_dependencies_for_source(
                scan_config,
                relative_path,
                unit_path,
                relative_path,
                include_stack=(relative_path,),
                scanned_sources=set(),
                define_shadowing_seen=define_shadowing_seen,
                preprocessor_seen=preprocessor_seen,
                macro_semantics_seen=macro_semantics_seen,
                diagnostic_config=config,
                source_backend=source_backend,
                variant=variant,
            )
        )
        dependencies.extend(variant_dependencies)
        diagnostics.extend(variant_diagnostics)
    return dependencies, diagnostics


def _resolved_source_root(config: ProjectConfig, source_root: str) -> Path:
    return _project_config_path(config.root, source_root).resolve()


def _source_root_status_for_path(config: ProjectConfig, path: Path) -> str:
    if not _is_relative_to(path, config.root):
        return "outside-project"
    if not path.exists():
        return "missing"
    if not path.is_dir():
        return "not-directory"
    return "active"


def _source_root_status_records(config: ProjectConfig) -> list[dict[str, Any]]:
    records = []
    for source_root in config.source_roots:
        absolute_root = _resolved_source_root(config, source_root)
        status = _source_root_status_for_path(config, absolute_root)
        records.append(
            {
                "path": source_root,
                "resolvedPath": str(absolute_root),
                "status": status,
                "scanVisible": status == "active",
            }
        )
    return records


def _source_root_status_counts(
    records: Sequence[Mapping[str, Any]],
) -> dict[str, int]:
    counts = {status: 0 for status in sorted(SOURCE_ROOT_STATUSES)}
    for record in records:
        status = record.get("status")
        if isinstance(status, str) and status in counts:
            counts[status] += 1
    return {status: count for status, count in counts.items() if count}


def _config_location(config: ProjectConfig) -> SourceLocation:
    if config.config_path:
        file = (
            _relpath(config.config_path, config.root)
            if _is_relative_to(config.config_path, config.root)
            else str(config.config_path)
        )
        return SourceLocation(file=file)
    return SourceLocation(file=".")


@dataclass(frozen=True)
class ProjectConfig:
    """Configuration for scanning and translating a shader repository."""

    root: Path | str | os.PathLike[str]
    config_path: Path | str | os.PathLike[str] | None = None
    source_roots: Sequence[str] | str = (".",)
    include_patterns: Sequence[str] | str = ()
    exclude_patterns: Sequence[str] | str = DEFAULT_EXCLUDE_PATTERNS
    targets: Sequence[str] | str = ()
    output_dir: str | os.PathLike[str] = DEFAULT_OUTPUT_DIR
    source_overrides: Mapping[str, str] = field(default_factory=dict)
    include_dirs: Sequence[str] | str = ()
    defines: Mapping[str, str] = field(default_factory=dict)
    source_options: Mapping[str, Mapping[str, Any]] = field(default_factory=dict)
    variants: Mapping[str, Mapping[str, str]] = field(default_factory=dict)
    selected_variants: Sequence[str] | str = ()
    external_corpus_manifest: str | os.PathLike[str] | None = None

    def __post_init__(self) -> None:
        root_path = _filesystem_path_arg(self.root, field_name="ProjectConfig.root")
        object.__setattr__(self, "root", root_path.resolve())
        if self.config_path is not None:
            config_path = _path_string_arg(
                self.config_path, field_name="ProjectConfig.config_path"
            )
            if not config_path.strip():
                raise ValueError("ProjectConfig.config_path must be non-empty")
            object.__setattr__(
                self,
                "config_path",
                _project_config_path(root_path, config_path).resolve(),
            )
        for field_name in (
            "source_roots",
            "include_patterns",
            "exclude_patterns",
            "include_dirs",
        ):
            object.__setattr__(
                self,
                field_name,
                _normalize_project_relative_paths(
                    _as_str_list(
                        getattr(self, field_name),
                        field_name=f"ProjectConfig.{field_name}",
                        allow_pathlike=True,
                    )
                ),
            )
        for field_name in ("targets", "selected_variants"):
            object.__setattr__(
                self,
                field_name,
                _as_str_list(
                    getattr(self, field_name),
                    field_name=f"ProjectConfig.{field_name}",
                ),
            )
        output_dir = _path_string_arg(
            self.output_dir, field_name="ProjectConfig.output_dir"
        )
        if not output_dir.strip():
            raise ValueError("ProjectConfig.output_dir must be a non-empty string")
        object.__setattr__(
            self, "output_dir", _normalize_project_relative_path(output_dir)
        )
        if not isinstance(self.source_overrides, Mapping):
            raise ValueError("ProjectConfig.source_overrides must be a mapping")
        object.__setattr__(
            self,
            "source_overrides",
            _normalize_source_override_mapping(
                _as_non_empty_str_mapping(
                    self.source_overrides,
                    field_name="ProjectConfig.source_overrides",
                )
            ),
        )
        if not isinstance(self.defines, Mapping):
            raise ValueError("ProjectConfig.defines must be a mapping")
        object.__setattr__(
            self,
            "defines",
            _as_str_mapping(self.defines, field_name="ProjectConfig.defines"),
        )
        object.__setattr__(
            self,
            "source_options",
            _as_source_options(
                self.source_options, field_name="ProjectConfig.source_options"
            ),
        )
        if not isinstance(self.variants, Mapping):
            raise ValueError("ProjectConfig.variants must be a mapping")
        variants: dict[str, dict[str, str]] = {}
        for name, defines in self.variants.items():
            if not isinstance(name, str) or not name.strip():
                raise ValueError(
                    "ProjectConfig.variants keys must be non-empty strings"
                )
            if not isinstance(defines, Mapping):
                raise ValueError(f"ProjectConfig.variants.{name} must be a mapping")
            variants[name] = _as_str_mapping(
                defines,
                field_name=f"ProjectConfig.variants.{name}",
            )
        object.__setattr__(self, "variants", variants)
        if self.external_corpus_manifest is not None:
            external_corpus_manifest = _path_string_arg(
                self.external_corpus_manifest,
                field_name="ProjectConfig.external_corpus_manifest",
            )
            if not external_corpus_manifest.strip():
                raise ValueError(
                    "ProjectConfig.external_corpus_manifest must be a non-empty string"
                )
            object.__setattr__(
                self,
                "external_corpus_manifest",
                _normalize_project_relative_path(external_corpus_manifest),
            )

    def normalized_targets(self) -> list[str]:
        return _normalized_targets(self.targets)

    @property
    def output_path(self) -> Path:
        return _project_output_path(self.root, self.output_dir)


def _project_config_hash(config: ProjectConfig) -> dict[str, str] | None:
    if config.config_path is None or not config.config_path.is_file():
        return None
    return _source_hash(config.config_path)


@dataclass(frozen=True)
class SourceLocation:
    """Compiler-compatible source span used by project diagnostics."""

    file: str
    line: int = 1
    column: int = 1
    offset: int = 0
    length: int = 0
    end_line: int = 1
    end_column: int = 1
    end_offset: int = 0

    def to_json(self) -> dict[str, Any]:
        return {
            "file": self.file,
            "line": self.line,
            "column": self.column,
            "offset": self.offset,
            "length": self.length,
            "endLine": self.end_line,
            "endColumn": self.end_column,
            "endOffset": self.end_offset,
        }


@dataclass(frozen=True)
class ProjectDiagnostic:
    """Structured project diagnostic compatible with compiler diagnostics."""

    severity: str
    code: str
    message: str
    location: SourceLocation
    target: str | None = None
    source_backend: str | None = None
    variant: str | None = None
    check_kind: str | None = None
    missing_capabilities: Sequence[str] = ()
    original_location: SourceLocation | None = None

    def to_json(self) -> dict[str, Any]:
        payload = {
            "severity": self.severity,
            "code": self.code,
            "message": self.message,
            "location": self.location.to_json(),
        }
        if self.original_location:
            payload["originalLocation"] = self.original_location.to_json()
        if self.target:
            payload["target"] = self.target
        if self.source_backend:
            payload["sourceBackend"] = self.source_backend
        if self.variant:
            payload["variant"] = self.variant
        if self.check_kind:
            payload["checkKind"] = self.check_kind
        if self.missing_capabilities:
            payload["missingCapabilities"] = list(self.missing_capabilities)
        return payload


@dataclass(frozen=True)
class ProjectNativeDirective:
    source: str
    source_backend: str
    line: int
    column: int
    kind: str
    payload: str
    handling_status: str
    variant: str | None = None

    def to_json(self) -> dict[str, Any]:
        payload = {
            "source": self.source,
            "sourceBackend": self.source_backend,
            "line": self.line,
            "column": self.column,
            "kind": self.kind,
            "payload": self.payload,
            "handlingStatus": self.handling_status,
        }
        if self.variant:
            payload["variant"] = self.variant
        return payload


@dataclass(frozen=True)
class ProjectTemplateMaterializedSource:
    text: str
    metadata: Mapping[str, Any]
    defines: Mapping[str, str]
    source_options: Mapping[str, Any]
    diagnostics: Sequence[ProjectDiagnostic] = ()
    blocked: bool = False
    error: str | None = None


def _configuration_diagnostics(config: ProjectConfig) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    location = _config_location(config)
    if not _is_relative_to(config.output_path, config.root):
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code=OUTPUT_DIR_OUTSIDE_PROJECT_CODE,
                message=(
                    f"Configured output directory '{config.output_dir}' resolves "
                    f"outside the repository: {config.output_path.resolve()}"
                ),
                location=location,
                missing_capabilities=["artifact.manifest"],
            )
        )
    if config.external_corpus_manifest:
        manifest_path = _external_corpus_manifest_path(config)
        if manifest_path is not None and not _is_relative_to(
            manifest_path, config.root
        ):
            diagnostics.append(
                ProjectDiagnostic(
                    severity="error",
                    code="project.config.external-corpus-outside-project",
                    message=(
                        "Configured external corpus manifest resolves outside "
                        f"the repository: {manifest_path}"
                    ),
                    location=location,
                    missing_capabilities=["external.corpus"],
                )
            )
        else:
            manifest, status = _load_external_corpus_manifest(config)
            if status in {"missing", "invalid"}:
                diagnostics.append(
                    ProjectDiagnostic(
                        severity="warning",
                        code=f"project.config.external-corpus-{status}",
                        message=(
                            "Configured external corpus manifest is "
                            f"{status}: {config.external_corpus_manifest}"
                        ),
                        location=location,
                        missing_capabilities=["external.corpus"],
                    )
                )
            elif manifest is not None:
                diagnostics.extend(_external_corpus_entry_diagnostics(config, manifest))
    return diagnostics


def _external_corpus_entry_diagnostics(
    config: ProjectConfig, manifest: Mapping[str, Any]
) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    location = _config_location(config)
    seen_ids: dict[str, int] = {}
    seen_paths: dict[str, int] = {}
    for index, entry in enumerate(manifest.get("entries", [])):
        reasons = _external_corpus_manifest_entry_reasons(entry)
        if not reasons and isinstance(entry, Mapping):
            reasons = _external_corpus_manifest_entry_duplicate_reasons(
                entry,
                seen_ids=seen_ids,
                seen_paths=seen_paths,
            )
        if not reasons:
            entry_id, path = _external_corpus_manifest_entry_identity(entry)
            if entry_id is not None:
                seen_ids[entry_id] = index
            if path is not None:
                seen_paths[path] = index
            continue
        diagnostics.append(
            ProjectDiagnostic(
                severity="warning",
                code="project.config.external-corpus-entry-invalid",
                message=(
                    f"External corpus manifest entry {index + 1} is invalid "
                    "and will be skipped: " + "; ".join(reasons)
                ),
                location=location,
                missing_capabilities=["external.corpus"],
            )
        )
    return diagnostics


def _external_corpus_source_backend_mismatch_diagnostics(
    config: ProjectConfig,
    units: Sequence[ProjectTranslationUnit],
) -> list[ProjectDiagnostic]:
    manifest_path = _external_corpus_manifest_path(config)
    if manifest_path is None or not _is_relative_to(manifest_path, config.root):
        return []

    manifest, _status = _load_external_corpus_manifest(config)
    if manifest is None:
        return []

    units_by_path = {unit.relative_path: unit for unit in units}
    diagnostics: list[ProjectDiagnostic] = []
    for index, entry in _valid_external_corpus_manifest_entries(manifest):
        path = str(entry.get("path", "")).replace("\\", "/")
        unit = units_by_path.get(path)
        declared_source_backend = entry.get("sourceBackend")
        if unit is None or not _is_non_empty_string(declared_source_backend):
            continue
        declared_backend = _external_corpus_source_backend(declared_source_backend)
        if declared_backend == unit.source_backend:
            continue
        diagnostics.append(
            ProjectDiagnostic(
                severity="warning",
                code="project.config.external-corpus-source-backend-mismatch",
                message=(
                    f"External corpus manifest entry {index + 1} declares "
                    f"sourceBackend {declared_backend} for {path}, but project "
                    f"discovery resolved {unit.source_backend}; the report uses "
                    "the discovered source backend."
                ),
                location=_config_location(config),
                missing_capabilities=["external.corpus"],
            )
        )
    return diagnostics


def _source_root_diagnostics(config: ProjectConfig) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    location = _config_location(config)
    for source_root in config.source_roots:
        absolute_root = _resolved_source_root(config, source_root)
        status = _source_root_status_for_path(config, absolute_root)
        if status == "outside-project":
            diagnostics.append(
                ProjectDiagnostic(
                    severity="error",
                    code="project.config.source-root-outside-project",
                    message=(
                        f"Configured source root '{source_root}' resolves outside "
                        f"the repository: {absolute_root}"
                    ),
                    location=location,
                    missing_capabilities=["repo.scan"],
                )
            )
            continue
        if status == "missing":
            diagnostics.append(
                ProjectDiagnostic(
                    severity="warning",
                    code="project.scan.missing-source-root",
                    message=f"Configured source root does not exist: {source_root}",
                    location=location,
                    missing_capabilities=["repo.scan"],
                )
            )
            continue
        if status == "not-directory":
            diagnostics.append(
                ProjectDiagnostic(
                    severity="warning",
                    code="project.config.source-root-not-directory",
                    message=(
                        "Configured source root resolves to a file or "
                        f"non-directory path: {source_root}"
                    ),
                    location=location,
                    missing_capabilities=["repo.scan"],
                )
            )
    return diagnostics


def _include_dir_diagnostics(config: ProjectConfig) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    location = _config_location(config)
    for include_dir in config.include_dirs:
        absolute_dir = _resolved_include_dir(config, include_dir)
        status = _include_dir_status_for_path(config, absolute_dir)
        if status == "outside-project":
            diagnostics.append(
                ProjectDiagnostic(
                    severity="warning",
                    code="project.config.include-dir-outside-project",
                    message=(
                        f"Configured include directory '{include_dir}' resolves "
                        f"outside the repository: {absolute_dir}"
                    ),
                    location=location,
                    missing_capabilities=["include.resolution"],
                )
            )
            continue
        if status == "missing":
            diagnostics.append(
                ProjectDiagnostic(
                    severity="warning",
                    code="project.config.missing-include-dir",
                    message=(
                        f"Configured include directory does not exist: {include_dir}"
                    ),
                    location=location,
                    missing_capabilities=["include.resolution"],
                )
            )
            continue
        if status == "not-directory":
            diagnostics.append(
                ProjectDiagnostic(
                    severity="warning",
                    code="project.config.include-dir-not-directory",
                    message=(
                        "Configured include directory resolves to a file or "
                        f"non-directory path: {include_dir}"
                    ),
                    location=location,
                    missing_capabilities=["include.resolution"],
                )
            )
    return diagnostics


def _scan_pattern_diagnostics(config: ProjectConfig) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    location = _config_location(config)
    for pattern in config.include_patterns:
        if _is_repository_relative_glob(pattern):
            continue
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.config.include-pattern-outside-project",
                message=(
                    f"Configured include pattern '{pattern}' is not "
                    "repository-relative."
                ),
                location=location,
                missing_capabilities=["repo.scan"],
            )
        )
    for pattern in config.exclude_patterns:
        if _is_repository_relative_glob(pattern):
            continue
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.config.exclude-pattern-outside-project",
                message=(
                    f"Configured exclude pattern '{pattern}' is not "
                    "repository-relative."
                ),
                location=location,
                missing_capabilities=["repo.scan"],
            )
        )
    for pattern in config.source_overrides:
        if _is_repository_relative_glob(pattern):
            continue
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.config.source-override-pattern-outside-project",
                message=(
                    f"Configured source override pattern '{pattern}' is not "
                    "repository-relative."
                ),
                location=location,
                missing_capabilities=["source.override"],
            )
        )
    if config.source_overrides:
        register_default_sources()
        discover_backend_plugins()
    supported_sources = ", ".join(SOURCE_REGISTRY.names())
    for pattern, backend in config.source_overrides.items():
        if _is_non_empty_string(backend) and SOURCE_REGISTRY.get(backend):
            continue
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.config.unsupported-source-override",
                message=(
                    f"Source override '{pattern}' references unsupported backend "
                    f"'{backend}'. Supported source backends: {supported_sources}"
                ),
                location=location,
                missing_capabilities=["source.override"],
            )
        )
    return diagnostics


def _target_diagnostics(
    config: ProjectConfig, targets: Sequence[str]
) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    supported_targets = _supported_target_names()
    supported = set(supported_targets)
    for target in targets:
        if target in supported:
            continue
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.config.unsupported-target",
                message=(
                    f"Target backend '{target}' is not supported. Supported "
                    f"targets: {', '.join(supported_targets)}"
                ),
                location=_config_location(config),
                target=target,
                missing_capabilities=["target.backend"],
            )
        )
    return diagnostics


@dataclass(frozen=True)
class ProjectTranslationUnit:
    """A discovered source file that can be translated as one unit."""

    path: Path
    relative_path: str
    source_backend: str
    extension: str
    source_hash: Mapping[str, str]
    source_size_bytes: int
    source_override: str | None = None
    include_dependencies: Sequence[Mapping[str, Any]] = ()

    def to_json(self) -> dict[str, Any]:
        payload = {
            "id": self.relative_path,
            "path": self.relative_path,
            "sourceBackend": self.source_backend,
            "extension": self.extension,
            "sourceHash": dict(self.source_hash),
            "sourceSizeBytes": self.source_size_bytes,
        }
        if self.source_override:
            payload["sourceOverride"] = self.source_override
        if self.include_dependencies:
            payload["includeDependencies"] = [
                dict(dependency) for dependency in self.include_dependencies
            ]
        return payload


def _required_capabilities_for_unit(unit: ProjectTranslationUnit) -> list[str]:
    if unit.source_backend != "opengl":
        return []
    try:
        source = unit.path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return []
    if (
        GLSL_FRAGMENT_INVOCATION_DENSITY_EXTENSION not in source
        and GLSL_FRAGMENT_INVOCATION_DENSITY_BUILTIN not in source
    ):
        return []
    return list(GLSL_FRAGMENT_INVOCATION_DENSITY_CAPABILITIES)


@dataclass(frozen=True)
class ProjectScan:
    """Result of scanning a repository for shader translation units."""

    config: ProjectConfig
    units: Sequence[ProjectTranslationUnit]
    skipped: Sequence[dict[str, Any]] = ()
    native_directives: Sequence[ProjectNativeDirective] = ()
    diagnostics: Sequence[ProjectDiagnostic] = ()

    def to_report(
        self, targets: Sequence[str] | str | None = None
    ) -> ProjectPortabilityReport:
        report_targets = (
            _normalized_targets(targets)
            if targets is not None
            else self.config.normalized_targets()
        )
        diagnostics = list(self.diagnostics)
        diagnostics.extend(_target_diagnostics(self.config, report_targets))
        return ProjectPortabilityReport(
            config=self.config,
            targets=report_targets,
            units=self.units,
            skipped=self.skipped,
            native_directives=self.native_directives,
            artifacts=[],
            diagnostics=diagnostics,
            validation={"toolchains": [], "artifacts": []},
            migration_actions=_project_migration_actions(
                self.config, self.units, report_targets
            ),
            artifact_matrix=_artifact_matrix_report(
                self.config, self.units, report_targets, self.config.variants, []
            ),
        )


@dataclass(frozen=True)
class ProjectPortabilityReport:
    """Machine-readable report emitted by the project porting pipeline."""

    config: ProjectConfig
    targets: Sequence[str]
    units: Sequence[ProjectTranslationUnit]
    skipped: Sequence[dict[str, Any]]
    native_directives: Sequence[ProjectNativeDirective]
    artifacts: Sequence[dict[str, Any]]
    diagnostics: Sequence[ProjectDiagnostic]
    validation: Mapping[str, Any]
    migration_actions: Sequence[dict[str, Any]]
    artifact_matrix: Mapping[str, Any] | None = None
    generated_at: int = field(default_factory=lambda: int(time.time()))

    def to_json(self) -> dict[str, Any]:
        artifact_count = len(self.artifacts)
        translated_count = sum(
            1 for artifact in self.artifacts if artifact.get("status") == "translated"
        )
        failed_count = sum(
            1 for artifact in self.artifacts if artifact.get("status") == "failed"
        )
        diagnostics = [diagnostic.to_json() for diagnostic in self.diagnostics]
        source_map_rollups = _source_map_rollups(self.artifacts)
        define_processing_rollups = _define_processing_rollups(self.artifacts)
        include_path_processing_rollups = _include_path_processing_rollups(
            self.artifacts
        )
        include_dependency_processing_rollups = _include_dependency_processing_rollups(
            self.artifacts
        )
        source_root_status = _source_root_status_records(self.config)
        include_dir_status = _include_dir_status_records(self.config)
        external_corpus = _external_corpus_report(
            self.config, self.units, self.artifacts, self.targets
        )
        payload = {
            "schemaVersion": REPORT_SCHEMA_VERSION,
            "kind": REPORT_KIND,
            "generatedAt": self.generated_at,
            "generator": {
                "name": "CrossTL",
                "pipeline": REPORT_GENERATOR_PIPELINE,
                "packageVersion": _package_version(),
            },
            "project": {
                "root": str(self.config.root),
                "config": (
                    str(self.config.config_path) if self.config.config_path else None
                ),
                "configHash": _project_config_hash(self.config),
                "sourceRoots": list(self.config.source_roots),
                "sourceRootCount": len(self.config.source_roots),
                "sourceRootStatus": source_root_status,
                "sourceRootStatusCounts": _source_root_status_counts(
                    source_root_status
                ),
                "includePatterns": list(self.config.include_patterns),
                "includePatternCount": len(self.config.include_patterns),
                "excludePatterns": list(self.config.exclude_patterns),
                "excludePatternCount": len(self.config.exclude_patterns),
                "targets": list(self.targets),
                "outputDir": str(self.config.output_path),
                "sourceOverrides": dict(sorted(self.config.source_overrides.items())),
                "sourceOverrideCount": len(self.config.source_overrides),
                "sourceOptions": {
                    name: dict(sorted(options.items()))
                    for name, options in sorted(self.config.source_options.items())
                },
                "sourceOptionCount": len(self.config.source_options),
                "includeDirs": list(self.config.include_dirs),
                "includeDirCount": len(self.config.include_dirs),
                "includeDirStatus": include_dir_status,
                "includeDirStatusCounts": _include_dir_status_counts(
                    include_dir_status
                ),
                "defines": dict(sorted(self.config.defines.items())),
                "defineCount": len(self.config.defines),
                "variants": {
                    name: dict(sorted(defines.items()))
                    for name, defines in sorted(self.config.variants.items())
                },
                "variantCount": len(self.config.variants),
                "variantDefineCounts": _variant_define_counts(self.config.variants),
                "selectedVariants": list(self.config.selected_variants),
                "externalCorpusManifest": self.config.external_corpus_manifest,
            },
            "summary": {
                "unitCount": len(self.units),
                "skippedCount": len(self.skipped),
                "targetCount": len(self.targets),
                "artifactCount": artifact_count,
                "translatedCount": translated_count,
                "failedCount": failed_count,
                "diagnosticCounts": _diagnostic_counts(self.diagnostics),
                "diagnosticsByCode": _diagnostic_counts_by_code(self.diagnostics),
                "diagnosticsByTarget": _diagnostic_counts_by_target(self.diagnostics),
                "diagnosticsBySourceBackend": _diagnostic_counts_by_source_backend(
                    self.diagnostics
                ),
                "diagnosticsByVariant": _diagnostic_counts_by_variant(self.diagnostics),
                "diagnosticsByCheckKind": _diagnostic_counts_by_check_kind(
                    self.diagnostics
                ),
                "missingCapabilityCounts": _missing_capability_counts(self.diagnostics),
                "unitsBySourceBackend": _unit_counts_by_source_backend(self.units),
                "unitsByExtension": _unit_counts_by_extension(self.units),
                "unitsBySourceOverride": _unit_counts_by_source_override(self.units),
                "includeDependencyCount": _include_dependency_count(self.units),
                "includeDependenciesByKind": _include_dependency_counts_by_kind(
                    self.units
                ),
                "includeDependenciesByStatus": _include_dependency_counts_by_status(
                    self.units
                ),
                "includeDependenciesByResolvedFrom": (
                    _include_dependency_counts_by_resolved_from(self.units)
                ),
                "includeDependenciesBySourceBackend": (
                    _include_dependency_counts_by_source_backend(self.units)
                ),
                "includeDependenciesBySourceBackendStatus": (
                    _include_dependency_counts_by_source_backend_status(self.units)
                ),
                "includeDependenciesByVariant": _include_dependency_counts_by_variant(
                    self.units
                ),
                "skippedByReason": _skipped_counts_by_reason(self.skipped),
                "skippedByExtension": _skipped_counts_by_extension(self.skipped),
                "skippedBySourceOverride": _skipped_counts_by_source_override(
                    self.skipped
                ),
                "artifactsBySourceBackend": _artifact_counts_by_source_backend(
                    self.artifacts
                ),
                "artifactsByVariant": _artifact_counts_by_variant(self.artifacts),
                "artifactsByTarget": _artifact_counts_by_target(self.artifacts),
                **_artifact_provenance_rollups(self.artifacts),
                **source_map_rollups,
                **define_processing_rollups,
                **include_path_processing_rollups,
                **include_dependency_processing_rollups,
            },
            "units": [unit.to_json() for unit in self.units],
            "skipped": list(self.skipped),
            "nativeDirectives": [
                directive.to_json() for directive in self.native_directives
            ],
            "artifacts": list(self.artifacts),
            "diagnosticCounts": _diagnostic_counts(self.diagnostics),
            "diagnostics": diagnostics,
            "validation": dict(self.validation),
            "migration": {
                "scope": REPORT_MIGRATION_SCOPE,
                "nonGoals": list(REPORT_MIGRATION_NON_GOALS),
                **_migration_action_rollups(self.migration_actions),
                **_migration_placeholder_rollups(self.diagnostics),
                "actions": list(self.migration_actions),
            },
        }
        if self.artifact_matrix is not None:
            payload["artifactMatrix"] = dict(self.artifact_matrix)
        if external_corpus is not None:
            payload["externalCorpus"] = external_corpus
        return payload

    def write_json(self, path: str | os.PathLike[str]) -> None:
        path = _filesystem_path_arg(path, field_name="Project report path")
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(
            json.dumps(self.to_json(), indent=2, sort_keys=True) + "\n",
            encoding="utf-8",
        )


def load_project_config(
    root: str | os.PathLike[str], config: str | os.PathLike[str] | None = None
) -> ProjectConfig:
    """Load ``crosstl.toml`` if present, otherwise return default scan settings."""
    root_path = _filesystem_path_arg(root, field_name="Project root").resolve()
    explicit_config = config is not None
    if explicit_config:
        try:
            config_value = os.fspath(config)
        except TypeError as exc:
            raise ValueError(
                "Project config path must be a string or path-like object returning str"
            ) from exc
        if not isinstance(config_value, str):
            raise ValueError(
                "Project config path must be a string or path-like object returning str"
            )
        if not config_value.strip():
            raise ValueError("Project config path must be non-empty")
        config_path = _project_config_path(root_path, config_value).resolve()
    else:
        config_path = root_path / DEFAULT_CONFIG_NAME
    if not config_path.exists():
        if explicit_config:
            raise ValueError(f"Project config not found: {config_path}")
        return ProjectConfig(root=root_path, config_path=None)
    if not config_path.is_file():
        raise ValueError(f"Project config path is not a file: {config_path}")

    raw = _load_toml(config_path)
    project = raw.get("project", raw)
    if not isinstance(project, Mapping):
        raise ValueError("crosstl.toml [project] must be a table")

    sources = _as_non_empty_str_mapping(
        project.get("sources"), field_name="crosstl.toml [project.sources]"
    )
    defines = _as_str_mapping(
        project.get("defines"), field_name="crosstl.toml [project.defines]"
    )
    source_options = _as_source_options(
        project.get("source_options"),
        field_name="crosstl.toml [project.source_options]",
    )
    variants = project.get("variants", {})
    if not isinstance(variants, Mapping):
        raise ValueError("crosstl.toml [project.variants] must be a table")
    output_dir = _as_optional_non_empty_str(
        project.get("output_dir"),
        field_name="crosstl.toml project.output_dir",
    )
    external_corpus_manifest = _as_optional_non_empty_str(
        project.get("external_corpus_manifest"),
        field_name="crosstl.toml project.external_corpus_manifest",
    )
    if external_corpus_manifest is not None:
        external_corpus_manifest = _normalize_project_relative_path(
            external_corpus_manifest
        )

    excludes = _as_str_list(project.get("exclude"), field_name="project.exclude")
    if not excludes:
        excludes = list(DEFAULT_EXCLUDE_PATTERNS)
    return ProjectConfig(
        root=root_path,
        config_path=config_path,
        source_roots=(
            _normalize_project_relative_paths(
                _as_str_list(
                    project.get("source_roots", "."),
                    field_name="project.source_roots",
                )
            )
            or (".",)
        ),
        include_patterns=_normalize_project_relative_paths(
            _as_str_list(project.get("include"), field_name="project.include")
        ),
        exclude_patterns=_normalize_project_relative_paths(excludes),
        targets=_as_str_list(project.get("targets"), field_name="project.targets"),
        output_dir=_normalize_project_relative_path(output_dir or DEFAULT_OUTPUT_DIR),
        source_overrides=_normalize_project_relative_path_mapping(sources),
        include_dirs=_normalize_project_relative_paths(
            _as_str_list(project.get("include_dirs"), field_name="project.include_dirs")
        ),
        defines=defines,
        source_options=source_options,
        variants=_variant_defines(variants),
        selected_variants=_as_str_list(
            project.get("selected_variants"),
            field_name="project.selected_variants",
        ),
        external_corpus_manifest=external_corpus_manifest,
    )


def _override_for_path(relative_path: str, config: ProjectConfig) -> str | None:
    for pattern, backend in config.source_overrides.items():
        if fnmatch.fnmatch(relative_path, _normalize_project_relative_path(pattern)):
            return backend
    return None


def _iter_scan_candidates(config: ProjectConfig) -> list[Path]:
    register_default_sources()
    discover_backend_plugins()
    known_extensions = tuple(SOURCE_REGISTRY.extensions())
    explicit_include_patterns = bool(config.include_patterns)
    include_patterns = _repository_relative_globs(config.include_patterns)
    source_override_patterns = set(
        _repository_relative_globs(tuple(config.source_overrides))
    )
    if not explicit_include_patterns:
        include_patterns = [f"**/*{extension}" for extension in known_extensions]
        include_patterns.extend(
            f"**/*{extension}"
            for extension in TARGET_ONLY_UNSUPPORTED_SOURCE_ARTIFACT_EXTENSIONS
        )
        include_patterns.extend(source_override_patterns)

    candidates: set[Path] = set()
    for source_root in config.source_roots:
        absolute_root = _resolved_source_root(config, source_root)
        if not _is_relative_to(absolute_root, config.root):
            continue
        if not absolute_root.exists():
            continue
        if not absolute_root.is_dir():
            continue
        for pattern in include_patterns:
            if explicit_include_patterns or pattern in source_override_patterns:
                candidates.update(
                    path
                    for path in config.root.glob(pattern)
                    if path.is_file() and _is_relative_to(path, absolute_root)
                )
            else:
                candidates.update(
                    path for path in absolute_root.glob(pattern) if path.is_file()
                )
    return sorted(candidates)


def _config_with_expanded_native_directive_variants(
    config: ProjectConfig,
    native_directives: Sequence[ProjectNativeDirective],
) -> ProjectConfig:
    expanded_variants = {
        directive.variant: {}
        for directive in native_directives
        if directive.handling_status == "expanded" and directive.variant
    }
    new_variants = {
        name: defines
        for name, defines in expanded_variants.items()
        if name not in config.variants
    }
    if not new_variants:
        return config
    return replace(
        config,
        variants={**dict(config.variants), **new_variants},
    )


def scan_project(
    config_or_root: ProjectConfig | str | os.PathLike[str],
    *,
    variants: Sequence[str] | str | None = None,
) -> ProjectScan:
    """Discover supported shader/GPU source files in a repository."""
    config = (
        config_or_root
        if isinstance(config_or_root, ProjectConfig)
        else load_project_config(config_or_root)
    )
    config = _config_with_selected_variants(config, variants)
    units: list[ProjectTranslationUnit] = []
    skipped: list[dict[str, Any]] = []
    native_directives: list[ProjectNativeDirective] = []
    diagnostics: list[ProjectDiagnostic] = _configuration_diagnostics(config)
    diagnostics.extend(_source_root_diagnostics(config))
    diagnostics.extend(_include_dir_diagnostics(config))
    diagnostics.extend(_scan_pattern_diagnostics(config))
    exclude_patterns = _repository_relative_globs(config.exclude_patterns)
    internal_exclude_patterns = _internal_exclude_patterns(config)

    for path in _iter_scan_candidates(config):
        try:
            relative_path = _relpath(path, config.root)
        except ValueError:
            continue
        if _path_matches(relative_path, exclude_patterns):
            continue
        if _path_matches(relative_path, internal_exclude_patterns):
            continue

        override = _override_for_path(relative_path, config)
        unsupported_extension_message = (
            None
            if override
            else SOURCE_REGISTRY.unsupported_extension_message(str(path))
        )
        if unsupported_extension_message:
            skipped.append({"path": relative_path, "reason": "unsupported-extension"})
            diagnostics.append(
                ProjectDiagnostic(
                    severity="warning",
                    code="project.scan.unsupported-source",
                    message=f"{relative_path}: {unsupported_extension_message}",
                    location=SourceLocation(file=relative_path),
                    missing_capabilities=["source.discovery"],
                )
            )
            diagnostics.extend(
                _scan_unsupported_wgsl_macro_semantics(config, path, relative_path)
            )
            continue

        source_spec = (
            SOURCE_REGISTRY.get(override)
            if override
            else SOURCE_REGISTRY.get_by_extension(str(path))
        )
        if override and not source_spec:
            skipped.append(
                {
                    "path": relative_path,
                    "reason": "unsupported-source-override",
                    "sourceOverride": override,
                }
            )
            continue
        if not source_spec:
            skipped.append({"path": relative_path, "reason": "unsupported-extension"})
            diagnostics.append(
                ProjectDiagnostic(
                    severity="warning",
                    code="project.scan.unsupported-source",
                    message=f"No registered source backend for {relative_path}",
                    location=SourceLocation(file=relative_path),
                    missing_capabilities=["source.discovery"],
                )
            )
            continue

        if source_spec.name == "metal" and _is_metal_template_utility_unit(
            config,
            path,
        ):
            skipped.append({"path": relative_path, "reason": "metal-template-utility"})
            continue

        scanned_directives, native_directive_diagnostics = (
            _scan_native_directive_planning(
                config,
                path,
                relative_path,
                source_backend=source_spec.name,
            )
        )
        native_directives.extend(scanned_directives)
        diagnostics.extend(native_directive_diagnostics)
        include_dependencies, include_diagnostics = _scan_include_dependencies(
            config, path, relative_path, source_spec.name
        )
        diagnostics.extend(include_diagnostics)
        units.append(
            ProjectTranslationUnit(
                path=path,
                relative_path=relative_path,
                source_backend=source_spec.name,
                extension=path.suffix.lower(),
                source_hash=_source_hash(path),
                source_size_bytes=path.stat().st_size,
                source_override=override,
                include_dependencies=include_dependencies,
            )
        )

    scan_config = _config_with_expanded_native_directive_variants(
        config, native_directives
    )
    diagnostics.extend(
        _external_corpus_source_backend_mismatch_diagnostics(scan_config, units)
    )
    if not units:
        diagnostics.append(
            ProjectDiagnostic(
                severity="warning",
                code="project.scan.empty",
                message="No supported shader or GPU source files were discovered",
                location=_config_location(config),
                missing_capabilities=["repo.scan"],
            )
        )
    return ProjectScan(
        config=scan_config,
        units=units,
        skipped=skipped,
        native_directives=native_directives,
        diagnostics=diagnostics,
    )


def _artifact_path(
    config: ProjectConfig,
    unit: ProjectTranslationUnit,
    target: str,
    variant: str | None = None,
    *,
    preserve_source_suffix: bool = False,
) -> Path:
    base = config.output_path / target
    if variant is not None:
        base = base / _variant_output_segment(variant)
    return base / _artifact_relative_path(
        unit.relative_path,
        target,
        preserve_source_suffix=preserve_source_suffix,
    )


def _artifact_relative_path(
    source: str,
    target: str,
    *,
    preserve_source_suffix: bool = False,
) -> Path:
    extension = _artifact_target_extension(target)
    relative = PurePosixPath(source.replace("\\", "/"))
    if preserve_source_suffix:
        if relative.suffix:
            return Path(f"{relative.as_posix()}{extension}")
        return Path(relative.with_suffix(f".source{extension}").as_posix())
    return Path(relative.with_suffix(extension).as_posix())


def _unit_artifact_source_path(unit: Any) -> str | None:
    if isinstance(unit, ProjectTranslationUnit):
        source = unit.relative_path
    elif isinstance(unit, Mapping):
        source = unit.get("path")
    else:
        return None
    if _is_non_empty_string(source) and _is_report_identity_path(source):
        return source
    return None


def _artifact_source_suffix_pairs(
    units: Sequence[Any],
    targets: Sequence[str],
) -> set[tuple[str, str]]:
    sources = sorted(
        {
            source
            for unit in units
            for source in (_unit_artifact_source_path(unit),)
            if source is not None
        }
    )
    normalized_targets = _normalized_targets(targets)
    preserve_source_suffix: set[tuple[str, str]] = set()
    pairs = [(source, target) for source in sources for target in normalized_targets]
    while True:
        paths: dict[tuple[str, str], set[str]] = {}
        for source, target in pairs:
            relative_path = _artifact_relative_path(
                source,
                target,
                preserve_source_suffix=(source, target) in preserve_source_suffix,
            ).as_posix()
            paths.setdefault((target, relative_path), set()).add(source)
        colliding_pairs = {
            (source, target)
            for (target, _relative_path), colliding_sources in paths.items()
            if len(colliding_sources) > 1
            for source in colliding_sources
        }
        new_pairs = colliding_pairs - preserve_source_suffix
        if not new_pairs:
            return preserve_source_suffix
        preserve_source_suffix.update(new_pairs)


def _artifact_target_extension(target: str) -> str:
    normalized_target = _normalized_targets([target])[0]
    if normalized_target in CROSSL_TARGETS:
        return ".cgl"
    return get_backend_extension(normalized_target) or ".out"


def _artifact_path_extension(path: str | os.PathLike[str]) -> str:
    filename = PurePosixPath(str(path).replace("\\", "/")).name
    return "".join(PurePosixPath(filename).suffixes).lower()


def _artifact_path_matches_target_extension(
    path: str | os.PathLike[str], target: str
) -> bool:
    return (
        PurePosixPath(str(path).replace("\\", "/"))
        .name.lower()
        .endswith(_artifact_target_extension(target).lower())
    )


def _webgl_stage_path(path: Path, stage: str) -> Path:
    suffix = _artifact_target_extension("webgl")
    name = path.name
    if name.lower().endswith(suffix):
        base = name[: -len(suffix)]
        return path.with_name(f"{base}.{stage}{suffix}")
    return path.with_name(f"{path.stem}.{stage}{path.suffix}")


def _webgl_stage_relative_path(relative_path: Path, stage_label: str) -> Path:
    stage = WEBGL_PROJECT_GLSLANG_STAGE_BY_LABEL.get(stage_label)
    if stage is None:
        return relative_path
    return _webgl_stage_path(relative_path, stage)


def _glslang_generated_stage_sections(source: str) -> list[tuple[str, str]]:
    matches = list(GLSLANG_GENERATED_STAGE_COMMENT_RE.finditer(source))
    sections = []
    for index, match in enumerate(matches):
        stage_name = match.group(1).strip().lower().replace("-", "_").replace(" ", "_")
        stage = GLSLANG_STAGE_BY_GENERATED_COMMENT.get(stage_name)
        if stage is None:
            continue
        end = matches[index + 1].start() if index + 1 < len(matches) else len(source)
        sections.append((stage, source[match.start() : end]))
    return sections


def _variant_jobs(
    config: ProjectConfig,
) -> list[tuple[str | None, dict[str, str]]]:
    if not config.variants:
        return [(None, dict(config.defines))]
    return [
        (name, {**config.defines, **dict(defines)})
        for name, defines in sorted(config.variants.items())
    ]


def _variant_define_sources(
    config: ProjectConfig,
    variant: str | None,
) -> dict[str, str]:
    sources = {name: "config" for name in config.defines}
    if variant is not None:
        for name in config.variants.get(variant, {}):
            sources[name] = "project-variant"
    return sources


def _selected_variant_names(variants: Sequence[str] | str | None) -> list[str] | None:
    if variants is None:
        return None
    try:
        names = [variants] if isinstance(variants, str) else list(variants)
    except TypeError as exc:
        raise ValueError(
            "selected project variants must be a string or sequence of strings"
        ) from exc
    if not names:
        raise ValueError(
            "selected project variants must include at least one variant name"
        )

    selected: list[str] = []
    seen: set[str] = set()
    for name in names:
        if not isinstance(name, str) or not name.strip():
            raise ValueError("selected project variants must be non-empty strings")
        if name not in seen:
            selected.append(name)
            seen.add(name)
    return selected


def _config_with_selected_variants(
    config: ProjectConfig, variants: Sequence[str] | str | None
) -> ProjectConfig:
    selected = _selected_variant_names(variants)
    if selected is None and config.selected_variants:
        selected = _selected_variant_names(config.selected_variants)
    if selected is None:
        return config

    unknown = [name for name in selected if name not in config.variants]
    if unknown:
        available = ", ".join(sorted(config.variants)) or "(none)"
        raise ValueError(
            "selected project variant is not declared in project config: "
            f"{', '.join(unknown)} (available: {available})"
        )
    return replace(
        config,
        variants={name: config.variants[name] for name in selected},
        selected_variants=tuple(selected),
    )


def _artifact_matrix_report(
    config: ProjectConfig,
    units: Sequence[ProjectTranslationUnit],
    targets: Sequence[str],
    variants: Mapping[str, Mapping[str, str]],
    artifacts: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    variant_count = len(variants)
    variant_factor = variant_count if variant_count else 1
    normalized_targets = _normalized_targets(targets)
    payload = {
        "unitCount": len(units),
        "targetCount": len(normalized_targets),
        "variantCount": variant_count,
        "variantMode": "named" if variant_count else "none",
    }
    artifact_identities = {
        identity
        for artifact in artifacts
        if isinstance(artifact, Mapping)
        for identity in (_artifact_identity(artifact),)
        if identity is not None
    }
    preserve_source_suffix = _artifact_source_suffix_pairs(units, normalized_targets)
    variant_names: list[str | None] = sorted(variants) if variants else [None]
    expected_identities = _expected_artifact_identities(
        config.root,
        config.output_path,
        units,
        normalized_targets,
        variant_names,
        preserve_source_suffix,
        artifacts=artifacts,
    )
    payload["expectedArtifactCount"] = len(expected_identities)
    missing_identities = expected_identities - artifact_identities
    extra_identities = artifact_identities - expected_identities
    source_backend_by_identity = _artifact_matrix_source_backend_by_identity(
        expected_identities,
        artifacts,
        _artifact_matrix_unit_source_backends(units),
    )
    payload.update(
        {
            "emittedArtifactCount": len(artifacts),
            "translatedCount": sum(
                1 for artifact in artifacts if artifact.get("status") == "translated"
            ),
            "failedCount": sum(
                1 for artifact in artifacts if artifact.get("status") == "failed"
            ),
            "identityCoverageAvailable": True,
            "missingArtifactCount": len(missing_identities),
            "extraArtifactCount": len(extra_identities),
            "complete": not missing_identities and not extra_identities,
            "statusByTarget": _artifact_matrix_status_by_field(
                expected_identities,
                artifacts,
                missing_identities,
                extra_identities,
                "target",
            ),
            "statusBySourceBackend": _artifact_matrix_status_by_field(
                expected_identities,
                artifacts,
                missing_identities,
                extra_identities,
                "sourceBackend",
                source_backend_by_identity=source_backend_by_identity,
            ),
            "statusByVariant": _artifact_matrix_status_by_field(
                expected_identities,
                artifacts,
                missing_identities,
                extra_identities,
                "variant",
            ),
        }
    )
    return payload


def _artifact_matrix_status_row() -> dict[str, Any]:
    return {
        "expectedArtifactCount": 0,
        "emittedArtifactCount": 0,
        "translatedCount": 0,
        "failedCount": 0,
        "missingArtifactCount": 0,
        "extraArtifactCount": 0,
        "complete": True,
    }


def _artifact_matrix_identity_field(
    identity: ArtifactIdentity,
    field_name: str,
    source_backend_by_identity: Mapping[ArtifactIdentity, str] | None = None,
) -> str | None:
    if field_name == "target":
        return identity[1]
    if field_name == "sourceBackend" and source_backend_by_identity is not None:
        return source_backend_by_identity.get(identity)
    if field_name == "variant":
        return identity[3]
    return None


def _artifact_matrix_status_by_field(
    expected_identities: set[ArtifactIdentity],
    artifacts: Sequence[Mapping[str, Any]],
    missing_identities: set[ArtifactIdentity],
    extra_identities: set[ArtifactIdentity],
    field_name: str,
    *,
    source_backend_by_identity: Mapping[ArtifactIdentity, str] | None = None,
) -> dict[str, dict[str, Any]]:
    rows: dict[str, dict[str, Any]] = {}
    for identity in expected_identities:
        value = _artifact_matrix_identity_field(
            identity,
            field_name,
            source_backend_by_identity,
        )
        if value is None:
            continue
        rows.setdefault(value, _artifact_matrix_status_row())[
            "expectedArtifactCount"
        ] += 1
    for artifact in artifacts:
        identity = _artifact_identity(artifact)
        if identity is None:
            continue
        value = _artifact_matrix_identity_field(
            identity,
            field_name,
            source_backend_by_identity,
        )
        if value is None:
            continue
        row = rows.setdefault(value, _artifact_matrix_status_row())
        row["emittedArtifactCount"] += 1
        status = artifact.get("status")
        if status == "translated":
            row["translatedCount"] += 1
        elif status == "failed":
            row["failedCount"] += 1
    for identity in missing_identities:
        value = _artifact_matrix_identity_field(
            identity,
            field_name,
            source_backend_by_identity,
        )
        if value is not None:
            rows.setdefault(value, _artifact_matrix_status_row())[
                "missingArtifactCount"
            ] += 1
    for identity in extra_identities:
        value = _artifact_matrix_identity_field(
            identity,
            field_name,
            source_backend_by_identity,
        )
        if value is not None:
            rows.setdefault(value, _artifact_matrix_status_row())[
                "extraArtifactCount"
            ] += 1
    for row in rows.values():
        row["complete"] = (
            row["missingArtifactCount"] == 0 and row["extraArtifactCount"] == 0
        )
    return {name: rows[name] for name in sorted(rows)}


def _artifact_matrix_unit_source_backends(units: Sequence[Any]) -> dict[str, str]:
    source_backends: dict[str, str] = {}
    for unit in units:
        if isinstance(unit, ProjectTranslationUnit):
            source = unit.relative_path
            source_backend = unit.source_backend
        elif isinstance(unit, Mapping):
            source = unit.get("path")
            source_backend = unit.get("sourceBackend")
        else:
            continue
        if (
            _is_non_empty_string(source)
            and _is_report_identity_path(source)
            and _is_non_empty_string(source_backend)
        ):
            source_backends.setdefault(source, source_backend)
    return source_backends


def _artifact_matrix_source_backend_by_identity(
    expected_identities: set[ArtifactIdentity],
    artifacts: Sequence[Mapping[str, Any]],
    source_backend_by_source: Mapping[str, str],
) -> dict[ArtifactIdentity, str]:
    source_backend_by_identity = {
        identity: source_backend_by_source[identity[0]]
        for identity in expected_identities
        if identity[0] in source_backend_by_source
    }
    for artifact in artifacts:
        identity = _artifact_identity(artifact)
        if identity is None:
            continue
        source_backend = artifact.get("sourceBackend")
        if not _is_non_empty_string(source_backend):
            source_backend = source_backend_by_source.get(identity[0])
        if _is_non_empty_string(source_backend):
            source_backend_by_identity[identity] = source_backend
    return source_backend_by_identity


def _artifact_source_map(
    config: ProjectConfig,
    unit: ProjectTranslationUnit,
    target: str,
    output_path: Path,
) -> dict[str, Any]:
    artifact_path = _artifact_report_path(output_path, config)
    source_span = _file_span(unit.path, unit.relative_path)
    generated_span = _file_span(output_path, artifact_path)
    line_mappings = _line_preserving_source_map_mappings(
        unit.path,
        unit.relative_path,
        output_path,
        artifact_path,
    )
    if not line_mappings:
        line_mappings = _derived_line_source_map_mappings(
            unit.path,
            unit.relative_path,
            output_path,
            artifact_path,
        )
    mapping_granularity = "line" if line_mappings else "file"
    mappings = (
        line_mappings
        if line_mappings
        else [
            {
                "source": source_span.to_json(),
                "generated": generated_span.to_json(),
            }
        ]
    )
    return {
        "schemaVersion": 1,
        "kind": "crosstl-artifact-source-map",
        "mappingGranularity": mapping_granularity,
        "target": target,
        "source": source_span.to_json(),
        "generated": generated_span.to_json(),
        "mappings": mappings,
    }


def _is_crossgl_target(target: str) -> bool:
    return _normalized_targets([target])[0] in CROSSL_TARGETS


def _source_remap_report_path(artifact_path: str) -> str:
    path = PurePosixPath(artifact_path.replace("\\", "/"))
    return path.with_name(f"{path.stem}.source-remap.json").as_posix()


def _source_remap_path(output_path: Path) -> Path:
    return output_path.with_name(f"{output_path.stem}.source-remap.json")


def _source_remap_payload(source_map: Mapping[str, Any]) -> dict[str, Any]:
    source_mappings = source_map.get("mappings")
    if not isinstance(source_mappings, list) or not source_mappings:
        source_mappings = [
            {
                "source": source_map["source"],
                "generated": source_map["generated"],
            }
        ]
    return {
        "schemaVersion": SOURCE_REMAP_SCHEMA_VERSION,
        "generatedFile": source_map["generated"]["file"],
        "mappings": [
            {
                "generated": dict(mapping["generated"]),
                "original": dict(mapping["source"]),
            }
            for mapping in source_mappings
        ],
    }


def _write_source_remap_sidecar(path: Path, payload: Mapping[str, Any]) -> None:
    path.write_text(
        json.dumps(payload, indent=2, sort_keys=True) + "\n",
        encoding="utf-8",
    )


def _artifact_source_remap(
    config: ProjectConfig,
    target: str,
    artifact_path: str,
    remap_path: Path,
    mapping_granularity: str,
    mapping_count: int,
) -> dict[str, Any]:
    return {
        "schemaVersion": SOURCE_REMAP_SCHEMA_VERSION,
        "path": _artifact_report_path(remap_path, config),
        "target": target,
        "generatedFile": artifact_path,
        "mappingGranularity": mapping_granularity,
        "mappingCount": mapping_count,
        "sizeBytes": remap_path.stat().st_size,
        "hash": _source_hash(remap_path),
    }


def _attach_artifact_source_remap(
    config: ProjectConfig,
    target: str,
    artifact: dict[str, Any],
    output_path: Path,
) -> None:
    remap_path = _source_remap_path(output_path)
    remap_payload = _source_remap_payload(artifact["sourceMap"])
    _write_source_remap_sidecar(remap_path, remap_payload)
    artifact["sourceRemap"] = _artifact_source_remap(
        config,
        target,
        artifact["path"],
        remap_path,
        str(artifact["sourceMap"]["mappingGranularity"]),
        len(remap_payload["mappings"]),
    )


def _webgl_split_stage_artifacts(
    config: ProjectConfig,
    unit: ProjectTranslationUnit,
    artifact: Mapping[str, Any],
    output_path: Path,
) -> list[dict[str, Any]] | None:
    if artifact.get("target") != "webgl":
        return None

    try:
        source = output_path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return None

    stage_sources = []
    for stage in _glslang_guarded_stages(output_path):
        macro = GLSLANG_GUARD_MACRO_BY_STAGE.get(stage)
        if macro is None:
            continue
        stage_source = _filter_glslang_guarded_stage_source(source, macro)
        if stage_source.strip():
            stage_sources.append((stage, stage_source))

    if len(stage_sources) <= 1:
        stage_sources = [
            (stage, stage_source)
            for stage, stage_source in _glslang_generated_stage_sections(source)
            if stage_source.strip()
        ]
    if len(stage_sources) <= 1:
        return None

    stage_artifacts = []
    for stage, stage_source in stage_sources:
        stage_label = WEBGL_PROJECT_STAGE_LABEL_BY_GLSLANG.get(stage)
        if stage_label is None:
            continue

        stage_path = _webgl_stage_path(output_path, stage)
        with stage_path.open("w", encoding="utf-8", newline="") as file:
            file.write(stage_source)
        stage_artifact = dict(artifact)
        stage_artifact["stage"] = stage_label
        stage_artifact["path"] = _artifact_report_path(stage_path, config)
        stage_artifact["generatedHash"] = _source_hash(stage_path)
        stage_artifact["generatedSizeBytes"] = stage_path.stat().st_size
        stage_artifact["sourceMap"] = _artifact_source_map(
            config, unit, str(artifact["target"]), stage_path
        )
        _attach_artifact_source_remap(
            config,
            str(artifact["target"]),
            stage_artifact,
            stage_path,
        )
        stage_artifacts.append(stage_artifact)

    if len(stage_artifacts) <= 1:
        return None

    try:
        output_path.unlink()
    except OSError:
        pass
    return stage_artifacts


def _unsupported_mapping_field_reasons(
    prefix: str, value: Mapping[str, Any], allowed_fields: frozenset[str]
) -> list[str]:
    reasons = []
    for field_name in sorted(value, key=str):
        if field_name not in allowed_fields:
            reasons.append(f"{prefix}.{field_name} is not allowed")
    return reasons


def _compiler_source_remap_span_reasons(prefix: str, value: Any) -> list[str]:
    reasons = _source_map_span_reasons(prefix, value)
    if reasons:
        return reasons

    if not isinstance(value, Mapping):
        return reasons
    reasons.extend(
        _unsupported_mapping_field_reasons(
            prefix, value, COMPILER_SOURCE_REMAP_SPAN_FIELDS
        )
    )

    file_path = value["file"]
    if not _is_stable_relative_posix_path(file_path):
        reasons.append(f"{prefix}.file must be a stable relative POSIX source path")
    for field_name in ("line", "column", "length", "endLine", "endColumn"):
        if value[field_name] <= 0:
            reasons.append(f"{prefix}.{field_name} must be greater than zero")
    if (
        value["length"] > 0
        and value["endLine"] == value["line"]
        and value["endColumn"] <= value["column"]
    ):
        reasons.append(f"{prefix}.endColumn must be greater than column")
    return reasons


def _compiler_source_remap_payload_reasons(payload: Any) -> list[str]:
    if not isinstance(payload, Mapping):
        return ["$ must be an object"]

    reasons = _unsupported_mapping_field_reasons(
        "$", payload, COMPILER_SOURCE_REMAP_PAYLOAD_FIELDS
    )
    if payload.get("schemaVersion") != SOURCE_REMAP_SCHEMA_VERSION:
        reasons.append("$.schemaVersion must be 1")

    generated_file = payload.get("generatedFile")
    if not _is_non_empty_string(generated_file):
        reasons.append("$.generatedFile must be a string")
    elif not _is_stable_relative_posix_path(generated_file):
        reasons.append("$.generatedFile must be a stable relative POSIX source path")

    mappings = payload.get("mappings")
    if not isinstance(mappings, list):
        reasons.append("$.mappings must be a list")
        return reasons
    if not mappings:
        reasons.append("$.mappings must not be empty")

    for mapping_index, mapping in enumerate(mappings):
        mapping_prefix = f"$.mappings[{mapping_index}]"
        if not isinstance(mapping, Mapping):
            reasons.append(f"{mapping_prefix} must be an object")
            continue
        reasons.extend(
            _unsupported_mapping_field_reasons(
                mapping_prefix, mapping, COMPILER_SOURCE_REMAP_MAPPING_FIELDS
            )
        )
        generated = mapping.get("generated")
        original = mapping.get("original")
        reasons.extend(
            _compiler_source_remap_span_reasons(
                f"{mapping_prefix}.generated", generated
            )
        )
        reasons.extend(
            _compiler_source_remap_span_reasons(f"{mapping_prefix}.original", original)
        )
        if (
            isinstance(generated, Mapping)
            and _is_non_empty_string(generated.get("file"))
            and _is_non_empty_string(generated_file)
            and generated["file"] != generated_file
        ):
            reasons.append(
                f"{mapping_prefix}.generated.file must match $.generatedFile"
            )
    return reasons


def _is_runtime_reference_candidate(path: Path) -> bool:
    suffix = path.suffix.lower()
    return (
        path.name in RUNTIME_REFERENCE_FILENAMES
        or suffix in RUNTIME_REFERENCE_EXTENSIONS
        or suffix in RUNTIME_REFERENCE_BUILD_EXTENSIONS
    )


def _is_runtime_build_reference_candidate(path: Path) -> bool:
    return (
        path.name in RUNTIME_REFERENCE_FILENAMES
        or path.suffix.lower() in RUNTIME_REFERENCE_BUILD_EXTENSIONS
    )


def _iter_runtime_reference_candidates(config: ProjectConfig) -> list[Path]:
    exclude_patterns = _repository_relative_globs(config.exclude_patterns)
    internal_exclude_patterns = _internal_exclude_patterns(config)
    candidates: list[Path] = []
    for path in config.root.rglob("*"):
        if not path.is_file() or not _is_runtime_reference_candidate(path):
            continue
        try:
            relative_path = _relpath(path, config.root)
        except ValueError:
            continue
        if _path_matches(relative_path, exclude_patterns):
            continue
        if _path_matches(relative_path, internal_exclude_patterns):
            continue
        candidates.append(path)
    return sorted(candidates, key=lambda candidate: _relpath(candidate, config.root))


def _runtime_reference_for_match(
    *,
    config: ProjectConfig,
    path: Path,
    line_number: int,
    match: re.Match[str],
    backend: str,
    kind: str,
    fallback_symbol: str | None,
) -> dict[str, Any]:
    symbol = fallback_symbol or match.group(1)
    return {
        "path": _relpath(path, config.root),
        "line": line_number,
        "column": match.start() + 1,
        "backend": backend,
        "kind": kind,
        "symbol": symbol,
    }


def _runtime_references(config: ProjectConfig) -> list[dict[str, Any]]:
    references: list[dict[str, Any]] = []
    for path in _iter_runtime_reference_candidates(config):
        try:
            if path.stat().st_size > RUNTIME_REFERENCE_FILE_SIZE_LIMIT:
                continue
            lines = path.read_text(encoding="utf-8").splitlines()
        except (OSError, UnicodeDecodeError):
            continue
        for line_number, line in enumerate(lines, start=1):
            for backend, kind, pattern, fallback_symbol in RUNTIME_REFERENCE_RULES:
                if (
                    kind == "build-system"
                    and not _is_runtime_build_reference_candidate(path)
                ):
                    continue
                for match in pattern.finditer(line):
                    references.append(
                        _runtime_reference_for_match(
                            config=config,
                            path=path,
                            line_number=line_number,
                            match=match,
                            backend=backend,
                            kind=kind,
                            fallback_symbol=fallback_symbol,
                        )
                    )
                    if len(references) >= RUNTIME_REFERENCE_LIMIT:
                        return references
    return references


def _runtime_migration_targets(
    units: Sequence[ProjectTranslationUnit],
    targets: Sequence[str],
    artifacts: Sequence[Mapping[str, Any]] | None = None,
) -> list[str]:
    if not units or not targets:
        return []
    supported_targets = set(_supported_target_names())
    selected_targets = [
        target for target in _normalized_targets(targets) if target in supported_targets
    ]
    if artifacts is None:
        return selected_targets

    translated_targets = {
        artifact.get("target")
        for artifact in artifacts
        if isinstance(artifact, Mapping) and artifact.get("status") == "translated"
    }
    return [target for target in selected_targets if target in translated_targets]


def _runtime_migration_actions(
    config: ProjectConfig,
    units: Sequence[ProjectTranslationUnit],
    targets: Sequence[str],
    artifacts: Sequence[Mapping[str, Any]] | None = None,
) -> list[dict[str, Any]]:
    action_targets = _runtime_migration_targets(units, targets, artifacts)
    if not action_targets:
        return []
    runtime_references = _runtime_references(config)
    return [
        {
            "kind": "manual-runtime-integration",
            "severity": "note",
            "message": (
                "CrossTL translated shader/kernel source artifacts only; review "
                "host runtime API calls, resource binding setup, build scripts, "
                "and backend framework integration separately."
            ),
            "targets": action_targets,
            "runtimeReferences": runtime_references,
        }
    ]


def _has_system_include_dependencies(units: Sequence[ProjectTranslationUnit]) -> bool:
    for unit in units:
        for dependency in unit.include_dependencies:
            if (
                isinstance(dependency, Mapping)
                and dependency.get("status") == "system"
                and dependency.get("kind") == "system"
            ):
                return True
    return False


def _include_migration_actions(
    units: Sequence[ProjectTranslationUnit],
    targets: Sequence[str],
    artifacts: Sequence[Mapping[str, Any]] | None = None,
) -> list[dict[str, Any]]:
    if not _has_system_include_dependencies(units):
        return []

    action_targets = _runtime_migration_targets(units, targets, artifacts)
    if not action_targets:
        return []

    return [
        {
            "kind": "manual-include-resolution",
            "severity": "note",
            "message": (
                "Review unresolved system include dependencies against target "
                "SDK or toolchain headers; CrossTL records them for portability "
                "but does not rewrite SDK or framework headers automatically."
            ),
            "targets": action_targets,
        }
    ]


def _project_migration_actions(
    config: ProjectConfig,
    units: Sequence[ProjectTranslationUnit],
    targets: Sequence[str],
    artifacts: Sequence[Mapping[str, Any]] | None = None,
) -> list[dict[str, Any]]:
    return [
        *_runtime_migration_actions(config, units, targets, artifacts),
        *_include_migration_actions(units, targets, artifacts),
    ]


def _has_error_diagnostic(diagnostics: Sequence[ProjectDiagnostic], code: str) -> bool:
    return any(
        diagnostic.severity == "error" and diagnostic.code == code
        for diagnostic in diagnostics
    )


def _is_template_hostile_target(target: str) -> bool:
    return not _is_crossgl_target(target)


def _metal_preprocess_without_template_materialization(
    preprocessor: Any, code: str, *, file_path: str
) -> str:
    from crosstl.backend.Metal.preprocessor import PRESERVED_INCLUDE_SENTINEL

    source = preprocessor._strip_leading_compiler_diagnostics(code)
    processed = super(type(preprocessor), preprocessor).preprocess(
        source,
        file_path=file_path,
    )
    return processed.replace(PRESERVED_INCLUDE_SENTINEL, "#include ")


def _metal_template_parameter_names(source: str) -> set[str]:
    from crosstl.backend.Metal.preprocessor import MetalPreprocessor

    preprocessor = MetalPreprocessor()
    names: set[str] = set()
    for template in preprocessor._find_template_functions(source):
        names.update(str(name) for name in template.template_parameters if name)
    return names


def _materialized_template_specialization_record(
    *,
    name: str,
    materialized_name: str,
    parameters: Mapping[str, str],
    parameter_sources: Mapping[str, str] | None = None,
    source: str,
    host_name: str | None = None,
) -> dict[str, Any]:
    sources = {
        parameter: str(
            parameter_sources.get(parameter, source)
            if parameter_sources is not None
            else source
        )
        for parameter in parameters
    }
    payload = {
        "name": name,
        "materializedName": materialized_name,
        "parameters": dict(sorted(parameters.items())),
        "parameterSources": dict(sorted(sources.items())),
        "source": source,
    }
    if _is_non_empty_string(host_name):
        payload["hostName"] = host_name
    return payload


def _unsupported_template_record(
    *,
    name: str,
    parameters: Sequence[str],
    configured_parameters: Mapping[str, str],
    source_declaration: Mapping[str, Any],
    target: str,
    required_signature: str,
) -> dict[str, Any]:
    missing = [
        parameter for parameter in parameters if parameter not in configured_parameters
    ]
    return {
        "name": name,
        "parameters": list(parameters),
        "missingParameters": missing,
        "reason": "missing-template-arguments",
        "sourceDeclaration": dict(source_declaration),
        "target": target,
        "requiredSignature": required_signature,
    }


def _template_source_declaration_record(
    unit: ProjectTranslationUnit,
    source: str,
    template: Any,
) -> dict[str, Any]:
    location = _source_location_at_offset(
        unit,
        source,
        int(template.span[0]),
        max(int(template.span[1]) - int(template.span[0]), 0),
    )
    return {
        "file": location.file,
        "line": location.line,
        "column": location.column,
        "name": str(template.name),
    }


def _template_parameter_values_from_arguments(
    preprocessor: Any,
    template: Any,
    arguments: Sequence[str],
) -> dict[str, str]:
    substitutions, variadic_bindings = preprocessor._template_argument_bindings(
        template,
        list(arguments),
    )
    parameters = {name: str(value) for name, value in substitutions.items()}
    for name, values in variadic_bindings.items():
        parameters[name] = ", ".join(str(value) for value in values)
    return parameters


def _template_parameter_sources_from_arguments(
    template: Any,
    arguments: Sequence[str],
    *,
    argument_source: str,
    default_source: str,
) -> dict[str, str]:
    sources: dict[str, str] = {}
    template_parameters = list(getattr(template, "template_parameters", []) or [])
    variadic = getattr(template, "variadic_template_parameters", set())
    argument_index = 0
    for parameter_index, parameter in enumerate(template_parameters):
        if parameter in variadic:
            remaining_fixed = len(template_parameters) - parameter_index - 1
            variadic_count = max(
                0,
                len(arguments) - argument_index - remaining_fixed,
            )
            sources[parameter] = (
                argument_source if variadic_count > 0 else default_source
            )
            argument_index += variadic_count
            continue
        if argument_index < len(arguments):
            sources[parameter] = argument_source
            argument_index += 1
            continue
        sources[parameter] = default_source
    return sources


def _template_argument_values_from_parameters(
    preprocessor: Any,
    template: Any,
    parameters: Mapping[str, str],
) -> list[str]:
    arguments: list[str] = []
    variadic = getattr(template, "variadic_template_parameters", set())
    for parameter in template.template_parameters:
        value = parameters[parameter]
        if parameter in variadic:
            arguments.extend(preprocessor._split_top_level_commas(value))
        else:
            arguments.append(value)
    return arguments


def _template_required_signature(
    preprocessor: Any,
    template: Any,
    parameters: Mapping[str, str],
) -> str:
    arguments: list[str] = []
    variadic = getattr(template, "variadic_template_parameters", set())
    for parameter in template.template_parameters:
        value = parameters.get(parameter, parameter)
        if parameter in variadic and parameter in parameters:
            arguments.extend(preprocessor._split_top_level_commas(value))
        else:
            arguments.append(value)
    return preprocessor._template_specialization_signature(template.name, arguments)


def _template_variant_parameter_bindings(
    *,
    source_options: Mapping[str, Any],
    target: str,
    relative_path: str,
    template_name: str,
    required_signature: str,
) -> dict[str, str]:
    manifests = source_options.get(TEMPLATE_VARIANTS_SOURCE_OPTION)
    if not isinstance(manifests, Mapping):
        return {}
    target_keys = ("*", target)
    declaration_keys = ("*", template_name, required_signature)
    normalized_path = _normalize_project_relative_path(relative_path)
    bindings: dict[str, str] = {}
    for target_key in target_keys:
        source_patterns = manifests.get(target_key)
        if not isinstance(source_patterns, Mapping):
            continue
        for pattern, declarations in source_patterns.items():
            if not isinstance(pattern, str) or not isinstance(declarations, Mapping):
                continue
            normalized_pattern = _normalize_project_relative_path(pattern)
            if not fnmatch.fnmatch(normalized_path, normalized_pattern):
                continue
            for declaration_key in declaration_keys:
                declaration_bindings = declarations.get(declaration_key)
                if _valid_string_mapping(declaration_bindings):
                    bindings.update(
                        {
                            str(name): str(value)
                            for name, value in declaration_bindings.items()
                        }
                    )
    return bindings


def _is_metal_variadic_template(template: Any) -> bool:
    return bool(getattr(template, "variadic_template_parameters", ()))


def _metal_template_header(template: Any) -> str:
    body_start = template.source.find("{")
    return template.source if body_start == -1 else template.source[:body_start]


def _metal_template_returns_void(template: Any) -> bool:
    header = _metal_template_header(template)
    paren_index = header.find("(")
    if paren_index == -1:
        return False
    before_params = header[:paren_index].rstrip()
    return (
        re.search(
            rf"\bvoid\s+(?:[A-Za-z_][A-Za-z0-9_:]*\s+)*"
            rf"{re.escape(template.name)}\s*$",
            before_params,
        )
        is not None
    )


def _is_metal_diagnostic_template_helper(template: Any) -> bool:
    return (
        _is_metal_variadic_template(template)
        and _metal_template_returns_void(template)
        and METAL_DIAGNOSTIC_TEMPLATE_HELPER_RE.search(template.name.lower())
        is not None
    )


def _is_metal_entry_template(template: Any) -> bool:
    from crosstl.backend.Metal.preprocessor import METAL_ENTRY_FUNCTION_RE

    return METAL_ENTRY_FUNCTION_RE.search(_metal_template_header(template)) is not None


def _is_metal_template_utility_unit(config: ProjectConfig, path: Path) -> bool:
    try:
        source = path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return False
    if "template" not in source:
        return False

    from crosstl.backend.Metal.preprocessor import MetalPreprocessor

    source_options = _source_options_for_unit(
        config,
        "metal",
        _relpath(path, config.root),
    )
    preprocessor_kwargs: dict[str, Any] = {
        "include_paths": _frontend_include_dirs(config),
    }
    if "strict_preprocessor" in source_options:
        preprocessor_kwargs["strict"] = bool(source_options["strict_preprocessor"])
    preprocessor = MetalPreprocessor(**preprocessor_kwargs, defines={})
    try:
        preprocessed = _metal_preprocess_without_template_materialization(
            preprocessor,
            source,
            file_path=str(path),
        )
    except Exception:  # noqa: BLE001
        return False

    template_spans = preprocessor._find_template_declaration_spans(preprocessed)
    if not template_spans:
        return False
    if preprocessor._find_project_template_instantiations(preprocessed):
        return False
    if any(
        _is_metal_entry_template(template)
        for template in preprocessor._find_template_functions(preprocessed)
    ):
        return False
    return not any(
        function.is_entry
        for function in preprocessor._find_non_template_function_definitions(
            preprocessed,
            template_spans,
        )
    )


def _metal_template_parameter_defaults(
    preprocessor: Any,
    source: str,
    template: Any,
    seed_parameters: Mapping[str, str] | None = None,
) -> dict[str, str]:
    template_defaults = dict(getattr(template, "template_parameter_defaults", {}) or {})
    if not template_defaults:
        declaration = source[template.span[0] : template.span[1]]
        angle_start = declaration.find("<")
        angle_end = preprocessor._find_matching_angle(declaration, angle_start)
        if angle_start == -1 or angle_end is None:
            return {}

        parameters = preprocessor._split_top_level_commas(
            declaration[angle_start + 1 : angle_end]
        )
        for parameter in parameters:
            if "=" not in parameter:
                continue
            names = preprocessor._template_parameter_names(parameter)
            if not names:
                continue
            template_defaults[names[-1]] = parameter.split("=", 1)[1].strip()

    available_parameters = dict(seed_parameters or {})
    defaults: dict[str, str] = {}
    for parameter in getattr(template, "template_parameters", []) or []:
        if parameter in available_parameters:
            continue
        default_argument = template_defaults.get(parameter)
        if default_argument is None:
            continue
        resolved = preprocessor._resolve_template_default_argument(
            default_argument,
            available_parameters,
            template,
        )
        defaults[parameter] = resolved
        available_parameters[parameter] = resolved
    return defaults


def _plain_template_function_call_names(
    preprocessor: Any,
    template: Any,
    template_names: set[str],
) -> set[str]:
    body_start = template.source.find("{")
    if body_start == -1:
        return set()
    body_end = template.source.rfind("}")
    body = template.source[body_start + 1 : body_end if body_end != -1 else None]
    return {
        name
        for name in preprocessor._find_function_references(body, template_names)
        if name != template.name
    }


def _inherited_template_arguments(
    preprocessor: Any,
    template: Any,
    inherited_parameters: Mapping[str, str],
    inherited_parameter_sources: Mapping[str, str],
) -> tuple[list[str], dict[str, str], dict[str, str]] | None:
    defaults = _metal_template_parameter_defaults(
        preprocessor,
        "",
        template,
        inherited_parameters,
    )
    arguments: list[str] = []
    parameters: dict[str, str] = {}
    parameter_sources: dict[str, str] = {}
    available_parameters = dict(inherited_parameters)
    available_sources = dict(inherited_parameter_sources)
    variadic = getattr(template, "variadic_template_parameters", set())

    for parameter in getattr(template, "template_parameters", []) or []:
        if parameter in available_parameters:
            value = available_parameters[parameter]
            parameters[parameter] = value
            parameter_sources[parameter] = available_sources.get(
                parameter,
                "source-instantiation",
            )
            if parameter in variadic:
                arguments.extend(preprocessor._split_top_level_commas(value))
            else:
                arguments.append(value)
            continue

        default_argument = defaults.get(parameter)
        if default_argument is None:
            return None
        parameters[parameter] = default_argument
        parameter_sources[parameter] = "source-default"
        available_parameters[parameter] = default_argument
        available_sources[parameter] = "source-default"
        if parameter in variadic:
            arguments.extend(preprocessor._split_top_level_commas(default_argument))
        else:
            arguments.append(default_argument)

    return arguments, parameters, parameter_sources


@dataclass
class _SourceInstantiationTemplateContext:
    template: Any
    materialized_name: str
    parameters: Mapping[str, str]
    parameter_sources: Mapping[str, str]


@dataclass
class _InheritedTemplateMaterialization:
    text: str
    specializations: list[dict[str, Any]]
    template_names: set[str]


@dataclass(frozen=True)
class _MetalTemplateTypeDeclaration:
    name: str
    parameters: tuple[str, ...]
    span: tuple[int, int]
    location: SourceLocation
    is_functor: bool = False


def _materialize_inherited_source_template_helpers(
    *,
    preprocessor: Any,
    materialized: str,
    templates_by_name: Mapping[str, Any],
    source_contexts: Sequence[_SourceInstantiationTemplateContext],
    existing_materialized_names: Mapping[tuple[str, tuple[str, ...]], str],
) -> _InheritedTemplateMaterialization:
    template_names = set(templates_by_name)
    generated: dict[tuple[str, tuple[str, ...]], dict[str, Any]] = {}
    generated_order: list[tuple[str, tuple[str, ...]]] = []
    inherited_template_names: set[str] = set()
    specialization_records: list[dict[str, Any]] = []
    seen_records: set[tuple[str, str, tuple[tuple[str, str], ...]]] = set()
    active: set[tuple[str, tuple[str, ...]]] = set()

    def ensure_helper(
        name: str,
        inherited_parameters: Mapping[str, str],
        inherited_parameter_sources: Mapping[str, str],
    ) -> str | None:
        template = templates_by_name.get(name)
        if template is None or _is_metal_entry_template(template):
            return None
        inherited = _inherited_template_arguments(
            preprocessor,
            template,
            inherited_parameters,
            inherited_parameter_sources,
        )
        if inherited is None:
            return None
        arguments, parameters, parameter_sources = inherited
        key = preprocessor._template_specialization_key(name, arguments)

        existing_name = existing_materialized_names.get(key)
        if existing_name is not None:
            return existing_name

        cached = generated.get(key)
        if cached is not None:
            return str(cached["materialized_name"])

        materialized_name = preprocessor._template_specialization_identifier(
            name,
            list(key[1]),
        )
        generated[key] = {
            "template": template,
            "arguments": list(key[1]),
            "materialized_name": materialized_name,
            "parameters": parameters,
            "parameter_sources": parameter_sources,
            "source": "",
        }
        if key in active:
            return materialized_name

        active.add(key)
        child_replacements: dict[str, str] = {}
        for child_name in sorted(
            _plain_template_function_call_names(
                preprocessor,
                template,
                template_names,
            )
        ):
            child_materialized_name = ensure_helper(
                child_name,
                parameters,
                parameter_sources,
            )
            if child_materialized_name is not None:
                child_replacements[child_name] = child_materialized_name

        source = preprocessor._materialize_template_function_with_name(
            template,
            list(key[1]),
            materialized_name,
            host_name=None,
        )
        if child_replacements:
            replacements = _plain_template_call_replacements(
                preprocessor,
                source,
                child_replacements,
                [],
                None,
            )
            source = preprocessor._apply_text_replacements(source, replacements)

        generated[key]["source"] = source
        generated_order.append(key)
        inherited_template_names.add(name)
        active.remove(key)

        record_key = (
            name,
            materialized_name,
            tuple(sorted(parameters.items())),
        )
        if record_key not in seen_records:
            seen_records.add(record_key)
            specialization_records.append(
                _materialized_template_specialization_record(
                    name=name,
                    materialized_name=materialized_name,
                    parameters=parameters,
                    parameter_sources=parameter_sources,
                    source=_template_specialization_source(
                        parameter_sources,
                        fallback="source-instantiation",
                    ),
                )
            )
        return materialized_name

    function_spans_by_name: dict[str, list[tuple[int, int]]] = {}
    template_spans = preprocessor._find_template_declaration_spans(materialized)
    for function in preprocessor._find_non_template_function_definitions(
        materialized,
        template_spans,
    ):
        function_spans_by_name.setdefault(function.name, []).append(function.span)

    call_replacements: list[tuple[int, int, str]] = []
    for context in source_contexts:
        replacements_by_name: dict[str, str] = {}
        for helper_name in sorted(
            _plain_template_function_call_names(
                preprocessor,
                context.template,
                template_names,
            )
        ):
            materialized_name = ensure_helper(
                helper_name,
                context.parameters,
                context.parameter_sources,
            )
            if materialized_name is not None:
                replacements_by_name[helper_name] = materialized_name
        if not replacements_by_name:
            continue
        for function_span in function_spans_by_name.get(context.materialized_name, []):
            call_replacements.extend(
                _plain_template_call_replacements(
                    preprocessor,
                    materialized,
                    replacements_by_name,
                    template_spans,
                    [function_span],
                )
            )

    if call_replacements:
        materialized = preprocessor._apply_text_replacements(
            materialized,
            call_replacements,
        )
    else:
        return _InheritedTemplateMaterialization(
            text=materialized,
            specializations=[],
            template_names=set(),
        )

    generated_sources = [
        str(generated[key]["source"]).rstrip()
        for key in generated_order
        if str(generated[key].get("source", "")).strip()
    ]
    if generated_sources:
        materialized = materialized.rstrip() + "\n\n" + "\n\n".join(generated_sources)
        if not materialized.endswith("\n"):
            materialized += "\n"

    return _InheritedTemplateMaterialization(
        text=materialized,
        specializations=specialization_records,
        template_names=inherited_template_names,
    )


def _metal_function_parameter_types(preprocessor: Any, header: str) -> dict[str, str]:
    paren_start = header.find("(")
    if paren_start == -1:
        return {}
    paren_end = preprocessor._find_matching_delimiter(header, paren_start, "(", ")")
    if paren_end is None:
        return {}

    parameters: dict[str, str] = {}
    for parameter in preprocessor._split_top_level_commas(
        header[paren_start + 1 : paren_end]
    ):
        parameter = re.sub(r"\[\[.*?\]\]", "", parameter, flags=re.DOTALL).strip()
        if not parameter or parameter == "void":
            continue
        match = re.search(r"([A-Za-z_][A-Za-z0-9_]*)\s*(?:\[[^\]]*\])?\s*$", parameter)
        if match is None:
            continue
        name = match.group(1)
        type_text = parameter[: match.start(1)].strip()
        type_text = re.sub(
            r"\b(?:const|device|thread|threadgroup|constant|volatile|restrict)\b",
            "",
            type_text,
        )
        type_text = re.sub(r"\s+", " ", type_text).strip()
        if type_text:
            parameters[name] = type_text
    return parameters


def _metal_collect_local_value_types(
    preprocessor: Any,
    source: str,
    body_start: int,
    body_end: int,
    seed_types: Mapping[str, str],
) -> dict[str, str]:
    types = dict(seed_types)
    body = source[body_start:body_end]
    type_name = r"[A-Za-z_][A-Za-z0-9_:]*(?:\s*<[^;=(){}]+>)?"
    declaration_re = re.compile(
        rf"(?:^|[;{{}}\n])\s*"
        rf"(?:const\s+|constexpr\s+|static\s+|thread\s+|threadgroup\s+|"
        rf"device\s+|constant\s+|volatile\s+|restrict\s+)*"
        rf"(?P<type>{type_name})\s*(?P<pointer>[*&]?)\s+"
        rf"(?P<name>[A-Za-z_][A-Za-z0-9_]*)\s*(?P<array>\[[^\]]*\])?"
        rf"\s*(?:[=;,\[])",
        re.DOTALL,
    )
    for match in declaration_re.finditer(body):
        value_type = re.sub(r"\s+", " ", match.group("type")).strip()
        if not value_type:
            continue
        if match.group("pointer"):
            value_type = f"{value_type}{match.group('pointer')}"
        types[match.group("name")] = value_type
    return types


def _metal_base_value_type(type_text: str) -> str:
    value = str(type_text or "").strip()
    value = re.sub(r"\b(?:const|device|thread|threadgroup|constant)\b", "", value)
    value = re.sub(r"\s+", " ", value).strip()
    while value.endswith(("*", "&")):
        value = value[:-1].strip()
    return value


def _metal_expression_value_type(
    preprocessor: Any,
    expression: str,
    value_types: Mapping[str, str],
) -> str | None:
    text = str(expression or "").strip()
    while text.startswith("(") and text.endswith(")"):
        end = preprocessor._find_matching_delimiter(text, 0, "(", ")")
        if end != len(text) - 1:
            break
        text = text[1:-1].strip()
    cast_match = re.match(r"(?P<type>[A-Za-z_][A-Za-z0-9_:]*)\s*\(", text)
    if cast_match and cast_match.group("type") not in {"if", "for", "while", "return"}:
        return cast_match.group("type")
    ident_match = re.match(r"(?P<name>[A-Za-z_][A-Za-z0-9_]*)\s*(?:\[|$)", text)
    if ident_match:
        value_type = value_types.get(ident_match.group("name"))
        if value_type:
            return _metal_base_value_type(value_type)
    for operator_text in ("+", "-", "*", "/"):
        depth = {"<": 0, "(": 0, "[": 0, "{": 0}
        for index, character in enumerate(text):
            if character in depth:
                depth[character] += 1
            elif character == ">" and depth["<"] > 0:
                depth["<"] -= 1
            elif character == ")" and depth["("] > 0:
                depth["("] -= 1
            elif character == "]" and depth["["] > 0:
                depth["["] -= 1
            elif character == "}" and depth["{"] > 0:
                depth["{"] -= 1
            elif character == operator_text and not any(depth.values()):
                for part in (text[:index], text[index + 1 :]):
                    value_type = _metal_expression_value_type(
                        preprocessor,
                        part,
                        value_types,
                    )
                    if value_type is not None:
                        return value_type
    if re.fullmatch(r"\d+u?", text):
        return "uint" if text.endswith("u") else "int"
    if re.fullmatch(r"\d+\.\d*f?", text):
        return "float"
    return None


def _metal_template_function_parameter_types(
    preprocessor: Any,
    template: Any,
) -> list[str]:
    header = _metal_template_header(template)
    paren_start = header.find("(")
    if paren_start == -1:
        return []
    paren_end = preprocessor._find_matching_delimiter(header, paren_start, "(", ")")
    if paren_end is None:
        return []
    parameter_types: list[str] = []
    for parameter in preprocessor._split_top_level_commas(
        header[paren_start + 1 : paren_end]
    ):
        parameter = re.sub(r"\[\[.*?\]\]", "", parameter, flags=re.DOTALL).strip()
        match = re.search(r"[A-Za-z_][A-Za-z0-9_]*\s*(?:\[[^\]]*\])?\s*$", parameter)
        if match is None:
            parameter_types.append("")
            continue
        parameter_types.append(parameter[: match.start()].strip())
    return parameter_types


def _metal_find_implicit_template_function_calls(
    preprocessor: Any,
    source: str,
    templates_by_name: Mapping[str, Any],
    excluded_spans: Sequence[tuple[int, int]],
    included_spans: Sequence[tuple[int, int]] | None,
    return_types: Mapping[str, str] | None = None,
    *,
    type_cache: _MetalMaterializationTypeEnvironmentCache | None = None,
    work_budget: _MetalTemplateMaterializationWorkBudget | None = None,
) -> list[tuple[str, list[str], tuple[int, int]]]:
    calls: list[tuple[str, list[str], tuple[int, int]]] = []
    functions = preprocessor._find_non_template_function_definitions(
        source,
        list(excluded_spans),
    )
    included = list(included_spans) if included_spans is not None else None
    known_return_types = dict(return_types or {})
    for function in functions:
        if (
            included is not None
            and preprocessor._containing_span(function.span[0], included) is None
        ):
            continue
        type_environment = _metal_function_type_environment(
            preprocessor,
            source,
            function,
            known_return_types,
            cache=type_cache,
            work_budget=work_budget,
        )
        body = source[function.body_span[0] : function.body_span[1]]
        body_offset = function.body_span[0]
        i = 0
        while i < len(body):
            if body[i] in "\"'":
                _literal, consumed = preprocessor._read_string(body, i)
                i += consumed
                continue
            if body.startswith("//", i):
                end = body.find("\n", i)
                if end == -1:
                    break
                i = end + 1
                continue
            if body.startswith("/*", i):
                end = body.find("*/", i + 2)
                if end == -1:
                    break
                i = end + 2
                continue
            if not (body[i].isalpha() or body[i] == "_"):
                i += 1
                continue
            ident, consumed = preprocessor._read_identifier(body, i)
            template = templates_by_name.get(ident)
            j = i + consumed
            while j < len(body) and body[j].isspace():
                j += 1
            if template is None or j >= len(body) or body[j] != "(":
                i += consumed
                continue
            paren_end = preprocessor._find_matching_delimiter(body, j, "(", ")")
            if paren_end is None:
                i += consumed
                continue
            arguments = preprocessor._split_top_level_commas(body[j + 1 : paren_end])
            inferred_arguments = _infer_plain_template_helper_arguments(
                preprocessor,
                template,
                arguments,
                type_environment,
                known_return_types,
            )
            if inferred_arguments:
                calls.append(
                    (
                        ident,
                        inferred_arguments,
                        (body_offset + i, body_offset + i + consumed),
                    )
                )
            i = paren_end + 1
    return calls


@dataclass
class _ImplicitTemplateMaterialization:
    text: str
    specializations: list[dict[str, Any]]


@dataclass
class _MetalMaterializationTypeEnvironmentCache:
    environments: dict[tuple[int, int, tuple[tuple[str, str], ...]], dict[str, str]] = (
        field(default_factory=dict)
    )
    resolved_types: dict[
        tuple[str, tuple[tuple[str, str], ...], tuple[tuple[str, str], ...]], str
    ] = field(default_factory=dict)


@dataclass
class _MetalTemplateMaterializationWorkBudget:
    limit: int
    limit_source: str
    unit: ProjectTranslationUnit | None
    source: str
    target: str
    pass_name: str = "implicit-template-materialization/type-environment"
    used: int = 0

    def consume(
        self,
        amount: int,
        *,
        offset: int = 0,
        length: int = 0,
        context: str = "type environment resolution",
    ) -> None:
        if amount <= 0:
            return
        self.used += amount
        if self.used <= self.limit:
            return

        from crosstl.backend.Metal.preprocessor import MetalTemplateSpecializationError

        location = (
            _source_location_at_offset(self.unit, self.source, offset, max(length, 0))
            if self.unit is not None
            else None
        )
        requested_signature = f"{self.pass_name}: {self.used} work items for {context}"
        suggested_action = (
            "raise max_template_materialization_work for this source pattern "
            "or backend, reduce implicit Metal template helper fan-out, or add "
            "explicit template arguments"
        )
        location_text = (
            f" Source context: {location.file}:{location.line}:{location.column}."
            if location is not None
            else ""
        )
        raise MetalTemplateSpecializationError(
            "Metal template materialization work budget exceeded while "
            f"running {self.pass_name} for target '{self.target}'; "
            f"{self.used} work items requested, limit {self.limit} from "
            f"{self.limit_source}.{location_text} "
            f"Suggested action: {suggested_action}.",
            limit=self.limit,
            limit_source=self.limit_source,
            unique_specialization_count=self.used,
            requested_signature=requested_signature,
            suggested_action=suggested_action,
            source_location=location,
        )


def _metal_template_materialization_work_limit(
    source_options: Mapping[str, Any],
) -> int:
    configured = source_options.get(METAL_TEMPLATE_MATERIALIZATION_WORK_LIMIT_OPTION)
    if configured is not None:
        if isinstance(configured, bool):
            return 0
        try:
            return max(0, operator.index(configured))
        except (TypeError, ValueError):
            return 0

    template_limit = source_options.get(METAL_TEMPLATE_SPECIALIZATION_LIMIT_OPTION)
    try:
        specialization_limit = operator.index(template_limit)
    except (TypeError, ValueError):
        specialization_limit = 512
    return (
        max(0, specialization_limit)
        * METAL_TEMPLATE_MATERIALIZATION_WORK_LIMIT_MULTIPLIER
    )


def _metal_template_materialization_work_limit_source(
    source_options: Mapping[str, Any],
) -> str:
    configured_source = source_options.get(
        METAL_TEMPLATE_MATERIALIZATION_WORK_LIMIT_SOURCE_OPTION
    )
    if isinstance(configured_source, str) and configured_source:
        return configured_source
    if METAL_TEMPLATE_MATERIALIZATION_WORK_LIMIT_OPTION in source_options:
        return METAL_TEMPLATE_MATERIALIZATION_WORK_LIMIT_OPTION

    specialization_source = source_options.get(
        METAL_TEMPLATE_SPECIALIZATION_LIMIT_SOURCE_OPTION
    )
    if isinstance(specialization_source, str) and specialization_source:
        return (
            f"{specialization_source} x "
            f"{METAL_TEMPLATE_MATERIALIZATION_WORK_LIMIT_MULTIPLIER}"
        )
    return (
        f"{METAL_TEMPLATE_SPECIALIZATION_LIMIT_OPTION} x "
        f"{METAL_TEMPLATE_MATERIALIZATION_WORK_LIMIT_MULTIPLIER}"
    )


def _materialize_implicit_template_function_calls(
    *,
    preprocessor: Any,
    materialized: str,
    source_contexts: Sequence[_SourceInstantiationTemplateContext] = (),
    unit: ProjectTranslationUnit | None = None,
    target: str = "",
    work_limit: int | None = None,
    work_limit_source: str | None = None,
) -> _ImplicitTemplateMaterialization:
    templates = preprocessor._find_template_functions(materialized)
    templates_by_name: dict[str, Any] = {}
    overloaded_template_names: set[str] = set()
    for template in templates:
        if template.name in templates_by_name:
            overloaded_template_names.add(template.name)
            continue
        templates_by_name[template.name] = template
    for template_name in overloaded_template_names:
        templates_by_name.pop(template_name, None)
    template_spans = preprocessor._find_template_declaration_spans(materialized)
    reachable_function_spans = preprocessor._reachable_function_spans(
        materialized,
        template_spans,
    )
    return_types = _metal_reachable_function_return_types(
        preprocessor,
        materialized,
        template_spans,
        reachable_function_spans or [],
    )
    type_cache = _MetalMaterializationTypeEnvironmentCache()
    work_budget = (
        _MetalTemplateMaterializationWorkBudget(
            limit=work_limit,
            limit_source=work_limit_source or "max_template_materialization_work",
            unit=unit,
            source=materialized,
            target=target,
            pass_name=(
                "implicit-template-materialization/type-environment "
                f"(templates={len(templates_by_name)}, "
                f"functions={len(reachable_function_spans or [])})"
            ),
        )
        if work_limit is not None and work_limit > 0
        else None
    )
    implicit_calls = _metal_find_implicit_template_function_calls(
        preprocessor,
        materialized,
        templates_by_name,
        template_spans,
        reachable_function_spans,
        return_types,
        type_cache=type_cache,
        work_budget=work_budget,
    )
    context_by_materialized_name = {
        context.materialized_name: context for context in source_contexts
    }
    inherited_context_spans: list[
        tuple[tuple[int, int], _SourceInstantiationTemplateContext]
    ] = []
    if context_by_materialized_name:
        for function in preprocessor._find_non_template_function_definitions(
            materialized,
            template_spans,
        ):
            context = context_by_materialized_name.get(function.name)
            if context is not None:
                inherited_context_spans.append((function.body_span, context))
    implicit_replacements: list[tuple[int, int, str]] = []
    implicit_materializations: list[tuple[str, tuple[str, ...], str]] = []
    specializations: list[dict[str, Any]] = []
    seen_implicit_specializations: set[tuple[str, tuple[str, ...]]] = set()
    for function_name, arguments, span in implicit_calls:
        template = templates_by_name.get(function_name)
        if template is None or not preprocessor._template_arguments_satisfy_parameters(
            template,
            arguments,
        ):
            continue
        key = preprocessor._template_specialization_key(function_name, arguments)
        inherited_context = next(
            (
                context
                for context_span, context in inherited_context_spans
                if context_span[0] <= span[0] < context_span[1]
            ),
            None,
        )
        if inherited_context is not None:
            inherited = _inherited_template_arguments(
                preprocessor,
                template,
                inherited_context.parameters,
                inherited_context.parameter_sources,
            )
            if inherited is not None:
                inherited_arguments, _parameters, _sources = inherited
                inherited_key = preprocessor._template_specialization_key(
                    function_name,
                    inherited_arguments,
                )
                if inherited_key == key:
                    continue
        materialized_name = preprocessor._template_specialization_identifier(
            function_name,
            list(key[1]),
        )
        implicit_replacements.append((span[0], span[1], materialized_name))
        if key in seen_implicit_specializations:
            continue
        seen_implicit_specializations.add(key)
        materialized_source = preprocessor._materialize_template_function_with_name(
            template,
            arguments,
            materialized_name,
            host_name=None,
        )
        if materialized_source:
            implicit_materializations.append(
                (function_name, tuple(key[1]), materialized_source)
            )
            parameters = _template_parameter_values_from_arguments(
                preprocessor,
                template,
                list(key[1]),
            )
            specializations.append(
                _materialized_template_specialization_record(
                    name=function_name,
                    materialized_name=materialized_name,
                    parameters=parameters,
                    parameter_sources={
                        parameter: "call-site" for parameter in parameters
                    },
                    source="call-site",
                )
            )
    if implicit_replacements or implicit_materializations:
        replacements = list(implicit_replacements)
        for function_name, _arguments, materialized_source in implicit_materializations:
            template = templates_by_name.get(function_name)
            if template is None:
                continue
            replacements.append(
                (template.span[0], template.span[1], materialized_source)
            )
        materialized = preprocessor._apply_text_replacements(materialized, replacements)
    return _ImplicitTemplateMaterialization(
        text=materialized,
        specializations=specializations,
    )


def _plain_template_call_replacements(
    preprocessor: Any,
    source: str,
    replacements_by_name: Mapping[str, str],
    excluded_spans: Sequence[tuple[int, int]],
    included_spans: Sequence[tuple[int, int]] | None,
) -> list[tuple[int, int, str]]:
    replacements: list[tuple[int, int, str]] = []
    for _ident, replacement, i, consumed, scan_end in _template_replacement_scan_sites(
        preprocessor,
        source,
        replacements_by_name,
        excluded_spans,
        included_spans,
    ):
        j = i + consumed
        while j < scan_end and source[j].isspace():
            j += 1
        if j < scan_end and source[j] == "(":
            replacements.append((i, i + consumed, replacement))
    return replacements


def _explicit_template_call_replacements(
    preprocessor: Any,
    source: str,
    replacements_by_name: Mapping[str, str],
    excluded_spans: Sequence[tuple[int, int]],
    included_spans: Sequence[tuple[int, int]] | None,
) -> list[tuple[int, int, str]]:
    replacements: list[tuple[int, int, str]] = []
    for _ident, replacement, i, consumed, scan_end in _template_replacement_scan_sites(
        preprocessor,
        source,
        replacements_by_name,
        excluded_spans,
        included_spans,
    ):
        j = i + consumed
        while j < scan_end and source[j].isspace():
            j += 1
        if j >= scan_end or source[j] != "<":
            continue
        angle_end = preprocessor._find_matching_angle(source, j)
        if angle_end is None or angle_end >= scan_end:
            continue
        k = angle_end + 1
        while k < scan_end and source[k].isspace():
            k += 1
        if k < scan_end and source[k] == "(":
            replacements.append(
                (
                    preprocessor._scoped_identifier_start(source, i),
                    angle_end + 1,
                    replacement,
                )
            )
    return replacements


def _template_replacement_scan_sites(
    preprocessor: Any,
    source: str,
    replacements_by_name: Mapping[str, str],
    excluded_spans: Sequence[tuple[int, int]],
    included_spans: Sequence[tuple[int, int]] | None,
) -> Iterator[tuple[str, str, int, int, int]]:
    excluded = _SpanLookup(excluded_spans)
    scan_spans = (
        [(0, len(source))]
        if included_spans is None
        else _SpanLookup(included_spans)._spans
    )
    for span_start, span_end in scan_spans:
        i = span_start
        scan_end = min(span_end, len(source))
        while i < scan_end:
            if source[i] in "\"'":
                _literal, consumed = preprocessor._read_string(source, i)
                i += consumed
                continue
            if source.startswith("//", i):
                end = source.find("\n", i, scan_end)
                if end == -1:
                    break
                i = end + 1
                continue
            if source.startswith("/*", i):
                end = source.find("*/", i + 2, scan_end)
                if end == -1:
                    break
                i = end + 2
                continue
            excluded_span = excluded.containing(i)
            if excluded_span is not None:
                i = min(excluded_span[1], scan_end)
                continue
            if source[i].isalpha() or source[i] == "_":
                ident, consumed = preprocessor._read_identifier(source, i)
                replacement = replacements_by_name.get(ident)
                if replacement is not None:
                    yield ident, replacement, i, consumed, scan_end
                i += consumed
                continue
            i += 1


METAL_TEMPLATE_TYPE_QUALIFIERS = frozenset(
    {
        "const",
        "constant",
        "device",
        "thread",
        "threadgroup",
        "volatile",
        "inline",
        "static",
        "constexpr",
        "kernel",
        "METAL_FUNC",
    }
)
METAL_TEMPLATE_DECLARATION_PREFIXES = frozenset(
    {
        "return",
        "if",
        "for",
        "while",
        "switch",
        "case",
        "break",
        "continue",
        "discard",
        "else",
        "do",
    }
)
METAL_TEMPLATE_SCALAR_TYPES = frozenset(
    {
        "bool",
        "char",
        "uchar",
        "short",
        "ushort",
        "int",
        "uint",
        "long",
        "ulong",
        "float",
        "half",
        "double",
        "size_t",
        "uint8_t",
        "uint16_t",
        "uint32_t",
        "uint64_t",
        "int8_t",
        "int16_t",
        "int32_t",
        "int64_t",
        "bfloat16_t",
        "complex64_t",
    }
)


def _strip_metal_attribute_blocks(text: str) -> str:
    return re.sub(r"\[\[[^\]]*\]\]", " ", str(text or ""))


def _normalize_metal_type_text(type_text: str) -> str:
    text = _strip_metal_attribute_blocks(type_text)
    text = re.sub(r"\b(?:struct|class|typename)\s+", "", text)
    text = re.sub(r"\s+", " ", text).strip()
    text = re.sub(r"\s*([<>,*&\[\]()])\s*", r"\1", text)
    return text.strip()


def _strip_metal_type_qualifiers(type_text: str) -> str:
    text = _normalize_metal_type_text(type_text)
    tokens = text.split(" ")
    while tokens and tokens[0] in METAL_TEMPLATE_TYPE_QUALIFIERS:
        tokens.pop(0)
    return " ".join(tokens).strip()


def _metal_pointer_pointee_type(type_text: str) -> str | None:
    text = _strip_metal_type_qualifiers(type_text).rstrip()
    while text.endswith("&"):
        text = text[:-1].strip()
    if not text.endswith("*"):
        return None
    pointee = text[:-1].strip()
    return pointee or None


def _metal_array_element_type(type_text: str) -> str | None:
    text = _strip_metal_type_qualifiers(type_text)
    match = re.fullmatch(r"(?P<element>.+?)(?:\[[^\]]*\])+", text)
    if match is None:
        return None
    return match.group("element").strip()


def _metal_generic_type_parts(
    preprocessor: Any, type_text: str
) -> tuple[str, list[str]]:
    text = _strip_metal_type_qualifiers(type_text)
    if not text.endswith(">"):
        return text, []
    angle_start = text.find("<")
    if angle_start == -1:
        return text, []
    angle_end = preprocessor._find_matching_angle(text, angle_start)
    if angle_end != len(text) - 1:
        return text, []
    return text[:angle_start].strip(), preprocessor._split_top_level_commas(
        text[angle_start + 1 : angle_end]
    )


def _metal_merge_template_binding(
    bindings: dict[str, str],
    parameter: str,
    value: str,
) -> bool:
    normalized_value = _strip_metal_type_qualifiers(value)
    existing = bindings.get(parameter)
    if existing is None:
        bindings[parameter] = normalized_value
        return True
    return _strip_metal_type_qualifiers(existing) == normalized_value


def _collect_metal_template_type_bindings(
    preprocessor: Any,
    *,
    expected_type: str,
    actual_type: str,
    bindings: dict[str, str],
    template_parameters: set[str],
) -> bool:
    expected = _strip_metal_type_qualifiers(expected_type)
    actual = _strip_metal_type_qualifiers(actual_type)
    if not expected or not actual:
        return True

    while expected.endswith("&") or actual.endswith("&"):
        expected = expected[:-1].strip() if expected.endswith("&") else expected
        actual = actual[:-1].strip() if actual.endswith("&") else actual

    if expected in template_parameters:
        return _metal_merge_template_binding(bindings, expected, actual)

    expected_pointee = _metal_pointer_pointee_type(expected)
    actual_pointee = _metal_pointer_pointee_type(actual)
    if expected_pointee is not None and actual_pointee is not None:
        return _collect_metal_template_type_bindings(
            preprocessor,
            expected_type=expected_pointee,
            actual_type=actual_pointee,
            bindings=bindings,
            template_parameters=template_parameters,
        )

    expected_element = _metal_array_element_type(expected)
    actual_element = _metal_array_element_type(actual)
    if expected_element is not None and actual_element is not None:
        return _collect_metal_template_type_bindings(
            preprocessor,
            expected_type=expected_element,
            actual_type=actual_element,
            bindings=bindings,
            template_parameters=template_parameters,
        )

    expected_base, expected_args = _metal_generic_type_parts(preprocessor, expected)
    actual_base, actual_args = _metal_generic_type_parts(preprocessor, actual)
    if (
        not expected_args
        or expected_base != actual_base
        or len(expected_args) != len(actual_args)
    ):
        return True

    for expected_arg, actual_arg in zip(expected_args, actual_args):
        if not _collect_metal_template_type_bindings(
            preprocessor,
            expected_type=expected_arg,
            actual_type=actual_arg,
            bindings=bindings,
            template_parameters=template_parameters,
        ):
            return False
    return True


def _metal_declared_type_and_name(declaration: str) -> tuple[str, str] | None:
    cleaned = _strip_metal_attribute_blocks(declaration)
    cleaned = cleaned.split("=", 1)[0].strip()
    cleaned = cleaned.rstrip(";").strip()
    if not cleaned or cleaned == "void":
        return None
    name_match = re.search(
        r"(?P<name>[A-Za-z_][A-Za-z0-9_]*)\s*(?:\[[^\]]*\]\s*)*$",
        cleaned,
    )
    if name_match is None:
        return None
    name = name_match.group("name")
    type_text = cleaned[: name_match.start()].strip()
    if not type_text:
        return None
    array_suffix = cleaned[name_match.end("name") :].strip()
    if array_suffix:
        type_text = f"{type_text}{array_suffix}"
    return _normalize_metal_type_text(type_text), name


def _metal_function_parameter_declarations(
    preprocessor: Any, header: str
) -> list[tuple[str, str, bool]]:
    open_paren = preprocessor._function_parameter_start(header)
    if open_paren is None:
        return []
    close_paren = preprocessor._find_matching_delimiter(header, open_paren, "(", ")")
    if close_paren is None:
        return []

    declarations: list[tuple[str, str, bool]] = []
    for parameter in preprocessor._split_top_level_commas(
        header[open_paren + 1 : close_paren]
    ):
        parameter = parameter.strip()
        if not parameter or parameter == "void":
            continue
        variadic = "..." in parameter
        normalized = parameter.replace("...", " ")
        parsed = _metal_declared_type_and_name(normalized)
        if parsed is None:
            continue
        type_text, name = parsed
        declarations.append((type_text, name, variadic))
    return declarations


def _metal_template_call_arity_matches(
    parameter_declarations: Sequence[tuple[str, str, bool]],
    call_argument_count: int,
) -> bool:
    if not any(variadic for _type_text, _name, variadic in parameter_declarations):
        return len(parameter_declarations) == call_argument_count

    minimum_argument_count = sum(
        1 for _type_text, _name, variadic in parameter_declarations if not variadic
    )
    return call_argument_count >= minimum_argument_count


def _metal_template_materialized_name(
    preprocessor: Any,
    function_name: str,
    arguments: Sequence[str],
    parameter_declarations: Sequence[tuple[str, str, bool]],
    existing_names: Mapping[tuple[str, tuple[str, ...], tuple[str, ...]], str],
) -> str:
    base_name = preprocessor._template_specialization_identifier(
        function_name,
        list(arguments),
    )
    if base_name not in set(existing_names.values()):
        return base_name

    signature_parts = [
        _normalize_metal_type_text(type_text).replace("...", "variadic")
        for type_text, _name, _variadic in parameter_declarations
    ]
    suffix = hashlib.sha1("|".join(signature_parts).encode("utf-8")).hexdigest()[:8]
    return f"{base_name}_{len(parameter_declarations)}_{suffix}"


def _metal_function_return_type(
    preprocessor: Any, header: str, function_name: str
) -> str | None:
    open_paren = preprocessor._function_parameter_start(header)
    if open_paren is None:
        return None
    before_params = header[:open_paren].rstrip()
    match = re.search(rf"\b{re.escape(function_name)}\s*$", before_params)
    if match is None:
        return None
    return_type = _strip_metal_attribute_blocks(before_params[: match.start()])
    return_type = _strip_metal_type_qualifiers(return_type)
    return return_type or None


def _metal_function_header(source: str, function: Any) -> str:
    return source[function.span[0] : function.body_span[0] - 1]


def _metal_statement_spans(source: str, start: int, end: int) -> list[tuple[int, int]]:
    spans: list[tuple[int, int]] = []
    statement_start = start
    paren_depth = bracket_depth = angle_depth = brace_depth = 0
    i = start
    while i < end:
        if source[i] in "\"'":
            _literal, consumed = _read_metal_string_for_project(source, i)
            i += consumed
            continue
        if source.startswith("//", i):
            line_end = source.find("\n", i)
            if line_end == -1:
                break
            i = line_end + 1
            continue
        if source.startswith("/*", i):
            comment_end = source.find("*/", i + 2)
            if comment_end == -1:
                break
            i = comment_end + 2
            continue
        ch = source[i]
        if (
            ch == ";"
            and paren_depth == 0
            and bracket_depth == 0
            and angle_depth == 0
            and brace_depth == 0
        ):
            spans.append((statement_start, i + 1))
            statement_start = i + 1
        elif ch == "(":
            paren_depth += 1
        elif ch == ")":
            paren_depth = max(0, paren_depth - 1)
        elif ch == "[":
            bracket_depth += 1
        elif ch == "]":
            bracket_depth = max(0, bracket_depth - 1)
        elif ch == "<":
            angle_depth += 1
        elif ch == ">":
            angle_depth = max(0, angle_depth - 1)
        elif ch == "{":
            brace_depth += 1
        elif ch == "}":
            brace_depth = max(0, brace_depth - 1)
        i += 1
    return spans


def _read_metal_string_for_project(source: str, start: int) -> tuple[str, int]:
    quote = source[start]
    i = start + 1
    while i < len(source):
        if source[i] == "\\":
            i += 2
            continue
        if source[i] == quote:
            return source[start : i + 1], i + 1 - start
        i += 1
    return source[start:], len(source) - start


def _metal_split_assignment(statement: str) -> tuple[str, str | None]:
    depth = 0
    for index, ch in enumerate(statement):
        if ch == "=" and depth == 0:
            return statement[:index], statement[index + 1 :]
        if ch in "({" and depth == 0:
            return statement[:index], statement[index:]
        if ch in "(<[{":
            depth += 1
        elif ch in ")>]}":
            depth = max(0, depth - 1)
    return statement, None


def _metal_local_variable_declaration(
    preprocessor: Any,
    statement: str,
    type_environment: Mapping[str, str],
    return_types: Mapping[str, str],
) -> tuple[str, str] | None:
    cleaned = _strip_metal_attribute_blocks(statement).strip().rstrip(";").strip()
    if not cleaned or cleaned.startswith("#"):
        return None
    first_word = cleaned.split(None, 1)[0] if cleaned.split(None, 1) else ""
    if first_word in METAL_TEMPLATE_DECLARATION_PREFIXES:
        return None

    declaration, initializer = _metal_split_assignment(cleaned)
    declaration_parts = preprocessor._split_top_level_commas(declaration)
    if not declaration_parts:
        return None
    first_declaration = declaration_parts[0]
    parsed = _metal_declared_type_and_name(first_declaration)
    if parsed is None:
        return None
    type_text, name = parsed
    if type_text == "auto" and initializer is not None:
        inferred = _metal_expression_type(
            preprocessor,
            initializer,
            type_environment,
            return_types,
        )
        if inferred:
            type_text = inferred
    return name, _normalize_metal_type_text(type_text)


def _metal_evaluate_integer_constant_expression(
    expression: str,
    constants: Mapping[str, str],
) -> str | None:
    text = str(expression or "").strip()
    if not text:
        return None
    for name, value in sorted(
        constants.items(),
        key=lambda item: len(item[0]),
        reverse=True,
    ):
        text = re.sub(rf"\b{re.escape(name)}\b", f"({value})", text)
    text = re.sub(r"\b(?:short|int|uint|long|ulong)\s*\(", "(", text)
    text = re.sub(r"\b([0-9]+)[uUlL]*\b", r"\1", text)
    if re.search(r"[^0-9+\-*/%<>&|^~()\s]", text):
        return None

    try:
        tree = ast.parse(text, mode="eval")
    except SyntaxError:
        return None

    def eval_node(node: ast.AST) -> int | None:
        if isinstance(node, ast.Expression):
            return eval_node(node.body)
        if isinstance(node, ast.Constant) and isinstance(node.value, int):
            return int(node.value)
        if isinstance(node, ast.UnaryOp):
            value = eval_node(node.operand)
            if value is None:
                return None
            if isinstance(node.op, ast.UAdd):
                return value
            if isinstance(node.op, ast.USub):
                return -value
            if isinstance(node.op, ast.Invert):
                return ~value
            return None
        if isinstance(node, ast.BinOp):
            left = eval_node(node.left)
            right = eval_node(node.right)
            if left is None or right is None:
                return None
            if isinstance(node.op, ast.Add):
                return left + right
            if isinstance(node.op, ast.Sub):
                return left - right
            if isinstance(node.op, ast.Mult):
                return left * right
            if isinstance(node.op, (ast.Div, ast.FloorDiv)):
                if right == 0:
                    return None
                return int(left / right)
            if isinstance(node.op, ast.Mod):
                if right == 0:
                    return None
                return left % right
            if isinstance(node.op, ast.LShift):
                return left << right
            if isinstance(node.op, ast.RShift):
                return left >> right
            if isinstance(node.op, ast.BitOr):
                return left | right
            if isinstance(node.op, ast.BitAnd):
                return left & right
            if isinstance(node.op, ast.BitXor):
                return left ^ right
        return None

    value = eval_node(tree)
    return str(value) if value is not None else None


def _metal_local_constant_declaration(
    statement: str,
    constants: Mapping[str, str],
) -> tuple[str, str] | None:
    cleaned = _strip_metal_attribute_blocks(statement).strip().rstrip(";").strip()
    match = re.match(
        r"(?:static\s+)?(?:constexpr\s+)?(?:const\s+)?"
        r"(?:short|ushort|int|uint|long|ulong|size_t|auto)\s+"
        r"(?P<name>[A-Za-z_][A-Za-z0-9_]*)\s*=\s*(?P<value>.+)$",
        cleaned,
        re.DOTALL,
    )
    if match is None:
        return None
    value = _metal_evaluate_integer_constant_expression(
        match.group("value"),
        constants,
    )
    if value is None:
        return None
    return match.group("name"), value


def _metal_local_using_alias(
    preprocessor: Any,
    statement: str,
    aliases: Mapping[str, str],
    constants: Mapping[str, str],
    *,
    cache: _MetalMaterializationTypeEnvironmentCache | None = None,
    work_budget: _MetalTemplateMaterializationWorkBudget | None = None,
    offset: int = 0,
) -> tuple[str, str] | None:
    cleaned = _strip_metal_attribute_blocks(statement).strip().rstrip(";").strip()
    match = re.match(
        r"using\s+(?P<name>[A-Za-z_][A-Za-z0-9_]*)\s*=\s*(?P<type>.+)$",
        cleaned,
        re.DOTALL,
    )
    if match is None:
        return None
    return (
        match.group("name"),
        _metal_resolve_type_identifiers(
            preprocessor,
            match.group("type"),
            aliases=aliases,
            constants=constants,
            cache=cache,
            work_budget=work_budget,
            offset=offset,
            length=len(statement),
        ),
    )


def _metal_rewrite_identifier_tokens(
    text: str,
    replacements: Mapping[str, str],
) -> tuple[str, bool]:
    if not replacements:
        return text, False

    parts: list[str] = []
    changed = False
    i = 0
    while i < len(text):
        if text[i].isalpha() or text[i] == "_":
            j = i + 1
            while j < len(text) and (text[j].isalnum() or text[j] == "_"):
                j += 1
            token = text[i:j]
            replacement = (
                None if text[max(0, i - 2) : i] == "::" else replacements.get(token)
            )
            if replacement is None:
                parts.append(token)
            else:
                replacement_text = str(replacement)
                parts.append(replacement_text)
                changed = changed or replacement_text != token
            i = j
            continue
        parts.append(text[i])
        i += 1

    if not changed:
        return text, False
    return "".join(parts), True


def _raise_metal_type_identifier_rewrite_error(
    *,
    original_text: str,
    current_text: str,
    pass_count: int,
    pass_limit: int,
    work_budget: _MetalTemplateMaterializationWorkBudget | None,
    offset: int,
    length: int,
    reason: str,
) -> None:
    from crosstl.backend.Metal.preprocessor import MetalTemplateSpecializationError

    location = (
        _source_location_at_offset(
            work_budget.unit,
            work_budget.source,
            offset,
            max(length, 0),
        )
        if work_budget is not None and work_budget.unit is not None
        else None
    )
    location_text = (
        f" Source context: {location.file}:{location.line}:{location.column}."
        if location is not None
        else ""
    )
    target_text = (
        f" for target '{work_budget.target}'" if work_budget is not None else ""
    )
    pass_name = (
        work_budget.pass_name
        if work_budget is not None
        else "metal-template-materialization/type-identifier-rewrite"
    )
    limit_source = (
        f"{work_budget.limit_source}; type-alias dependency graph"
        if work_budget is not None
        else "type-alias dependency graph"
    )
    suggested_action = (
        "break cyclic local using aliases or provide explicit template arguments "
        "so Metal template materialization can resolve concrete types"
    )
    raise MetalTemplateSpecializationError(
        "Metal template materialization type identifier rewrite limit exceeded "
        f"while running {pass_name}{target_text}; {pass_count} rewrite passes "
        f"requested, limit {pass_limit} from {limit_source}. "
        f"Initial type '{original_text}' reached '{current_text}' before "
        f"stabilizing ({reason}).{location_text} "
        f"Suggested action: {suggested_action}.",
        limit=pass_limit,
        limit_source=limit_source,
        unique_specialization_count=pass_count,
        requested_signature=(
            f"{pass_name}: {pass_count} type identifier rewrite passes for "
            f"'{original_text}'"
        ),
        suggested_action=suggested_action,
        source_location=location,
    )


def _metal_resolve_type_identifiers(
    preprocessor: Any,
    type_text: str,
    *,
    aliases: Mapping[str, str],
    constants: Mapping[str, str],
    cache: _MetalMaterializationTypeEnvironmentCache | None = None,
    work_budget: _MetalTemplateMaterializationWorkBudget | None = None,
    offset: int = 0,
    length: int = 0,
) -> str:
    text = _normalize_metal_type_text(type_text)
    aliases_key = tuple(
        sorted((str(name), str(value)) for name, value in aliases.items())
    )
    constants_key = tuple(
        sorted((str(name), str(value)) for name, value in constants.items())
    )
    cache_key = (text, aliases_key, constants_key)
    if cache is not None:
        cached = cache.resolved_types.get(cache_key)
        if cached is not None:
            return cached
    if work_budget is not None:
        work_budget.consume(
            1,
            offset=offset,
            length=length,
            context=f"resolving type '{text}'",
        )
    alias_values = dict(aliases_key)
    constant_values = dict(constants_key)
    rewrite_pass_limit = max(1, len(alias_values) + len(constant_values) + 1)
    seen_texts = {text}
    for rewrite_pass in range(1, rewrite_pass_limit + 1):
        previous = text
        text, alias_changed = _metal_rewrite_identifier_tokens(text, alias_values)
        text, constant_changed = _metal_rewrite_identifier_tokens(
            text,
            constant_values,
        )
        if "<" in text and ">" in text:
            base, arguments = _metal_generic_type_parts(preprocessor, text)
            if arguments:
                resolved_arguments = [
                    _metal_evaluate_integer_constant_expression(argument, constants)
                    or argument
                    for argument in arguments
                ]
                generic_text = f"{base}<{','.join(resolved_arguments)}>"
                if generic_text != text:
                    text = generic_text
        if text == previous and not alias_changed and not constant_changed:
            break
        if text in seen_texts:
            _raise_metal_type_identifier_rewrite_error(
                original_text=cache_key[0],
                current_text=text,
                pass_count=rewrite_pass,
                pass_limit=rewrite_pass_limit,
                work_budget=work_budget,
                offset=offset,
                length=length,
                reason="cycle detected",
            )
        seen_texts.add(text)
    else:
        _raise_metal_type_identifier_rewrite_error(
            original_text=cache_key[0],
            current_text=text,
            pass_count=rewrite_pass_limit,
            pass_limit=rewrite_pass_limit,
            work_budget=work_budget,
            offset=offset,
            length=length,
            reason="pass limit reached",
        )
    resolved = _normalize_metal_type_text(text)
    if cache is not None:
        cache.resolved_types[cache_key] = resolved
    return resolved


def _metal_function_type_environment(
    preprocessor: Any,
    source: str,
    function: Any,
    return_types: Mapping[str, str],
    *,
    cache: _MetalMaterializationTypeEnvironmentCache | None = None,
    work_budget: _MetalTemplateMaterializationWorkBudget | None = None,
) -> dict[str, str]:
    return_type_key = tuple(
        sorted((str(name), str(value)) for name, value in return_types.items())
    )
    cache_key = (int(function.span[0]), int(function.span[1]), return_type_key)
    if cache is not None:
        cached_environment = cache.environments.get(cache_key)
        if cached_environment is not None:
            return dict(cached_environment)
    if work_budget is not None:
        work_budget.consume(
            1,
            offset=int(function.span[0]),
            length=max(int(function.span[1]) - int(function.span[0]), 0),
            context=f"function '{function.name}'",
        )
    environment: dict[str, str] = {}
    constants: dict[str, str] = {}
    aliases: dict[str, str] = {}
    header = _metal_function_header(source, function)
    for type_text, name, _variadic in _metal_function_parameter_declarations(
        preprocessor,
        header,
    ):
        environment[name] = _metal_resolve_type_identifiers(
            preprocessor,
            type_text,
            aliases=aliases,
            constants=constants,
            cache=cache,
            work_budget=work_budget,
            offset=int(function.span[0]),
            length=max(int(function.body_span[0]) - int(function.span[0]), 0),
        )

    body_start, body_end = function.body_span
    for start, end in _metal_statement_spans(source, body_start, body_end):
        statement = source[start:end]
        constant = _metal_local_constant_declaration(statement, constants)
        if constant is not None:
            name, value = constant
            constants[name] = value
            continue
        alias = _metal_local_using_alias(
            preprocessor,
            statement,
            aliases,
            constants,
            cache=cache,
            work_budget=work_budget,
            offset=start,
        )
        if alias is not None:
            name, type_text = alias
            aliases[name] = type_text
            continue
        declaration = _metal_local_variable_declaration(
            preprocessor,
            statement,
            environment,
            return_types,
        )
        if declaration is not None:
            name, type_text = declaration
            environment[name] = _metal_resolve_type_identifiers(
                preprocessor,
                type_text,
                aliases=aliases,
                constants=constants,
                cache=cache,
                work_budget=work_budget,
                offset=start,
                length=max(end - start, 0),
            )
    if cache is not None:
        cache.environments[cache_key] = dict(environment)
    return environment


def _metal_strip_outer_parentheses(expression: str) -> str:
    text = expression.strip()
    while text.startswith("(") and text.endswith(")"):
        depth = 0
        matched_outer = False
        for index, ch in enumerate(text):
            if ch == "(":
                depth += 1
            elif ch == ")":
                depth -= 1
                if depth == 0:
                    matched_outer = index == len(text) - 1
                    break
        if not matched_outer:
            break
        text = text[1:-1].strip()
    return text


def _metal_literal_type(expression: str) -> str | None:
    text = expression.strip()
    if re.fullmatch(r"(?:true|false)", text):
        return "bool"
    if re.fullmatch(r"0[xX][0-9A-Fa-f]+[uU]?", text):
        return "uint" if text[-1:].lower() == "u" else "int"
    if re.fullmatch(r"\d+[uU]", text):
        return "uint"
    if re.fullmatch(r"\d+[lL]?[uU]?[lL]?", text):
        return "int"
    if re.fullmatch(
        r"(?:\d+\.\d*|\.\d+|\d+[eE][+-]?\d+|\d+\.\d*[eE][+-]?\d+)[fF]?",
        text,
    ):
        return "float"
    if re.fullmatch(
        r"(?:\d+\.\d*|\.\d+|\d+[eE][+-]?\d+|\d+\.\d*[eE][+-]?\d+)[hH]",
        text,
    ):
        return "half"
    return None


def _metal_expression_callee(
    preprocessor: Any, expression: str
) -> tuple[str, str, int] | None:
    text = expression.strip()
    match = re.match(r"[A-Za-z_][A-Za-z0-9_:]*", text)
    if match is None:
        return None
    callee = match.group(0)
    end = match.end()
    rendered = callee
    while end < len(text) and text[end].isspace():
        end += 1
    if end < len(text) and text[end] == "<":
        angle_end = preprocessor._find_matching_angle(text, end)
        if angle_end is None:
            return None
        rendered = text[: angle_end + 1].strip()
        end = angle_end + 1
        while end < len(text) and text[end].isspace():
            end += 1
    if end >= len(text) or text[end] != "(":
        return None
    return callee.split("::")[-1], rendered, end


def _metal_looks_like_type_name(type_name: str) -> bool:
    base = type_name.split("<", 1)[0].split("::")[-1].strip()
    return (
        base in METAL_TEMPLATE_SCALAR_TYPES
        or re.fullmatch(r"(?:u?int|float|half|bool)(?:[234](?:x[234])?)?", base)
        is not None
        or base.endswith("_t")
        or (base[:1].isupper() and not base.isupper())
    )


def _metal_expression_type(
    preprocessor: Any,
    expression: str,
    type_environment: Mapping[str, str],
    return_types: Mapping[str, str],
) -> str | None:
    text = _metal_strip_outer_parentheses(expression).rstrip(";").strip()
    if not text:
        return None

    literal_type = _metal_literal_type(text)
    if literal_type is not None:
        return literal_type

    static_cast = re.match(r"(?:static_cast|as_type)\s*<(?P<type>[^>]+)>\s*\(", text)
    if static_cast is not None:
        return _normalize_metal_type_text(static_cast.group("type"))

    c_style_cast = re.match(r"\(\s*(?P<type>[A-Za-z_][A-Za-z0-9_:<>]*)\s*\)", text)
    if c_style_cast is not None and _metal_looks_like_type_name(
        c_style_cast.group("type")
    ):
        return _normalize_metal_type_text(c_style_cast.group("type"))

    index_match = re.match(r"(?P<name>[A-Za-z_][A-Za-z0-9_]*)\s*\[", text)
    if index_match is not None:
        base_type = type_environment.get(index_match.group("name"))
        if base_type:
            return (
                _metal_pointer_pointee_type(base_type)
                or _metal_array_element_type(base_type)
                or base_type
            )

    pointer_match = re.match(r"(?P<name>[A-Za-z_][A-Za-z0-9_]*)\s*[+\-]", text)
    if pointer_match is not None and pointer_match.group("name") in type_environment:
        return type_environment[pointer_match.group("name")]

    address_match = re.match(r"&\s*(?P<name>[A-Za-z_][A-Za-z0-9_]*)\b", text)
    if address_match is not None:
        base_type = type_environment.get(address_match.group("name"))
        if base_type:
            return f"{base_type}*"

    if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", text):
        return type_environment.get(text)

    callee = _metal_expression_callee(preprocessor, text)
    if callee is not None:
        callee_name, rendered_callee, _paren_start = callee
        return_type = return_types.get(callee_name)
        if return_type:
            return return_type
        if _metal_looks_like_type_name(rendered_callee):
            return _normalize_metal_type_text(rendered_callee)

    for operator_text in ("+", "-", "*", "/", "%", "|", "&", "^"):
        parts = _split_metal_expression_operator(text, operator_text)
        if len(parts) > 1:
            inferred = [
                _metal_expression_type(
                    preprocessor,
                    part,
                    type_environment,
                    return_types,
                )
                for part in parts
            ]
            for preferred in (
                "double",
                "float",
                "half",
                "ulong",
                "uint",
                "long",
                "int",
            ):
                if preferred in inferred:
                    return preferred
            return next((item for item in inferred if item), None)
    return None


def _split_metal_expression_operator(expression: str, operator_text: str) -> list[str]:
    parts: list[str] = []
    current = []
    paren_depth = bracket_depth = angle_depth = brace_depth = 0
    i = 0
    while i < len(expression):
        ch = expression[i]
        if ch in "\"'":
            literal, consumed = _read_metal_string_for_project(expression, i)
            current.append(literal)
            i += consumed
            continue
        if ch == "(":
            paren_depth += 1
        elif ch == ")":
            paren_depth = max(0, paren_depth - 1)
        elif ch == "[":
            bracket_depth += 1
        elif ch == "]":
            bracket_depth = max(0, bracket_depth - 1)
        elif ch == "<":
            angle_depth += 1
        elif ch == ">":
            angle_depth = max(0, angle_depth - 1)
        elif ch == "{":
            brace_depth += 1
        elif ch == "}":
            brace_depth = max(0, brace_depth - 1)
        if (
            expression.startswith(operator_text, i)
            and paren_depth == 0
            and bracket_depth == 0
            and angle_depth == 0
            and brace_depth == 0
        ):
            parts.append("".join(current).strip())
            current = []
            i += len(operator_text)
            continue
        current.append(ch)
        i += 1
    if parts:
        parts.append("".join(current).strip())
    return [part for part in parts if part]


class _SpanLookup:
    def __init__(self, spans: Sequence[tuple[int, int]]):
        merged: list[tuple[int, int]] = []
        for start, end in sorted(
            (int(start), int(end)) for start, end in spans if start < end
        ):
            if merged and start <= merged[-1][1]:
                merged[-1] = (merged[-1][0], max(merged[-1][1], end))
            else:
                merged.append((start, end))
        self._spans = merged
        self._starts = [start for start, _end in merged]

    def containing(self, position: int) -> tuple[int, int] | None:
        index = bisect.bisect_right(self._starts, position) - 1
        if index < 0:
            return None
        start, end = self._spans[index]
        if start <= position < end:
            return start, end
        return None


_PlainTemplateHelperCallSite = tuple[str, list[str], tuple[int, int], list[str]]


def _metal_template_reference_names(
    preprocessor: Any,
    source: str,
    template_names: set[str],
    excluded_spans: Sequence[tuple[int, int]],
    included_spans: Sequence[tuple[int, int]],
) -> set[str]:
    references: set[str] = set()
    excluded = _SpanLookup(excluded_spans)
    for span_start, span_end in _SpanLookup(included_spans)._spans:
        i = span_start
        scan_end = min(span_end, len(source))
        while i < scan_end:
            if source[i] in "\"'":
                _literal, consumed = preprocessor._read_string(source, i)
                i += consumed
                continue
            if source.startswith("//", i):
                end = source.find("\n", i, scan_end)
                if end == -1:
                    break
                i = end + 1
                continue
            if source.startswith("/*", i):
                end = source.find("*/", i + 2, scan_end)
                if end == -1:
                    break
                i = end + 2
                continue
            excluded_span = excluded.containing(i)
            if excluded_span is not None:
                i = min(excluded_span[1], scan_end)
                continue
            if not (source[i].isalpha() or source[i] == "_"):
                i += 1
                continue

            ident, consumed = preprocessor._read_identifier(source, i)
            if (
                ident not in template_names
                or preprocessor._is_member_identifier_context(
                    source,
                    i,
                )
            ):
                i += consumed
                continue
            j = i + consumed
            while j < scan_end and source[j].isspace():
                j += 1
            if j < scan_end and source[j] == "<":
                angle_end = preprocessor._find_matching_angle(source, j)
                if angle_end is None or angle_end >= scan_end:
                    i += consumed
                    continue
                j = angle_end + 1
                while j < scan_end and source[j].isspace():
                    j += 1
            if j < scan_end and source[j] == "(":
                references.add(ident)
            i += consumed
    return references


def _reachable_metal_template_function_names(
    preprocessor: Any,
    source: str,
    templates: Sequence[Any],
    template_spans: Sequence[tuple[int, int]],
    reachable_function_spans: Sequence[tuple[int, int]] | None,
) -> set[str]:
    if not reachable_function_spans:
        return set()

    template_names = {template.name for template in templates}
    required = _metal_template_reference_names(
        preprocessor,
        source,
        template_names,
        template_spans,
        reachable_function_spans,
    )
    if not required:
        return set()

    templates_by_name: dict[str, list[Any]] = {}
    for template in templates:
        templates_by_name.setdefault(template.name, []).append(template)

    pending = list(required)
    while pending:
        template_name = pending.pop()
        for template in templates_by_name.get(template_name, ()):
            body_span = (int(template.body_start) + 1, int(template.span[1]) - 1)
            children = _metal_template_reference_names(
                preprocessor,
                source,
                template_names,
                template_spans,
                [body_span],
            )
            for child in children:
                if child not in required:
                    required.add(child)
                    pending.append(child)
    return required


def _plain_template_helper_call_sites(
    preprocessor: Any,
    source: str,
    templates_by_name: Mapping[str, Any],
    excluded_spans: Sequence[tuple[int, int]],
    included_spans: Sequence[tuple[int, int]],
) -> list[_PlainTemplateHelperCallSite]:
    """Return helper name, call arguments, replacement span, and explicit type args."""
    calls: list[_PlainTemplateHelperCallSite] = []
    excluded = _SpanLookup(excluded_spans)
    for span_start, span_end in _SpanLookup(included_spans)._spans:
        i = span_start
        scan_end = min(span_end, len(source))
        while i < scan_end:
            if source[i] in "\"'":
                _literal, consumed = preprocessor._read_string(source, i)
                i += consumed
                continue
            if source.startswith("//", i):
                end = source.find("\n", i, scan_end)
                if end == -1:
                    break
                i = end + 1
                continue
            if source.startswith("/*", i):
                end = source.find("*/", i + 2, scan_end)
                if end == -1:
                    break
                i = end + 2
                continue
            span = excluded.containing(i)
            if span is not None:
                i = min(span[1], scan_end)
                continue
            if source[i].isalpha() or source[i] == "_":
                ident, consumed = preprocessor._read_identifier(source, i)
                if (
                    ident not in templates_by_name
                    or preprocessor._is_member_identifier_context(
                        source,
                        i,
                    )
                ):
                    i += consumed
                    continue
                j = i + consumed
                while j < scan_end and source[j].isspace():
                    j += 1
                explicit_template_arguments: list[str] = []
                replacement_end = i + consumed
                if j < scan_end and source[j] == "<":
                    angle_end = preprocessor._find_matching_angle(source, j)
                    if angle_end is None or angle_end >= scan_end:
                        i += consumed
                        continue
                    explicit_template_arguments = preprocessor._split_top_level_commas(
                        source[j + 1 : angle_end]
                    )
                    replacement_end = angle_end + 1
                    j = angle_end + 1
                    while j < scan_end and source[j].isspace():
                        j += 1
                if j >= scan_end or source[j] != "(":
                    i += consumed
                    continue
                paren_end = preprocessor._find_matching_delimiter(source, j, "(", ")")
                if paren_end is None:
                    i += consumed
                    continue
                arguments = preprocessor._split_top_level_commas(
                    source[j + 1 : paren_end]
                )
                calls.append(
                    (
                        ident,
                        arguments,
                        (
                            preprocessor._scoped_identifier_start(source, i),
                            replacement_end,
                        ),
                        explicit_template_arguments,
                    )
                )
                i = paren_end + 1
                continue
            i += 1
    return calls


def _infer_plain_template_helper_arguments(
    preprocessor: Any,
    template: Any,
    call_arguments: Sequence[str],
    type_environment: Mapping[str, str],
    return_types: Mapping[str, str],
    explicit_template_arguments: Sequence[str] = (),
) -> list[str] | None:
    header = _metal_template_header(template)
    parameter_declarations = _metal_function_parameter_declarations(
        preprocessor,
        header,
    )
    if not parameter_declarations:
        return None
    if not _metal_template_call_arity_matches(
        parameter_declarations,
        len(call_arguments),
    ):
        return None

    template_parameters = set(getattr(template, "template_parameters", []) or [])
    variadic_parameters = set(
        getattr(template, "variadic_template_parameters", set()) or set()
    )
    explicit_bindings, explicit_variadic_bindings = (
        preprocessor._template_argument_bindings(
            template,
            list(explicit_template_arguments),
        )
        if explicit_template_arguments
        else ({}, {})
    )
    bindings: dict[str, str] = {
        parameter: _strip_metal_type_qualifiers(value)
        for parameter, value in explicit_bindings.items()
    }
    variadic_bindings: dict[str, list[str]] = {
        parameter: [
            _strip_metal_type_qualifiers(str(value))
            for value in values
            if str(value).strip()
        ]
        for parameter, values in explicit_variadic_bindings.items()
    }
    argument_index = 0
    for parameter_index, (expected_type, _name, variadic) in enumerate(
        parameter_declarations
    ):
        if variadic:
            remaining_fixed = len(parameter_declarations) - parameter_index - 1
            variadic_count = max(
                0,
                len(call_arguments) - argument_index - remaining_fixed,
            )
            actual_types = [
                _metal_expression_type(
                    preprocessor,
                    argument,
                    type_environment,
                    return_types,
                )
                for argument in call_arguments[
                    argument_index : argument_index + variadic_count
                ]
            ]
            argument_index += variadic_count
            expected_clean = _strip_metal_type_qualifiers(expected_type)
            if expected_clean in variadic_parameters and all(actual_types):
                variadic_bindings[expected_clean] = [
                    _strip_metal_type_qualifiers(str(actual_type))
                    for actual_type in actual_types
                    if actual_type
                ]
            continue
        if argument_index >= len(call_arguments):
            continue
        actual_type = _metal_expression_type(
            preprocessor,
            call_arguments[argument_index],
            type_environment,
            return_types,
        )
        argument_index += 1
        if not actual_type:
            continue
        if not _collect_metal_template_type_bindings(
            preprocessor,
            expected_type=expected_type,
            actual_type=actual_type,
            bindings=bindings,
            template_parameters=template_parameters,
        ):
            return None

    defaults = _metal_template_parameter_defaults(
        preprocessor,
        template.source,
        template,
        bindings,
    )
    bindings = {**defaults, **bindings}
    for parameter, values in variadic_bindings.items():
        bindings[parameter] = ", ".join(values)

    missing = [
        parameter
        for parameter in getattr(template, "template_parameters", []) or []
        if parameter not in bindings and parameter not in variadic_bindings
    ]
    if missing:
        return None
    return _template_argument_values_from_parameters(preprocessor, template, bindings)


def _metal_reachable_function_return_types(
    preprocessor: Any,
    source: str,
    template_spans: Sequence[tuple[int, int]],
    reachable_function_spans: Sequence[tuple[int, int]],
) -> dict[str, str]:
    reachable = set(reachable_function_spans)
    return_types: dict[str, str] = {}
    for function in preprocessor._find_non_template_function_definitions(
        source,
        list(template_spans),
    ):
        if function.span not in reachable:
            continue
        return_type = _metal_function_return_type(
            preprocessor,
            _metal_function_header(source, function),
            function.name,
        )
        if return_type:
            return_types[function.name] = return_type
    return return_types


def _materialize_plain_template_helper_calls(
    preprocessor: Any,
    source: str,
) -> tuple[
    str,
    list[dict[str, Any]],
    set[str],
    dict[tuple[str, tuple[str, ...], tuple[str, ...]], str],
]:
    materialized_names: dict[tuple[str, tuple[str, ...], tuple[str, ...]], str] = {}
    specialization_records: list[dict[str, Any]] = []
    materialized_template_names: set[str] = set()
    working = source

    while True:
        templates = preprocessor._find_template_functions(working)
        if not templates:
            return (
                working,
                specialization_records,
                materialized_template_names,
                materialized_names,
            )
        templates_by_name: dict[str, list[Any]] = {}
        for template in templates:
            templates_by_name.setdefault(template.name, []).append(template)
        template_spans = preprocessor._find_template_declaration_spans(working)
        reachable_function_spans = preprocessor._reachable_function_spans(
            working,
            template_spans,
        )
        if not reachable_function_spans:
            return (
                working,
                specialization_records,
                materialized_template_names,
                materialized_names,
            )

        return_types = _metal_reachable_function_return_types(
            preprocessor,
            working,
            template_spans,
            reachable_function_spans,
        )
        functions = preprocessor._find_non_template_function_definitions(
            working,
            template_spans,
        )
        reachable = set(reachable_function_spans)
        replacements: list[tuple[int, int, str]] = []
        new_materializations: list[str] = []

        active_materializations: set[tuple[str, tuple[str, ...], tuple[str, ...]]] = (
            set()
        )

        def ensure_plain_helper(
            function_name: str,
            template: Any,
            arguments: Sequence[str],
            parameter_declarations: Sequence[tuple[str, str, bool]],
        ) -> str:
            specialization_key = preprocessor._template_specialization_key(
                function_name,
                arguments,
            )
            signature_key = tuple(
                _normalize_metal_type_text(type_text)
                for type_text, _name, _variadic in parameter_declarations
            )
            key = (specialization_key[0], specialization_key[1], signature_key)
            materialized_name = materialized_names.get(key)
            if materialized_name is not None:
                return materialized_name

            unique_count = len(materialized_names) + 1
            if len(materialized_names) >= preprocessor.max_template_specializations:
                from crosstl.backend.Metal.preprocessor import (
                    MetalTemplateSpecializationError,
                )

                requested_signature = preprocessor._template_specialization_signature(
                    function_name,
                    arguments,
                )
                suggested_action = (
                    "raise max_template_specializations for this source "
                    "pattern or backend, or reduce inferred template "
                    "helper instantiations"
                )
                raise MetalTemplateSpecializationError(
                    "Metal template specialization limit exceeded while "
                    f"materializing '{requested_signature}'; "
                    f"{unique_count} unique concrete signatures requested, "
                    f"limit {preprocessor.max_template_specializations} "
                    f"from {preprocessor.template_specialization_limit_source}. "
                    f"Suggested action: {suggested_action}.",
                    limit=preprocessor.max_template_specializations,
                    limit_source=(preprocessor.template_specialization_limit_source),
                    unique_specialization_count=unique_count,
                    requested_signature=requested_signature,
                    suggested_action=suggested_action,
                )

            materialized_name = _metal_template_materialized_name(
                preprocessor,
                function_name,
                list(key[1]),
                parameter_declarations,
                materialized_names,
            )
            materialized_names[key] = materialized_name
            parameters = _template_parameter_values_from_arguments(
                preprocessor,
                template,
                list(key[1]),
            )
            specialization_records.append(
                _materialized_template_specialization_record(
                    name=function_name,
                    materialized_name=materialized_name,
                    parameters=parameters,
                    parameter_sources={
                        parameter: "call-site" for parameter in parameters
                    },
                    source="call-site",
                )
            )
            materialized_template_names.add(function_name)

            materialized = preprocessor._materialize_template_function_with_name(
                template,
                list(key[1]),
                materialized_name,
                host_name=None,
            )
            if not materialized:
                return materialized_name

            if key not in active_materializations:
                active_materializations.add(key)
                child_replacements: list[tuple[int, int, str]] = []
                materialized_template_spans = (
                    preprocessor._find_template_declaration_spans(materialized)
                )
                materialized_functions = (
                    preprocessor._find_non_template_function_definitions(
                        materialized,
                        materialized_template_spans,
                    )
                )
                materialized_return_types = {
                    function.name: return_type
                    for function in materialized_functions
                    if (
                        return_type := _metal_function_return_type(
                            preprocessor,
                            _metal_function_header(materialized, function),
                            function.name,
                        )
                    )
                }
                for function in materialized_functions:
                    if function.name != materialized_name:
                        continue
                    type_environment = _metal_function_type_environment(
                        preprocessor,
                        materialized,
                        function,
                        materialized_return_types,
                    )
                    child_calls = _plain_template_helper_call_sites(
                        preprocessor,
                        materialized,
                        templates_by_name,
                        materialized_template_spans,
                        [function.body_span],
                    )
                    for (
                        child_name,
                        child_arguments,
                        child_span,
                        child_template_arguments,
                    ) in child_calls:
                        inferred_matches: list[
                            tuple[Any, list[str], list[tuple[str, str, bool]]]
                        ] = []
                        for child_template in templates_by_name.get(child_name, []):
                            inferred_arguments = _infer_plain_template_helper_arguments(
                                preprocessor,
                                child_template,
                                child_arguments,
                                type_environment,
                                materialized_return_types,
                                child_template_arguments,
                            )
                            if (
                                not inferred_arguments
                                or not preprocessor._template_arguments_satisfy_parameters(
                                    child_template,
                                    inferred_arguments,
                                )
                            ):
                                continue
                            child_parameter_declarations = (
                                _metal_function_parameter_declarations(
                                    preprocessor,
                                    _metal_template_header(child_template),
                                )
                            )
                            inferred_matches.append(
                                (
                                    child_template,
                                    inferred_arguments,
                                    child_parameter_declarations,
                                )
                            )
                        if len(inferred_matches) != 1:
                            continue
                        (
                            child_template,
                            child_arguments,
                            child_parameter_declarations,
                        ) = inferred_matches[0]
                        child_materialized_name = ensure_plain_helper(
                            child_name,
                            child_template,
                            child_arguments,
                            child_parameter_declarations,
                        )
                        child_replacements.append(
                            (
                                child_span[0],
                                child_span[1],
                                child_materialized_name,
                            )
                        )
                if child_replacements:
                    materialized = preprocessor._apply_text_replacements(
                        materialized,
                        child_replacements,
                    )
                active_materializations.remove(key)

            new_materializations.append(materialized)
            return materialized_name

        for function in functions:
            if function.span not in reachable:
                continue
            type_environment = _metal_function_type_environment(
                preprocessor,
                working,
                function,
                return_types,
            )
            calls = _plain_template_helper_call_sites(
                preprocessor,
                working,
                templates_by_name,
                template_spans,
                [function.body_span],
            )
            for function_name, call_arguments, span, template_arguments in calls:
                candidate_templates = templates_by_name.get(function_name, [])
                inferred_matches: list[
                    tuple[Any, list[str], list[tuple[str, str, bool]]]
                ] = []
                for template in candidate_templates:
                    arguments = _infer_plain_template_helper_arguments(
                        preprocessor,
                        template,
                        call_arguments,
                        type_environment,
                        return_types,
                        template_arguments,
                    )
                    if (
                        not arguments
                        or not preprocessor._template_arguments_satisfy_parameters(
                            template,
                            arguments,
                        )
                    ):
                        continue
                    parameter_declarations = _metal_function_parameter_declarations(
                        preprocessor,
                        _metal_template_header(template),
                    )
                    inferred_matches.append(
                        (template, arguments, parameter_declarations)
                    )
                if len(inferred_matches) != 1:
                    continue
                template, arguments, parameter_declarations = inferred_matches[0]
                materialized_name = ensure_plain_helper(
                    function_name,
                    template,
                    arguments,
                    parameter_declarations,
                )
                replacements.append((span[0], span[1], materialized_name))

        if not replacements and not new_materializations:
            return (
                working,
                specialization_records,
                materialized_template_names,
                materialized_names,
            )

        if replacements:
            working = preprocessor._apply_text_replacements(working, replacements)
        if new_materializations:
            working = working.rstrip() + "\n\n" + "\n\n".join(new_materializations)
            if not working.endswith("\n"):
                working += "\n"


def _metal_diagnostic_template_call_noop_replacements(
    preprocessor: Any,
    source: str,
    helper_names: set[str],
    excluded_spans: Sequence[tuple[int, int]],
) -> list[tuple[int, int, str]]:
    replacements: list[tuple[int, int, str]] = []
    i = 0
    excluded = list(excluded_spans)
    while i < len(source):
        if source[i] in "\"'":
            _literal, consumed = preprocessor._read_string(source, i)
            i += consumed
            continue
        if source.startswith("//", i):
            end = source.find("\n", i)
            if end == -1:
                break
            i = end + 1
            continue
        if source.startswith("/*", i):
            end = source.find("*/", i + 2)
            if end == -1:
                break
            i = end + 2
            continue
        span = preprocessor._containing_span(i, excluded)
        if span is not None:
            i = span[1]
            continue
        if source[i].isalpha() or source[i] == "_":
            ident, consumed = preprocessor._read_identifier(source, i)
            if ident not in helper_names or preprocessor._is_member_identifier_context(
                source, i
            ):
                i += consumed
                continue
            call_start = preprocessor._scoped_identifier_start(source, i)
            j = i + consumed
            while j < len(source) and source[j].isspace():
                j += 1
            if j < len(source) and source[j] == "<":
                angle_end = preprocessor._find_matching_angle(source, j)
                if angle_end is None:
                    i += consumed
                    continue
                j = angle_end + 1
                while j < len(source) and source[j].isspace():
                    j += 1
            if j >= len(source) or source[j] != "(":
                i += consumed
                continue
            paren_end = preprocessor._find_matching_delimiter(source, j, "(", ")")
            if paren_end is None:
                i += consumed
                continue
            statement_end = paren_end + 1
            while statement_end < len(source) and source[statement_end].isspace():
                statement_end += 1
            if statement_end < len(source) and source[statement_end] == ";":
                replacements.append((call_start, statement_end + 1, ";"))
                i = statement_end + 1
                continue
            i += consumed
            continue
        i += 1
    return replacements


def _metal_block_spans(preprocessor: Any, source: str) -> list[tuple[int, int]]:
    spans: list[tuple[int, int]] = []
    stack: list[int] = []
    i = 0
    while i < len(source):
        if source[i] in "\"'":
            _literal, consumed = preprocessor._read_string(source, i)
            i += consumed
            continue
        if source.startswith("//", i):
            end = source.find("\n", i)
            if end == -1:
                break
            i = end + 1
            continue
        if source.startswith("/*", i):
            end = source.find("*/", i + 2)
            if end == -1:
                break
            i = end + 2
            continue
        if source[i] == "{":
            stack.append(i)
        elif source[i] == "}" and stack:
            spans.append((stack.pop(), i + 1))
        i += 1
    return spans


def _metal_enclosing_block_end(
    block_spans: Sequence[tuple[int, int]],
    position: int,
) -> int | None:
    enclosing = [span for span in block_spans if span[0] < position < span[1]]
    if not enclosing:
        return None
    return min(enclosing, key=lambda span: span[1] - span[0])[1]


def _metal_statement_semicolon(
    preprocessor: Any,
    source: str,
    start: int,
) -> int | None:
    depths = {"<": 0, "(": 0, "[": 0, "{": 0}
    i = start
    while i < len(source):
        if source[i] in "\"'":
            _literal, consumed = preprocessor._read_string(source, i)
            i += consumed
            continue
        if source.startswith("//", i):
            end = source.find("\n", i)
            if end == -1:
                return None
            i = end + 1
            continue
        if source.startswith("/*", i):
            end = source.find("*/", i + 2)
            if end == -1:
                return None
            i = end + 2
            continue

        character = source[i]
        if character in depths:
            depths[character] += 1
        elif character == ">" and depths["<"] > 0:
            depths["<"] -= 1
        elif character == ")" and depths["("] > 0:
            depths["("] -= 1
        elif character == "]" and depths["["] > 0:
            depths["["] -= 1
        elif character == "}" and depths["{"] > 0:
            depths["{"] -= 1
        elif character == ";" and not any(depths.values()):
            return i
        i += 1
    return None


def _metal_concrete_using_alias_type(alias_type: str) -> str | None:
    alias_type = str(alias_type or "").strip()
    if alias_type.startswith("typename "):
        alias_type = alias_type[len("typename ") :].strip()
    if "<" not in alias_type or ">" not in alias_type:
        return None
    if any(character in alias_type for character in "{};="):
        return None
    return alias_type


def _metal_template_struct_members(
    preprocessor: Any,
    source: str,
) -> dict[str, dict[str, Any]]:
    structs: dict[str, dict[str, Any]] = {}
    pos = 0
    while True:
        match = re.search(r"\btemplate\s*<", source[pos:])
        if match is None:
            break
        start = pos + match.start()
        angle_start = source.find("<", start)
        angle_end = preprocessor._find_matching_angle(source, angle_start)
        if angle_end is None:
            pos = start + len("template")
            continue
        parameter_text = source[angle_start + 1 : angle_end]
        parameters = preprocessor._template_parameter_names(parameter_text)
        struct_match = re.match(
            r"\s*struct\s+([A-Za-z_][A-Za-z0-9_]*)\s*\{",
            source[angle_end + 1 :],
        )
        if struct_match is None:
            pos = angle_end + 1
            continue
        name = struct_match.group(1)
        body_start = angle_end + 1 + struct_match.end() - 1
        body_end = preprocessor._find_matching_brace(source, body_start)
        if body_end is None:
            pos = body_start + 1
            continue
        body = source[body_start + 1 : body_end]
        aliases = {
            alias_match.group("name"): alias_match.group("type").strip()
            for alias_match in re.finditer(
                r"\busing\s+(?P<name>[A-Za-z_][A-Za-z0-9_]*)\s*="
                r"\s*(?P<type>[^;]+);",
                body,
                re.DOTALL,
            )
        }
        constants = {
            constant_match.group("name"): constant_match.group("value").strip()
            for constant_match in re.finditer(
                r"\b(?:static\s+)?(?:constexpr\s+)?(?:constant\s+)?"
                r"(?:const\s+)?[A-Za-z_][A-Za-z0-9_:]*\s+"
                r"(?P<name>[A-Za-z_][A-Za-z0-9_]*)\s*="
                r"\s*(?P<value>[^;]+);",
                body,
                re.DOTALL,
            )
        }
        structs[name] = {
            "parameters": parameters,
            "aliases": aliases,
            "constants": constants,
        }
        pos = body_end + 1
    return structs


def _metal_concrete_template_struct_members(
    preprocessor: Any,
    template_structs: Mapping[str, Mapping[str, Any]],
    concrete_type: str,
) -> dict[str, str]:
    text = str(concrete_type or "").strip()
    if "<" not in text:
        return {}
    name = text.split("<", 1)[0].strip()
    struct = template_structs.get(name)
    if not isinstance(struct, Mapping):
        return {}
    angle_start = text.find("<")
    angle_end = preprocessor._find_matching_angle(text, angle_start)
    if angle_end is None:
        return {}
    arguments = preprocessor._split_top_level_commas(text[angle_start + 1 : angle_end])
    parameters = list(struct.get("parameters") or [])
    substitutions = {
        parameter: arguments[index]
        for index, parameter in enumerate(parameters)
        if index < len(arguments)
    }
    members: dict[str, str] = {}
    for member, value in dict(struct.get("aliases") or {}).items():
        members[str(member)] = preprocessor._replace_identifiers(
            str(value),
            substitutions,
        )
    for member, value in dict(struct.get("constants") or {}).items():
        members[str(member)] = preprocessor._replace_identifiers(
            str(value),
            substitutions,
        )
    return members


def _inline_metal_concrete_using_template_aliases(
    preprocessor: Any,
    source: str,
    excluded_spans: Sequence[tuple[int, int]],
) -> str:
    block_spans = _metal_block_spans(preprocessor, source)
    template_structs = _metal_template_struct_members(preprocessor, source)
    aliases: list[dict[str, Any]] = []
    alias_spans: list[tuple[int, int]] = []
    excluded = list(excluded_spans)
    i = 0
    while i < len(source):
        if source[i] in "\"'":
            _literal, consumed = preprocessor._read_string(source, i)
            i += consumed
            continue
        if source.startswith("//", i):
            end = source.find("\n", i)
            if end == -1:
                break
            i = end + 1
            continue
        if source.startswith("/*", i):
            end = source.find("*/", i + 2)
            if end == -1:
                break
            i = end + 2
            continue
        span = preprocessor._containing_span(i, excluded)
        if span is not None:
            i = span[1]
            continue
        if not (source[i].isalpha() or source[i] == "_"):
            i += 1
            continue

        ident, consumed = preprocessor._read_identifier(source, i)
        if ident != "using":
            i += consumed
            continue

        j = i + consumed
        while j < len(source) and source[j].isspace():
            j += 1
        if j >= len(source) or not (source[j].isalpha() or source[j] == "_"):
            i += consumed
            continue
        alias_name, alias_consumed = preprocessor._read_identifier(source, j)
        j += alias_consumed
        while j < len(source) and source[j].isspace():
            j += 1
        if j >= len(source) or source[j] != "=":
            i += consumed
            continue
        semicolon = _metal_statement_semicolon(preprocessor, source, j + 1)
        if semicolon is None:
            i += consumed
            continue
        raw_alias_type = source[j + 1 : semicolon]
        alias_type = _metal_concrete_using_alias_type(raw_alias_type)
        if alias_type is None:
            dependent_match = re.fullmatch(
                r"\s*typename\s+([A-Za-z_][A-Za-z0-9_]*)::"
                r"([A-Za-z_][A-Za-z0-9_]*)\s*",
                raw_alias_type,
                re.DOTALL,
            )
            if dependent_match is not None:
                owner, member = dependent_match.groups()
                for candidate in reversed(aliases):
                    if candidate["name"] != owner:
                        continue
                    alias_type = (candidate.get("members") or {}).get(member)
                    break
        scope_end = _metal_enclosing_block_end(block_spans, i)
        if alias_type is None or scope_end is None:
            i = semicolon + 1
            continue
        members = _metal_concrete_template_struct_members(
            preprocessor,
            template_structs,
            alias_type,
        )
        aliases.append(
            {
                "name": alias_name,
                "type": alias_type,
                "members": members,
                "start": i,
                "end": semicolon + 1,
                "scope_end": scope_end,
            }
        )
        alias_spans.append((i, semicolon + 1))
        i = semicolon + 1

    if not aliases:
        return source

    replacements: list[tuple[int, int, str]] = [
        (alias["start"], alias["end"], "") for alias in aliases
    ]
    excluded_for_replacement = [*excluded, *alias_spans]
    i = 0
    while i < len(source):
        if source[i] in "\"'":
            _literal, consumed = preprocessor._read_string(source, i)
            i += consumed
            continue
        if source.startswith("//", i):
            end = source.find("\n", i)
            if end == -1:
                break
            i = end + 1
            continue
        if source.startswith("/*", i):
            end = source.find("*/", i + 2)
            if end == -1:
                break
            i = end + 2
            continue
        span = preprocessor._containing_span(i, excluded_for_replacement)
        if span is not None:
            i = span[1]
            continue
        if not (source[i].isalpha() or source[i] == "_"):
            i += 1
            continue
        ident, consumed = preprocessor._read_identifier(source, i)
        qualified_candidates = [
            alias
            for alias in aliases
            if alias["name"] == ident and alias["end"] <= i and i < alias["scope_end"]
        ]
        qualified = None
        if qualified_candidates and source[i + consumed : i + consumed + 2] == "::":
            member_start = i + consumed + 2
            if member_start < len(source) and (
                source[member_start].isalpha() or source[member_start] == "_"
            ):
                member, member_consumed = preprocessor._read_identifier(
                    source,
                    member_start,
                )
                for candidate in reversed(qualified_candidates):
                    qualified = (candidate.get("members") or {}).get(member)
                    if qualified is not None:
                        replacements.append(
                            (i, member_start + member_consumed, str(qualified))
                        )
                        i = member_start + member_consumed
                        break
                if qualified is not None:
                    continue
        candidates = qualified_candidates
        if candidates:
            alias = max(candidates, key=lambda item: int(item["end"]))
            replacements.append((i, i + consumed, str(alias["type"])))
        i += consumed

    return preprocessor._apply_text_replacements(source, replacements)


def _strip_metal_diagnostic_template_helpers(
    preprocessor: Any,
    source: str,
    templates: Sequence[Any],
) -> tuple[str, bool]:
    diagnostic_helpers = [
        template
        for template in templates
        if _is_metal_diagnostic_template_helper(template)
    ]
    if not diagnostic_helpers:
        return source, False

    helper_names = {template.name for template in diagnostic_helpers}
    template_spans = preprocessor._find_template_declaration_spans(source)
    replacements: list[tuple[int, int, str]] = [
        (template.span[0], template.span[1], "") for template in diagnostic_helpers
    ]
    replacements.extend(
        _metal_diagnostic_template_call_noop_replacements(
            preprocessor,
            source,
            helper_names,
            template_spans,
        )
    )
    if not replacements:
        return source, False
    return preprocessor._apply_text_replacements(source, replacements), True


def _template_materialization_metadata(
    *,
    specializations: Sequence[Mapping[str, Any]],
    configured_parameters: Mapping[str, str],
    configured_parameter_sources: Mapping[str, str],
    unsupported: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    return {
        "status": "unsupported" if unsupported else "materialized",
        "specializationCount": len(specializations),
        "configuredParameterCount": len(configured_parameters),
        "configuredParameters": dict(sorted(configured_parameters.items())),
        "configuredParameterSources": dict(
            sorted(configured_parameter_sources.items())
        ),
        "specializations": [dict(specialization) for specialization in specializations],
        "unsupported": [dict(record) for record in unsupported],
    }


def _template_specialization_source(
    parameter_sources: Mapping[str, str],
    *,
    fallback: str,
) -> str:
    sources = {source for source in parameter_sources.values() if source}
    if len(sources) == 1:
        return next(iter(sources))
    for source in ("variant-manifest", "project-variant", "config", "source-default"):
        if source in sources:
            return source
    return fallback


def _template_materialization_unsupported_message(
    target: str,
    unit: ProjectTranslationUnit,
    unsupported: Sequence[Mapping[str, Any]],
) -> str:
    details = []
    for record in unsupported:
        name = record.get("name", "<unknown>")
        missing = record.get("missingParameters", [])
        missing_text = ", ".join(str(parameter) for parameter in missing) or "<none>"
        declaration = record.get("sourceDeclaration", {})
        declaration_text = str(unit.relative_path)
        if isinstance(declaration, Mapping):
            file_name = declaration.get("file")
            line = declaration.get("line")
            column = declaration.get("column")
            if (
                isinstance(file_name, str)
                and file_name
                and isinstance(line, int)
                and isinstance(column, int)
            ):
                declaration_text = f"{file_name}:{line}:{column}"
        signature = record.get("requiredSignature", name)
        if missing:
            details.append(
                f"{name} missing {missing_text} "
                f"(declaration {declaration_text}, target {target}, "
                f"required {signature})"
            )
        else:
            details.append(
                f"{name} has an unmaterialized concrete template functor use "
                f"(declaration {declaration_text}, target {target}, "
                f"required {signature})"
            )
    return (
        f"Template-hostile target '{target}' requires concrete template arguments "
        f"before translating '{unit.relative_path}': " + "; ".join(details)
    )


def _template_materialization_unsupported_location(
    unit: ProjectTranslationUnit,
    unsupported: Sequence[Mapping[str, Any]],
) -> SourceLocation:
    for record in unsupported:
        declaration = record.get("sourceDeclaration")
        if not isinstance(declaration, Mapping):
            continue
        file_name = declaration.get("file")
        line = declaration.get("line")
        column = declaration.get("column")
        if isinstance(file_name, str) and file_name and isinstance(line, int):
            return SourceLocation(
                file=file_name,
                line=line,
                column=column if isinstance(column, int) else 1,
                end_line=line,
                end_column=column if isinstance(column, int) else 1,
            )
    return SourceLocation(file=unit.relative_path)


def _masked_metal_non_code_text(source: str) -> str:
    chars = list(source)
    i = 0
    while i < len(chars):
        if source.startswith("//", i):
            end = source.find("\n", i)
            if end == -1:
                end = len(chars)
            for index in range(i, end):
                chars[index] = " "
            i = end
            continue
        if source.startswith("/*", i):
            end = source.find("*/", i + 2)
            if end == -1:
                end = len(chars) - 2
            for index in range(i, min(end + 2, len(chars))):
                if chars[index] != "\n":
                    chars[index] = " "
            i = end + 2
            continue
        if chars[i] in {"'", '"'}:
            quote = chars[i]
            chars[i] = " "
            i += 1
            while i < len(chars):
                current = chars[i]
                if current != "\n":
                    chars[i] = " "
                if current == "\\":
                    i += 2
                    continue
                i += 1
                if current == quote:
                    break
            continue
        i += 1
    return "".join(chars)


def _metal_template_type_declarations(
    preprocessor: Any,
    unit: ProjectTranslationUnit,
    source: str,
) -> list[_MetalTemplateTypeDeclaration]:
    declarations: list[_MetalTemplateTypeDeclaration] = []
    pos = 0
    while True:
        match = re.search(r"\btemplate\s*<", source[pos:])
        if match is None:
            break
        start = pos + match.start()
        angle_start = source.find("<", start)
        angle_end = preprocessor._find_matching_angle(source, angle_start)
        if angle_end is None:
            pos = start + len("template")
            continue

        parameters = tuple(
            preprocessor._template_parameter_names(source[angle_start + 1 : angle_end])
        )
        declaration_start = angle_end + 1
        header = source[declaration_start : declaration_start + 512]
        declaration_match = re.match(
            r"\s*(?:\[\[[^\]]*\]\]\s*)*"
            r"(?P<kind>struct|class)\s+"
            r"(?P<name>[A-Za-z_][A-Za-z0-9_:]*)\b",
            header,
            re.DOTALL,
        )
        if declaration_match is None or not parameters:
            pos = declaration_start
            continue

        body_start = preprocessor._find_next_top_level_char(
            source,
            declaration_start,
            "{",
        )
        semicolon = preprocessor._find_next_top_level_char(
            source,
            declaration_start,
            ";",
        )
        if body_start is not None and (semicolon is None or body_start < semicolon):
            body_end = preprocessor._find_matching_brace(source, body_start)
            if body_end is None:
                pos = body_start + 1
                continue
            end = body_end
            if end < len(source) and source[end] == ";":
                end += 1
            body = source[body_start + 1 : body_end]
        elif semicolon is not None:
            end = semicolon + 1
            body = ""
        else:
            end = declaration_start + declaration_match.end()
            body = ""

        location = _source_location_at_offset(unit, source, start, max(end - start, 0))
        declarations.append(
            _MetalTemplateTypeDeclaration(
                name=declaration_match.group("name").split("::")[-1],
                parameters=parameters,
                span=(start, end),
                location=location,
                is_functor=re.search(r"\boperator\s*\(\s*\)", body) is not None,
            )
        )
        pos = max(end, declaration_start + 1)
    return declarations


def _source_offset_in_spans(offset: int, spans: Sequence[tuple[int, int]]) -> bool:
    return any(start <= offset < end for start, end in spans)


def _template_argument_missing_parameters(
    argument: str,
    template_parameter_names: set[str],
) -> list[str]:
    missing: list[str] = []
    for token in re.findall(r"[A-Za-z_][A-Za-z0-9_]*", argument):
        if token in template_parameter_names and token not in missing:
            missing.append(token)
    return missing


def _unresolved_metal_template_type_records(
    *,
    preprocessor: Any,
    unit: ProjectTranslationUnit,
    source: str,
    target: str,
) -> list[dict[str, Any]]:
    declarations = _metal_template_type_declarations(preprocessor, unit, source)
    if not declarations:
        return []

    declarations_by_name = {
        declaration.name: declaration for declaration in declarations
    }
    template_parameter_names = {
        parameter
        for declaration in declarations
        for parameter in declaration.parameters
    }
    if not template_parameter_names:
        return []

    declaration_spans = preprocessor._find_template_declaration_spans(source)
    masked_source = _masked_metal_non_code_text(source)
    names_pattern = "|".join(
        re.escape(name) for name in sorted(declarations_by_name, key=len, reverse=True)
    )
    if not names_pattern:
        return []

    records: list[dict[str, Any]] = []
    seen_records: set[tuple[str, tuple[str, ...], str]] = set()
    for match in re.finditer(rf"\b(?P<name>{names_pattern})\s*<", masked_source):
        if _source_offset_in_spans(match.start(), declaration_spans):
            continue
        declaration = declarations_by_name[match.group("name")]
        angle_start = masked_source.find("<", match.start())
        angle_end = preprocessor._find_matching_angle(source, angle_start)
        if angle_end is None:
            continue

        arguments = [
            argument.strip()
            for argument in preprocessor._split_top_level_commas(
                source[angle_start + 1 : angle_end]
            )
        ]
        missing: list[str] = []
        for argument in arguments:
            for parameter in _template_argument_missing_parameters(
                argument,
                template_parameter_names,
            ):
                if parameter not in missing:
                    missing.append(parameter)
        if len(arguments) < len(declaration.parameters):
            for parameter in declaration.parameters[len(arguments) :]:
                if parameter not in missing:
                    missing.append(parameter)
        if not missing:
            continue

        required_signature = (
            f"{declaration.name}<"
            f"{', '.join(arguments) if arguments else ', '.join(declaration.parameters)}"
            ">"
        )
        key = (declaration.name, tuple(missing), required_signature)
        if key in seen_records:
            continue
        seen_records.add(key)
        records.append(
            {
                "name": declaration.name,
                "parameters": list(declaration.parameters),
                "missingParameters": missing,
                "reason": "missing-template-arguments",
                "sourceDeclaration": {
                    "file": declaration.location.file,
                    "line": declaration.location.line,
                    "column": declaration.location.column,
                    "name": declaration.name,
                },
                "target": target,
                "requiredSignature": required_signature,
            }
        )
    return records


def _unmaterialized_metal_template_functor_records(
    *,
    preprocessor: Any,
    unit: ProjectTranslationUnit,
    source: str,
    target: str,
) -> list[dict[str, Any]]:
    declarations = [
        declaration
        for declaration in _metal_template_type_declarations(preprocessor, unit, source)
        if declaration.is_functor
    ]
    if not declarations:
        return []

    declarations_by_name = {
        declaration.name: declaration for declaration in declarations
    }
    names_pattern = "|".join(
        re.escape(name) for name in sorted(declarations_by_name, key=len, reverse=True)
    )
    if not names_pattern:
        return []

    template_parameter_names = {
        parameter
        for declaration in declarations
        for parameter in declaration.parameters
    }
    declaration_spans = preprocessor._find_template_declaration_spans(source)
    masked_source = _masked_metal_non_code_text(source)
    records: list[dict[str, Any]] = []
    seen_records: set[tuple[str, str]] = set()
    for match in re.finditer(rf"\b(?P<name>{names_pattern})\s*<", masked_source):
        if _source_offset_in_spans(match.start(), declaration_spans):
            continue
        declaration = declarations_by_name[match.group("name")]
        angle_start = masked_source.find("<", match.start())
        angle_end = preprocessor._find_matching_angle(source, angle_start)
        if angle_end is None:
            continue
        arguments = [
            argument.strip()
            for argument in preprocessor._split_top_level_commas(
                source[angle_start + 1 : angle_end]
            )
        ]
        missing: list[str] = []
        for argument in arguments:
            for parameter in _template_argument_missing_parameters(
                argument,
                template_parameter_names,
            ):
                if parameter not in missing:
                    missing.append(parameter)
        if missing:
            continue

        required_signature = f"{declaration.name}<{', '.join(arguments)}>"
        key = (declaration.name, required_signature)
        if key in seen_records:
            continue
        seen_records.add(key)
        records.append(
            {
                "name": declaration.name,
                "parameters": list(declaration.parameters),
                "missingParameters": [],
                "reason": "missing-template-arguments",
                "sourceDeclaration": {
                    "file": declaration.location.file,
                    "line": declaration.location.line,
                    "column": declaration.location.column,
                    "name": declaration.name,
                },
                "target": target,
                "requiredSignature": required_signature,
            }
        )
    return records


def _project_template_materialization_for_artifact(
    *,
    unit: ProjectTranslationUnit,
    target: str,
    variant: str | None,
    defines: Mapping[str, str],
    define_sources: Mapping[str, str] | None = None,
    include_paths: Sequence[str],
    source_options: Mapping[str, Any],
) -> ProjectTemplateMaterializedSource | None:
    if unit.source_backend != "metal" or not _is_template_hostile_target(target):
        return None

    try:
        source = unit.path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return None
    if "template" not in source and "#include" not in source:
        return None

    from crosstl.backend.Metal.preprocessor import (
        MetalPreprocessor,
        MetalTemplateSpecializationError,
    )

    base_preprocessor_kwargs: dict[str, Any] = {
        "include_paths": list(include_paths),
    }
    if "strict_preprocessor" in source_options:
        base_preprocessor_kwargs["strict"] = bool(source_options["strict_preprocessor"])
    if "max_template_specializations" in source_options:
        base_preprocessor_kwargs["max_template_specializations"] = source_options[
            "max_template_specializations"
        ]
    if "template_specialization_limit_source" in source_options:
        base_preprocessor_kwargs["template_specialization_limit_source"] = (
            source_options["template_specialization_limit_source"]
        )
    materialization_work_limit = _metal_template_materialization_work_limit(
        source_options
    )
    materialization_work_limit_source = (
        _metal_template_materialization_work_limit_source(source_options)
    )

    try:
        discovery_preprocessor = MetalPreprocessor(
            **base_preprocessor_kwargs,
            defines={},
        )
        discovery_source = _metal_preprocess_without_template_materialization(
            discovery_preprocessor,
            source,
            file_path=str(unit.path),
        )
    except Exception:  # noqa: BLE001
        return None

    source_template_parameters = _metal_template_parameter_names(discovery_source)
    unresolved_type_records = _unresolved_metal_template_type_records(
        preprocessor=discovery_preprocessor,
        unit=unit,
        source=discovery_source,
        target=target,
    )
    unmaterialized_functor_records = _unmaterialized_metal_template_functor_records(
        preprocessor=discovery_preprocessor,
        unit=unit,
        source=discovery_source,
        target=target,
    )
    unsupported_type_records = [
        *unresolved_type_records,
        *unmaterialized_functor_records,
    ]
    if not source_template_parameters and not unsupported_type_records:
        return None

    configured_parameters = {
        name: str(defines[name])
        for name in sorted(source_template_parameters)
        if name in defines
    }
    configured_parameter_sources = {
        name: (
            str(define_sources.get(name, "config"))
            if define_sources is not None
            else "config"
        )
        for name in configured_parameters
    }
    parser_defines = {
        name: str(value)
        for name, value in defines.items()
        if name not in configured_parameters
    }
    if unsupported_type_records:
        metadata = _template_materialization_metadata(
            specializations=[],
            configured_parameters={},
            configured_parameter_sources={},
            unsupported=unsupported_type_records,
        )
        message = _template_materialization_unsupported_message(
            target,
            unit,
            unsupported_type_records,
        )
        return ProjectTemplateMaterializedSource(
            text=discovery_source,
            metadata=metadata,
            defines=parser_defines,
            source_options={
                **_frontend_source_options(source_options),
                "preprocess": False,
            },
            diagnostics=[
                ProjectDiagnostic(
                    severity="error",
                    code="project.translate.template-materialization-unsupported",
                    message=message,
                    location=_template_materialization_unsupported_location(
                        unit,
                        unsupported_type_records,
                    ),
                    target=target,
                    source_backend=unit.source_backend,
                    variant=variant,
                    missing_capabilities=["template.specialization"],
                )
            ],
            blocked=True,
            error=message,
        )

    preprocessor = MetalPreprocessor(
        **base_preprocessor_kwargs,
        defines=parser_defines,
    )
    try:
        preprocessed = _metal_preprocess_without_template_materialization(
            preprocessor,
            source,
            file_path=str(unit.path),
        )
        templates = preprocessor._find_template_functions(preprocessed)
    except Exception:  # noqa: BLE001
        return None
    if not templates:
        return None
    preprocessed, stripped_diagnostic_helpers = (
        _strip_metal_diagnostic_template_helpers(
            preprocessor,
            preprocessed,
            templates,
        )
    )
    if stripped_diagnostic_helpers:
        templates = preprocessor._find_template_functions(preprocessed)

    specializations: list[dict[str, Any]] = []
    source_instantiation_unsupported: list[dict[str, Any]] = []
    source_instantiation_partial_templates: set[str] = set()
    template_lookup = {template.name: template for template in templates}
    source_instantiations = preprocessor._find_project_template_instantiations(
        preprocessed
    )
    if target == "opengl" and source_instantiations:
        materialization_work_items = len(source_instantiations) * max(
            1,
            len(templates),
        )
        if materialization_work_items > materialization_work_limit:
            first_instantiation = source_instantiations[0]
            first_template = template_lookup.get(first_instantiation.function_name)
            if first_template is not None:
                location = _source_location_at_offset(
                    unit,
                    preprocessed,
                    int(first_template.span[0]),
                    max(int(first_template.span[1]) - int(first_template.span[0]), 0),
                )
                location_kind = "source declaration"
            else:
                location = _source_location_at_offset(
                    unit,
                    preprocessed,
                    int(first_instantiation.span[0]),
                    max(
                        int(first_instantiation.span[1])
                        - int(first_instantiation.span[0]),
                        0,
                    ),
                )
                location_kind = "source instantiation"
            requested_signature = (
                f"{len(source_instantiations)} source instantiations x "
                f"{len(templates)} templates"
            )
            suggested_action = (
                "raise max_template_materialization_work for this source pattern "
                "or OpenGL target, or reduce source template instantiations"
            )
            raise MetalTemplateSpecializationError(
                "OpenGL Metal template materialization work limit exceeded before "
                f"GLSL codegen for '{unit.relative_path}'; "
                f"{materialization_work_items} source-instantiation/template work "
                f"items requested ({requested_signature}), limit "
                f"{materialization_work_limit} from "
                f"{materialization_work_limit_source}. "
                f"First {location_kind}: "
                f"{location.file}:{location.line}:{location.column}. "
                f"Suggested action: {suggested_action}.",
                limit=materialization_work_limit,
                limit_source=materialization_work_limit_source,
                requested_signature=requested_signature,
                suggested_action=suggested_action,
                source_location=location,
            )
    source_instantiation_contexts: list[_SourceInstantiationTemplateContext] = []
    source_instantiation_materialized_names: dict[tuple[str, tuple[str, ...]], str] = {}
    seen_source_instantiations: set[tuple[str, tuple[str, ...], str]] = set()
    seen_unsupported_source_instantiations: set[
        tuple[str, tuple[tuple[str, str], ...], str]
    ] = set()
    for instantiation in source_instantiations:
        template = template_lookup.get(instantiation.function_name)
        if template is None:
            continue
        raw_arguments = list(instantiation.template_arguments)
        arguments = preprocessor._template_arguments_with_defaults(
            preprocessed,
            template,
            raw_arguments,
        )
        normalized_arguments = list(
            preprocessor._template_specialization_key(
                instantiation.function_name,
                arguments,
            )[1]
        )
        parameters = _template_parameter_values_from_arguments(
            preprocessor,
            template,
            normalized_arguments,
        )
        if not preprocessor._template_arguments_satisfy_parameters(
            template,
            arguments,
        ):
            source_instantiation_partial_templates.add(template.name)
            required_signature = _template_required_signature(
                preprocessor,
                template,
                parameters,
            )
            unsupported_key = (
                template.name,
                tuple(sorted(parameters.items())),
                required_signature,
            )
            if unsupported_key in seen_unsupported_source_instantiations:
                continue
            seen_unsupported_source_instantiations.add(unsupported_key)
            source_instantiation_unsupported.append(
                _unsupported_template_record(
                    name=template.name,
                    parameters=template.template_parameters,
                    configured_parameters=parameters,
                    source_declaration=_template_source_declaration_record(
                        unit,
                        preprocessed,
                        template,
                    ),
                    target=target,
                    required_signature=required_signature,
                )
            )
            continue
        key = (
            instantiation.function_name,
            tuple(normalized_arguments),
            instantiation.host_name,
        )
        if key in seen_source_instantiations:
            continue
        seen_source_instantiations.add(key)
        materialized_name = preprocessor._materialized_function_identifier(
            instantiation.host_name,
            template.name,
        )
        parameter_sources = _template_parameter_sources_from_arguments(
            template,
            raw_arguments,
            argument_source="source-instantiation",
            default_source="source-default",
        )
        parameter_sources = {
            parameter: parameter_sources[parameter] for parameter in parameters
        }
        specializations.append(
            _materialized_template_specialization_record(
                name=template.name,
                materialized_name=materialized_name,
                parameters=parameters,
                parameter_sources=parameter_sources,
                source="source-instantiation",
                host_name=instantiation.host_name,
            )
        )
        source_instantiation_contexts.append(
            _SourceInstantiationTemplateContext(
                template=template,
                materialized_name=materialized_name,
                parameters=parameters,
                parameter_sources=parameter_sources,
            )
        )
        if not _is_metal_entry_template(template):
            source_instantiation_materialized_names[
                preprocessor._template_specialization_key(
                    instantiation.function_name,
                    normalized_arguments,
                )
            ] = materialized_name
    preprocessed = preprocessor._materialize_project_template_instantiations(
        preprocessed
    )

    templates = preprocessor._find_template_functions(preprocessed)
    templates_by_name = {template.name: template for template in templates}
    template_spans = preprocessor._find_template_declaration_spans(preprocessed)
    reachable_function_spans = preprocessor._reachable_function_spans(
        preprocessed, template_spans
    )
    explicit_specialization_keys = (
        preprocessor._find_explicit_template_specialization_keys(preprocessed)
    )
    calls = preprocessor._find_explicit_template_function_calls(
        preprocessed,
        templates_by_name,
        template_spans,
        explicit_specialization_keys,
        reachable_function_spans,
    )

    explicit_template_names: set[str] = set()
    seen_call_specializations: set[tuple[str, tuple[str, ...]]] = set()
    call_site_materialized_names: dict[tuple[str, tuple[str, ...]], str] = {}
    for function_name, arguments, _span in calls:
        template = templates_by_name.get(function_name)
        if template is None or not preprocessor._template_arguments_satisfy_parameters(
            template,
            list(arguments),
        ):
            continue
        key = preprocessor._template_specialization_key(function_name, arguments)
        if key in seen_call_specializations:
            continue
        seen_call_specializations.add(key)
        explicit_template_names.add(function_name)
        normalized_arguments = list(key[1])
        materialized_name = preprocessor._template_specialization_identifier(
            function_name,
            normalized_arguments,
        )
        call_site_materialized_names[key] = materialized_name
        parameters = _template_parameter_values_from_arguments(
            preprocessor,
            template,
            normalized_arguments,
        )
        parameter_sources = {parameter: "call-site" for parameter in parameters}
        specializations.append(
            _materialized_template_specialization_record(
                name=function_name,
                materialized_name=materialized_name,
                parameters=parameters,
                parameter_sources=parameter_sources,
                source="call-site",
            )
        )

    try:
        materialized = preprocessor._materialize_explicit_template_function_calls(
            preprocessed
        )
    except MetalTemplateSpecializationError:
        raise
    except Exception:  # noqa: BLE001
        return None

    implicit_materialization = _materialize_implicit_template_function_calls(
        preprocessor=preprocessor,
        materialized=materialized,
        source_contexts=source_instantiation_contexts,
        unit=unit,
        target=target,
        work_limit=materialization_work_limit,
        work_limit_source=materialization_work_limit_source,
    )
    materialized = implicit_materialization.text
    specializations.extend(implicit_materialization.specializations)

    inherited_materialization = _materialize_inherited_source_template_helpers(
        preprocessor=preprocessor,
        materialized=materialized,
        templates_by_name=template_lookup,
        source_contexts=source_instantiation_contexts,
        existing_materialized_names={
            **source_instantiation_materialized_names,
            **call_site_materialized_names,
        },
    )
    materialized = inherited_materialization.text
    specializations.extend(inherited_materialization.specializations)
    inherited_template_names = inherited_materialization.template_names

    (
        materialized,
        inferred_plain_specializations,
        inferred_plain_template_names,
        _inferred_plain_materialized_names,
    ) = _materialize_plain_template_helper_calls(
        preprocessor,
        materialized,
    )
    specializations.extend(inferred_plain_specializations)

    replacements: list[tuple[int, int, str]] = []
    unsupported: list[dict[str, Any]] = list(source_instantiation_unsupported)
    used_configured_parameters: dict[str, str] = {}
    used_configured_parameter_sources: dict[str, str] = {}
    default_call_replacements: dict[str, str] = {}
    materialized_call_replacements: dict[str, str] = {}
    current_template_spans = preprocessor._find_template_declaration_spans(materialized)
    current_reachable_function_spans = preprocessor._reachable_function_spans(
        materialized,
        current_template_spans,
    )
    remaining_templates = preprocessor._find_template_functions(materialized)
    reachable_template_names = _reachable_metal_template_function_names(
        preprocessor,
        materialized,
        remaining_templates,
        current_template_spans,
        current_reachable_function_spans,
    )
    for template in remaining_templates:
        if (
            template.name in explicit_template_names
            or template.name in inherited_template_names
            or template.name in inferred_plain_template_names
        ):
            replacements.append((template.span[0], template.span[1], ""))
            continue
        if (
            current_reachable_function_spans
            and template.name not in reachable_template_names
        ):
            replacements.append((template.span[0], template.span[1], ""))
            continue
        if template.name in source_instantiation_partial_templates:
            continue
        default_parameters = _metal_template_parameter_defaults(
            preprocessor,
            materialized,
            template,
            configured_parameters,
        )
        base_parameters = {
            **default_parameters,
            **configured_parameters,
        }
        base_parameter_sources = {
            **{parameter: "source-default" for parameter in default_parameters},
            **configured_parameter_sources,
        }
        required_signature = _template_required_signature(
            preprocessor,
            template,
            base_parameters,
        )
        manifest_parameters = _template_variant_parameter_bindings(
            source_options=source_options,
            target=target,
            relative_path=unit.relative_path,
            template_name=template.name,
            required_signature=required_signature,
        )
        available_parameters = {
            **base_parameters,
            **manifest_parameters,
        }
        available_parameter_sources = {
            **base_parameter_sources,
            **{parameter: "variant-manifest" for parameter in manifest_parameters},
        }
        if all(
            parameter in available_parameters
            for parameter in template.template_parameters
        ):
            arguments = _template_argument_values_from_parameters(
                preprocessor,
                template,
                available_parameters,
            )
            has_configured_parameters = any(
                parameter in configured_parameters
                for parameter in template.template_parameters
            )
            has_manifest_parameters = any(
                parameter in manifest_parameters
                for parameter in template.template_parameters
            )
            if has_configured_parameters or has_manifest_parameters:
                materialized_name = template.name
            else:
                materialized_name = preprocessor._template_specialization_identifier(
                    template.name,
                    arguments,
                )
                default_call_replacements[template.name] = materialized_name
            materialized_call_replacements[template.name] = materialized_name
            materialized_source = preprocessor._materialize_template_function_with_name(
                template,
                arguments,
                materialized_name,
                host_name=None,
            )
            replacements.append(
                (template.span[0], template.span[1], materialized_source)
            )
            parameters = {
                parameter: available_parameters[parameter]
                for parameter in template.template_parameters
            }
            parameter_sources = {
                parameter: available_parameter_sources[parameter]
                for parameter in template.template_parameters
            }
            source_kind = _template_specialization_source(
                parameter_sources,
                fallback=(
                    "variant-manifest"
                    if has_manifest_parameters
                    else "config" if has_configured_parameters else "source-default"
                ),
            )
            used_configured_parameters.update(
                {
                    parameter: configured_parameters[parameter]
                    for parameter in template.template_parameters
                    if parameter in configured_parameters
                }
            )
            used_configured_parameters.update(
                {
                    parameter: manifest_parameters[parameter]
                    for parameter in template.template_parameters
                    if parameter in manifest_parameters
                }
            )
            used_configured_parameter_sources.update(
                {
                    parameter: configured_parameter_sources[parameter]
                    for parameter in template.template_parameters
                    if parameter in configured_parameter_sources
                }
            )
            used_configured_parameter_sources.update(
                {
                    parameter: "variant-manifest"
                    for parameter in template.template_parameters
                    if parameter in manifest_parameters
                }
            )
            specializations.append(
                _materialized_template_specialization_record(
                    name=template.name,
                    materialized_name=materialized_name,
                    parameters=parameters,
                    parameter_sources=parameter_sources,
                    source=source_kind,
                )
            )
            continue
        unsupported.append(
            _unsupported_template_record(
                name=template.name,
                parameters=template.template_parameters,
                configured_parameters=available_parameters,
                source_declaration=_template_source_declaration_record(
                    unit,
                    materialized,
                    template,
                ),
                target=target,
                required_signature=_template_required_signature(
                    preprocessor,
                    template,
                    available_parameters,
                ),
            )
        )

    if default_call_replacements:
        replacements.extend(
            _plain_template_call_replacements(
                preprocessor,
                materialized,
                default_call_replacements,
                current_template_spans,
                current_reachable_function_spans,
            )
        )
    if replacements:
        materialized = preprocessor._apply_text_replacements(materialized, replacements)
    if materialized_call_replacements:
        remaining_template_spans = preprocessor._find_template_declaration_spans(
            materialized
        )
        remaining_reachable_function_spans = preprocessor._reachable_function_spans(
            materialized,
            remaining_template_spans,
        )
        explicit_replacements = _explicit_template_call_replacements(
            preprocessor,
            materialized,
            materialized_call_replacements,
            remaining_template_spans,
            remaining_reachable_function_spans,
        )
        if explicit_replacements:
            materialized = preprocessor._apply_text_replacements(
                materialized, explicit_replacements
            )
    materialized = _inline_metal_concrete_using_template_aliases(
        preprocessor,
        materialized,
        preprocessor._find_template_declaration_spans(materialized),
    )
    if not materialized.endswith("\n"):
        materialized += "\n"

    configured_payload = {
        name: used_configured_parameters[name]
        for name in sorted(used_configured_parameters)
    }
    configured_source_payload = {
        name: used_configured_parameter_sources[name]
        for name in sorted(used_configured_parameter_sources)
    }
    metadata = _template_materialization_metadata(
        specializations=specializations,
        configured_parameters=configured_payload,
        configured_parameter_sources=configured_source_payload,
        unsupported=unsupported,
    )
    if not specializations and not unsupported and not stripped_diagnostic_helpers:
        return None

    if unsupported:
        message = _template_materialization_unsupported_message(
            target, unit, unsupported
        )
        diagnostics = [
            ProjectDiagnostic(
                severity="error",
                code="project.translate.template-materialization-unsupported",
                message=message,
                location=_template_materialization_unsupported_location(
                    unit,
                    unsupported,
                ),
                target=target,
                source_backend=unit.source_backend,
                variant=variant,
                missing_capabilities=["template.specialization"],
            )
        ]
        return ProjectTemplateMaterializedSource(
            text=materialized,
            metadata=metadata,
            defines=parser_defines,
            source_options={
                **_frontend_source_options(source_options),
                "preprocess": False,
            },
            diagnostics=diagnostics,
            blocked=True,
            error=message,
        )

    return ProjectTemplateMaterializedSource(
        text=materialized,
        metadata=metadata,
        defines=parser_defines,
        source_options={
            **_frontend_source_options(source_options),
            "preprocess": False,
        },
    )


def _translation_failure_diagnostic_code(exc: Exception) -> str:
    code = getattr(exc, "project_diagnostic_code", None)
    return code if _is_non_empty_string(code) else "project.translate.failed"


def _is_directx_unresolved_type_attribute_error(exc: Exception, target: str) -> bool:
    return (
        target == "directx"
        and isinstance(exc, AttributeError)
        and "'NoneType' object has no attribute 'startswith'" in str(exc)
    )


def _translation_failure_message(
    exc: Exception,
    target: str,
    unit: ProjectTranslationUnit,
    artifact_path: str | None = None,
) -> str:
    if _is_directx_unresolved_type_attribute_error(exc, target):
        return (
            "DirectX translation could not resolve source type metadata while "
            f"translating '{unit.relative_path}'. Affected function or declaration "
            "could not be determined before DirectX codegen reached an internal "
            "type check."
        )
    metal_template_message = _metal_template_failure_message(
        exc,
        target,
        unit,
        artifact_path,
    )
    if metal_template_message is not None:
        return metal_template_message
    return str(exc)


def _translation_failure_code(exc: Exception, target: str) -> str:
    if _is_directx_unresolved_type_attribute_error(exc, target):
        return "project.translate.unresolved-source-type"
    return _translation_failure_diagnostic_code(exc)


def _translation_failure_missing_capabilities(
    exc: Exception, target: str | None = None
) -> list[str]:
    if target is not None and _is_directx_unresolved_type_attribute_error(exc, target):
        return ["directx.type-inference"]
    capabilities = getattr(exc, "missing_capabilities", None)
    if isinstance(capabilities, str):
        return [capabilities]
    if capabilities:
        return [str(capability) for capability in capabilities]
    return ["batch.translation"]


def _translation_failure_project_diagnostics(
    exc: Exception,
    target: str,
    unit: ProjectTranslationUnit,
    variant: str | None,
    message: str,
) -> list[ProjectDiagnostic]:
    contracts = getattr(exc, "contracts", None)
    if contracts:
        diagnostics: list[ProjectDiagnostic] = []
        location = _translation_failure_location(exc, unit)
        for contract in contracts:
            code = getattr(contract, "code", None)
            if not _is_non_empty_string(code):
                code = _translation_failure_code(exc, target)
            format_message = getattr(contract, "format_project_message", None)
            if callable(format_message):
                diagnostic_message = format_message(target)
            else:
                diagnostic_message = str(contract)
            capabilities = getattr(contract, "missing_capabilities", None)
            if isinstance(capabilities, str):
                missing_capabilities = [capabilities]
            elif capabilities:
                missing_capabilities = [str(capability) for capability in capabilities]
            else:
                missing_capabilities = _translation_failure_missing_capabilities(
                    exc, target
                )
            diagnostics.append(
                ProjectDiagnostic(
                    severity="error",
                    code=code,
                    message=diagnostic_message,
                    location=location,
                    target=target,
                    source_backend=unit.source_backend,
                    variant=variant,
                    missing_capabilities=missing_capabilities,
                )
            )
        return diagnostics

    return [
        ProjectDiagnostic(
            severity="error",
            code=_translation_failure_code(exc, target),
            message=message,
            location=_translation_failure_location(exc, unit),
            target=target,
            source_backend=unit.source_backend,
            variant=variant,
            missing_capabilities=_translation_failure_missing_capabilities(exc, target),
        )
    ]


def _is_metal_template_failure(exc: Exception, unit: ProjectTranslationUnit) -> bool:
    return (
        unit.source_backend == "metal"
        and _translation_failure_diagnostic_code(exc)
        == "project.translate.opengl-template-type-unresolved"
    )


def _metal_template_missing_binding(exc: Exception) -> str | None:
    message = str(exc)
    match = re.search(r"unresolved template type '([^']+)'", message)
    if match is not None:
        return match.group(1)
    match = re.search(r"generic function '([^']+)'", message)
    if match is not None:
        return match.group(1)
    return None


def _metal_template_failure_function(exc: Exception) -> str | None:
    match = re.search(r"generic function '([^']+)'", str(exc))
    return match.group(1) if match is not None else None


def _split_template_parameters(text: str) -> list[str]:
    parts: list[str] = []
    current: list[str] = []
    depth = 0
    pairs = {"<": ">", "(": ")", "[": "]", "{": "}"}
    closers = set(pairs.values())
    for character in text:
        if character in pairs:
            depth += 1
        elif character in closers and depth > 0:
            depth -= 1
        if character == "," and depth == 0:
            part = "".join(current).strip()
            if part:
                parts.append(part)
            current = []
            continue
        current.append(character)
    part = "".join(current).strip()
    if part:
        parts.append(part)
    return parts


def _metal_template_parameter_name(parameter: str) -> str | None:
    parameter = parameter.split("=", 1)[0].strip()
    tokens = re.findall(r"[A-Za-z_][A-Za-z0-9_]*", parameter)
    if not tokens:
        return None
    if tokens[0] in {"typename", "class"} and len(tokens) >= 2:
        return tokens[-1]
    if len(tokens) >= 2:
        return tokens[-1]
    return None


def _source_location_at_offset(
    unit: ProjectTranslationUnit, text: str, offset: int, length: int
) -> SourceLocation:
    prefix = text[:offset]
    line = prefix.count("\n") + 1
    previous_newline = prefix.rfind("\n")
    column = offset + 1 if previous_newline == -1 else offset - previous_newline
    end_line, end_column = _advance_source_position(
        text[offset : offset + length],
        line,
        column,
    )
    return SourceLocation(
        file=unit.relative_path,
        line=line,
        column=column,
        offset=offset,
        length=length,
        end_line=end_line,
        end_column=end_column,
        end_offset=offset + length,
    )


def _metal_template_declaration_context(
    exc: Exception, unit: ProjectTranslationUnit
) -> dict[str, Any] | None:
    if not _is_metal_template_failure(exc, unit):
        return None
    try:
        text = unit.path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return None

    function_name = _metal_template_failure_function(exc)
    missing_binding = _metal_template_missing_binding(exc)
    pattern = re.compile(
        r"\btemplate\s*<(?P<params>.*?)>\s*"
        r"(?P<header>(?:(?!\btemplate\b).){0,1200}?)"
        r"\b(?P<name>[A-Za-z_][A-Za-z0-9_]*)\s*(?:<[^;{}()]*>)?\s*\(",
        re.DOTALL,
    )
    fallback = None
    for match in pattern.finditer(text):
        name = match.group("name")
        params = [
            name
            for name in (
                _metal_template_parameter_name(part)
                for part in _split_template_parameters(match.group("params"))
            )
            if name
        ]
        if function_name and name != function_name:
            continue
        if missing_binding and not function_name and missing_binding not in params:
            continue
        location = _source_location_at_offset(
            unit,
            text,
            match.start(),
            max(match.end() - match.start(), 0),
        )
        context = {
            "name": name,
            "parameters": params,
            "location": location,
        }
        if function_name or missing_binding in params:
            return context
        if fallback is None:
            fallback = context
    return fallback


def _metal_template_failure_message(
    exc: Exception,
    target: str,
    unit: ProjectTranslationUnit,
    artifact_path: str | None,
) -> str | None:
    context = _metal_template_declaration_context(exc, unit)
    if context is None and not _is_metal_template_failure(exc, unit):
        return None
    missing_binding = _metal_template_missing_binding(exc)
    if missing_binding is None and context is not None:
        missing_binding = ", ".join(context.get("parameters", ())) or None

    parts = [str(exc)]
    if missing_binding:
        parts.append(f"Missing template binding: {missing_binding}.")
    if context is not None:
        location = context["location"]
        declaration_name = context.get("name") or "<unknown>"
        parts.append(
            "Source declaration: "
            f"{declaration_name} at {location.file}:{location.line}:{location.column}."
        )
    else:
        parts.append(f"Source declaration: not found in {unit.relative_path}.")
    if artifact_path:
        parts.append(f"Target artifact: {artifact_path}.")
    parts.append(
        "Suggested action: add a concrete Metal template instantiation, supply "
        f"explicit template arguments, or specialize the source before {target} "
        "generation."
    )
    return " ".join(parts)


def _translation_source_location_value(location: Any, *names: str) -> Any:
    if isinstance(location, Mapping):
        for name in names:
            if name in location:
                return location[name]
        return None

    for name in names:
        if hasattr(location, name):
            return getattr(location, name)
    return None


def _translation_source_location_int(value: Any, default: int) -> int:
    if isinstance(value, bool):
        return default
    try:
        converted = int(value)
    except (TypeError, ValueError):
        return default
    return converted if converted >= 0 else default


def _translation_source_location_file(value: Any, unit: ProjectTranslationUnit) -> str:
    if not isinstance(value, str) or not value.strip():
        return unit.relative_path

    normalized = value.strip().replace("\\", "/")
    if PureWindowsPath(value).is_absolute() or PurePosixPath(normalized).is_absolute():
        return unit.relative_path
    if any(part in {"", ".", ".."} for part in PurePosixPath(normalized).parts):
        return unit.relative_path
    return normalized


def _translation_failure_location(
    exc: Exception, unit: ProjectTranslationUnit
) -> SourceLocation:
    source_location = getattr(exc, "source_location", None)
    if isinstance(source_location, SourceLocation):
        file_name = _translation_source_location_file(source_location.file, unit)
        if file_name == source_location.file:
            return source_location
        return replace(source_location, file=file_name)
    if source_location is None:
        context = _metal_template_declaration_context(exc, unit)
        if context is not None:
            return context["location"]
        return SourceLocation(file=unit.relative_path)

    file_name = _translation_source_location_file(
        _translation_source_location_value(source_location, "file"), unit
    )

    line = max(
        1,
        _translation_source_location_int(
            _translation_source_location_value(source_location, "line"), 1
        ),
    )
    column = max(
        1,
        _translation_source_location_int(
            _translation_source_location_value(source_location, "column"), 1
        ),
    )
    end_line = max(
        line,
        _translation_source_location_int(
            _translation_source_location_value(source_location, "end_line", "endLine"),
            line,
        ),
    )
    end_column = max(
        1,
        _translation_source_location_int(
            _translation_source_location_value(
                source_location, "end_column", "endColumn"
            ),
            column,
        ),
    )
    return SourceLocation(
        file=file_name,
        line=line,
        column=column,
        offset=_translation_source_location_int(
            _translation_source_location_value(source_location, "offset"), 0
        ),
        length=_translation_source_location_int(
            _translation_source_location_value(source_location, "length"), 0
        ),
        end_line=end_line,
        end_column=end_column,
        end_offset=_translation_source_location_int(
            _translation_source_location_value(
                source_location, "end_offset", "endOffset"
            ),
            0,
        ),
    )


def translate_project(
    config_or_root: ProjectConfig | str | os.PathLike[str],
    *,
    targets: Sequence[str] | str | None = None,
    output_dir: str | os.PathLike[str] | None = None,
    variants: Sequence[str] | str | None = None,
    format_output: bool = False,
    validate: bool = False,
    run_toolchains: bool = False,
) -> ProjectPortabilityReport:
    """Translate all discovered project units to one or more target backends."""
    format_output = _bool_arg(format_output, field_name="format_output")
    validate = _bool_arg(validate, field_name="validate")
    run_toolchains = _bool_arg(run_toolchains, field_name="run_toolchains")
    config = (
        config_or_root
        if isinstance(config_or_root, ProjectConfig)
        else load_project_config(config_or_root)
    )
    if output_dir is not None:
        output_dir = _path_string_arg(output_dir, field_name="output_dir")
        if not output_dir.strip():
            raise ValueError("output_dir must be a non-empty string")
        config = ProjectConfig(
            root=config.root,
            config_path=config.config_path,
            source_roots=config.source_roots,
            include_patterns=config.include_patterns,
            exclude_patterns=config.exclude_patterns,
            targets=config.targets,
            output_dir=output_dir,
            source_overrides=config.source_overrides,
            include_dirs=config.include_dirs,
            defines=config.defines,
            source_options=config.source_options,
            variants=config.variants,
            selected_variants=config.selected_variants,
            external_corpus_manifest=config.external_corpus_manifest,
        )
    config = _config_with_selected_variants(config, variants)

    selected_targets = _normalized_targets(
        targets if targets is not None else config.targets
    )
    if not selected_targets:
        selected_targets = ["cgl"]

    scan = scan_project(config)
    config = scan.config
    diagnostics: list[ProjectDiagnostic] = list(scan.diagnostics)
    diagnostics.extend(_target_diagnostics(config, selected_targets))
    artifacts: list[dict[str, Any]] = []
    include_paths = _frontend_include_dirs(config)
    output_dir_blocked = _has_error_diagnostic(
        diagnostics, OUTPUT_DIR_OUTSIDE_PROJECT_CODE
    )

    variant_jobs = _variant_jobs(config)
    max_define_count = max(
        (len(defines) for _variant, defines in variant_jobs), default=0
    )
    define_forwarding_diagnostics: set[str] = set()
    include_path_forwarding_diagnostics: set[str] = set()
    preserve_source_suffix = _artifact_source_suffix_pairs(scan.units, selected_targets)

    for unit in scan.units:
        required_capabilities = _required_capabilities_for_unit(unit)
        source_supports_defines = _source_frontend_supports_lexer_keyword(
            unit.source_backend, "defines"
        )
        source_supports_include_paths = _source_frontend_supports_lexer_keyword(
            unit.source_backend, "include_paths"
        )
        if (
            max_define_count > 0
            and not source_supports_defines
            and unit.source_backend not in define_forwarding_diagnostics
        ):
            diagnostics.append(
                _frontend_define_forwarding_diagnostic(unit, max_define_count)
            )
            define_forwarding_diagnostics.add(unit.source_backend)
        if (
            include_paths
            and not source_supports_include_paths
            and unit.source_backend not in include_path_forwarding_diagnostics
        ):
            diagnostics.append(
                _frontend_include_path_forwarding_diagnostic(
                    unit,
                    len(include_paths),
                )
            )
            include_path_forwarding_diagnostics.add(unit.source_backend)
        for target in selected_targets:
            for variant, defines in variant_jobs:
                artifact_include_dependencies = _include_dependencies_for_artifact(
                    unit.include_dependencies,
                    variant,
                )
                output_path = _artifact_path(
                    config,
                    unit,
                    target,
                    variant,
                    preserve_source_suffix=(unit.relative_path, target)
                    in preserve_source_suffix,
                )
                artifact = {
                    "source": unit.relative_path,
                    "sourceBackend": unit.source_backend,
                    "target": target,
                    "path": _artifact_report_path(output_path, config),
                    "status": "translated",
                    "defines": dict(sorted(defines.items())),
                    "defineProcessing": _artifact_define_processing(
                        unit.source_backend,
                        defines,
                        supports_defines=source_supports_defines,
                    ),
                    "includePathProcessing": _artifact_include_path_processing(
                        unit.source_backend,
                        include_paths,
                        supports_include_paths=source_supports_include_paths,
                    ),
                    "includeDependencyProcessing": (
                        _artifact_include_dependency_processing(
                            unit.source_backend,
                            artifact_include_dependencies,
                            supports_include_paths=source_supports_include_paths,
                        )
                    ),
                    "sourceHash": dict(unit.source_hash),
                    "sourceSizeBytes": unit.source_size_bytes,
                    "provenance": {
                        "pipeline": "single-file-translate",
                        "intermediate": (
                            "crossgl"
                            if unit.source_backend not in {"cgl", "crossgl"}
                            and target not in {"cgl", "crossgl"}
                            else None
                        ),
                    },
                    "requiredCapabilities": list(required_capabilities),
                }
                if variant is not None:
                    artifact["variant"] = variant
                if output_dir_blocked:
                    artifact["status"] = "failed"
                    artifact["error"] = (
                        "Configured output directory resolves outside the repository; "
                        "artifact was not written."
                    )
                    artifacts.append(artifact)
                    continue
                source_options = _source_options_for_unit(
                    config,
                    unit.source_backend,
                    unit.relative_path,
                    target=target,
                )
                try:
                    template_materialization = (
                        _project_template_materialization_for_artifact(
                            unit=unit,
                            target=target,
                            variant=variant,
                            defines=defines,
                            define_sources=_variant_define_sources(config, variant),
                            include_paths=include_paths,
                            source_options=source_options,
                        )
                    )
                except Exception as exc:  # noqa: BLE001
                    failure_message = _translation_failure_message(
                        exc,
                        target,
                        unit,
                        artifact.get("path"),
                    )
                    artifact["status"] = "failed"
                    artifact["error"] = failure_message
                    diagnostics.extend(
                        _translation_failure_project_diagnostics(
                            exc,
                            target,
                            unit,
                            variant,
                            failure_message,
                        )
                    )
                    artifacts.append(artifact)
                    continue
                if template_materialization is not None:
                    artifact["templateMaterialization"] = dict(
                        template_materialization.metadata
                    )
                    diagnostics.extend(template_materialization.diagnostics)
                    if template_materialization.blocked:
                        artifact["status"] = "failed"
                        artifact["error"] = template_materialization.error or (
                            "Template materialization failed."
                        )
                        artifacts.append(artifact)
                        continue
                artifact_records = [artifact]
                template_temp_dir: tempfile.TemporaryDirectory[str] | None = None
                try:
                    output_path.parent.mkdir(parents=True, exist_ok=True)
                    translation_input_path = unit.path
                    translation_defines: Mapping[str, str] = defines
                    translation_source_options: Mapping[str, Any] = source_options
                    if template_materialization is not None:
                        template_temp_dir = tempfile.TemporaryDirectory(
                            prefix="crosstl-template-"
                        )
                        materialized_path = (
                            Path(template_temp_dir.name) / Path(unit.relative_path).name
                        )
                        materialized_path.write_text(
                            template_materialization.text,
                            encoding="utf-8",
                            newline="",
                        )
                        translation_input_path = materialized_path
                        translation_defines = template_materialization.defines
                        translation_source_options = (
                            template_materialization.source_options
                        )
                    translate_kwargs: dict[str, Any] = {
                        "backend": target,
                        "save_shader": str(output_path),
                        "format_output": format_output,
                        "source_backend": unit.source_backend,
                        "include_paths": include_paths,
                        "defines": translation_defines,
                    }
                    if translation_source_options:
                        translate_kwargs["source_options"] = translation_source_options
                    generated_source = translate(
                        str(translation_input_path), **translate_kwargs
                    )
                    mojo_host_diagnostics = (
                        _mojo_unresolved_target_construct_diagnostics(
                            artifact, generated_source
                        )
                    )
                    if mojo_host_diagnostics:
                        artifact["status"] = "failed"
                        artifact["error"] = mojo_host_diagnostics[0].message
                        output_path.unlink(missing_ok=True)
                        artifact_records = [artifact]
                    else:
                        artifact["generatedHash"] = _source_hash(output_path)
                        artifact["generatedSizeBytes"] = output_path.stat().st_size
                        artifact["sourceMap"] = _artifact_source_map(
                            config, unit, target, output_path
                        )
                        split_artifacts = _webgl_split_stage_artifacts(
                            config, unit, artifact, output_path
                        )
                        if split_artifacts is not None:
                            artifact_records = split_artifacts
                        else:
                            _attach_artifact_source_remap(
                                config, target, artifact, output_path
                            )
                        diagnostics.extend(
                            _generated_placeholder_diagnostics(artifact_records, config)
                        )
                    diagnostics.extend(mojo_host_diagnostics)
                except Exception as exc:  # noqa: BLE001
                    # Project translation reports per-artifact failures so one bad
                    # unit does not hide the rest of the repository's migration state.
                    failure_message = _translation_failure_message(
                        exc,
                        target,
                        unit,
                        artifact.get("path"),
                    )
                    artifact["status"] = "failed"
                    artifact["error"] = failure_message
                    artifact.pop("generatedHash", None)
                    artifact.pop("generatedSizeBytes", None)
                    artifact.pop("sourceMap", None)
                    artifact.pop("sourceRemap", None)
                    artifact_records = [artifact]
                    diagnostics.extend(
                        _translation_failure_project_diagnostics(
                            exc,
                            target,
                            unit,
                            variant,
                            failure_message,
                        )
                    )
                finally:
                    if template_temp_dir is not None:
                        template_temp_dir.cleanup()
                artifacts.extend(artifact_records)

    validation = (
        _validate_artifacts(artifacts, selected_targets, config)
        if validate or run_toolchains
        else {"toolchains": [], "artifacts": []}
    )
    if run_toolchains:
        toolchain_runs = _run_toolchain_smoke(artifacts, config.root)
        validation["toolchainRuns"] = toolchain_runs
        validation["_diagnostics"].extend(_toolchain_run_diagnostics(toolchain_runs))
    diagnostics.extend(validation.pop("_diagnostics", []))
    return ProjectPortabilityReport(
        config=config,
        targets=selected_targets,
        units=scan.units,
        skipped=scan.skipped,
        native_directives=scan.native_directives,
        artifacts=artifacts,
        diagnostics=diagnostics,
        validation=validation,
        migration_actions=_project_migration_actions(
            config, scan.units, selected_targets, artifacts
        ),
        artifact_matrix=_artifact_matrix_report(
            config, scan.units, selected_targets, config.variants, artifacts
        ),
    )


def _tool_status(target: str) -> dict[str, Any]:
    tools = TOOLCHAIN_BY_BACKEND.get(target, ())
    if not tools:
        return {
            "target": target,
            "status": "not-configured",
            "tools": [],
            "message": "No validation toolchain hook is configured for this target.",
        }
    resolved = []
    for tool in tools:
        path = shutil.which(tool)
        resolved.append({"name": tool, "path": path, "available": path is not None})
    available = all(tool["available"] for tool in resolved)
    return {
        "target": target,
        "status": "available" if available else "unavailable",
        "tools": resolved,
    }


def _status_counts(
    records: Sequence[Any], field_name: str, statuses: frozenset[str]
) -> dict[str, int]:
    counts = {status: 0 for status in sorted(statuses)}
    for record in records:
        if not isinstance(record, Mapping):
            continue
        status = record.get(field_name)
        if isinstance(status, str) and status in counts:
            counts[status] += 1
    return counts


def _validation_summary(artifact_checks: Sequence[Any]) -> dict[str, Any]:
    status_counts = _status_counts(
        artifact_checks, "status", VALIDATION_ARTIFACT_STATUSES
    )
    return {
        "artifactCount": len(artifact_checks),
        "okCount": status_counts["ok"],
        "failedCount": status_counts["failed"],
        "sourceHashStatusCounts": _status_counts(
            artifact_checks, "sourceHashStatus", SOURCE_HASH_VALIDATION_STATUSES
        ),
        "sourceSizeStatusCounts": _status_counts(
            artifact_checks, "sourceSizeStatus", SOURCE_SIZE_VALIDATION_STATUSES
        ),
        "generatedHashStatusCounts": _status_counts(
            artifact_checks,
            "generatedHashStatus",
            GENERATED_HASH_VALIDATION_STATUSES,
        ),
        "generatedSizeStatusCounts": _status_counts(
            artifact_checks,
            "generatedSizeStatus",
            GENERATED_SIZE_VALIDATION_STATUSES,
        ),
        "sourceMapStatusCounts": _status_counts(
            artifact_checks,
            "sourceMapStatus",
            SOURCE_MAP_VALIDATION_STATUSES,
        ),
        "sourceRemapStatusCounts": _status_counts(
            artifact_checks,
            "sourceRemapStatus",
            SOURCE_REMAP_VALIDATION_STATUSES,
        ),
    }


def _validation_toolchain_status_counts(toolchains: Sequence[Any]) -> dict[str, int]:
    return _status_counts(
        toolchains,
        "status",
        frozenset(("available", "not-configured", "unavailable")),
    )


def _validation_toolchain_run_status_counts(runs: Sequence[Any]) -> dict[str, int]:
    return _status_counts(runs, "status", VALIDATION_TOOLCHAIN_RUN_STATUSES)


def _validation_run_status_rollup(
    records: Sequence[Any], field_name: str
) -> dict[str, dict[str, int]]:
    counts: dict[str, dict[str, int]] = {}
    for record in records:
        if not isinstance(record, Mapping):
            continue
        value = record.get(field_name)
        if not isinstance(value, str) or not value.strip():
            continue
        name = value.strip()
        row = counts.setdefault(
            name,
            {
                "runCount": 0,
                "okCount": 0,
                "failedCount": 0,
            },
        )
        row["runCount"] += 1
        status = record.get("status")
        if status == "ok":
            row["okCount"] += 1
        elif status == "failed":
            row["failedCount"] += 1
    return {name: counts[name] for name in sorted(counts)}


def _validation_toolchain_run_status_by_target(
    runs: Sequence[Any],
) -> dict[str, dict[str, int]]:
    return _validation_run_status_rollup(runs, "target")


